    w.document.write('<div><h1 style="margin:0;font-size:22px;letter-spacing:1px;">Aevus</h1><div style="font-size:9px;letter-spacing:2px;color:#94A3B8;font-family:monospace;margin-top:2px;">PREDICT · PREVENT · PERFORM</div><div style="font-size:11px;color:#64748b;margin-top:4px;">Executive Report · Intrepid Logic LLC · SDVOSB</div></div></div>');
