// ── SESSION MANAGEMENT — timeout, lockout, audit log ──
(function() {
  if (window.AEVUS_DEMO) return; // demo has its own timeout

  // Demo page gate — restrict to showcase pages only
  // (handled separately in demo mode block)

  // Check JWT expiry every 30s
  setInterval(function() {
    var tok = localStorage.getItem('aevus_id_token');
    if (!tok) return;
    try {
      var payload = JSON.parse(atob(tok.split('.')[1]));
      var exp = payload.exp * 1000; // ms
      var remaining = exp - Date.now();
      var badge = document.getElementById('session-timer-badge');

      if (remaining < 0) {
        // Expired — redirect
        window.aevusLogout();
        return;
      }

      if (remaining < 300000) { // <5 min
        var mins = Math.ceil(remaining / 60000);
        if (!badge) {
          badge = document.createElement('div');
          badge.id = 'session-timer-badge';
          badge.style.cssText = 'position:fixed;bottom:60px;right:16px;z-index:9999;background:rgba(251,191,36,0.15);border:1px solid rgba(251,191,36,0.4);border-radius:8px;padding:8px 14px;font-size:11px;color:#FBBF24;font-family:Manrope,sans-serif;backdrop-filter:blur(8px);';
          document.body.appendChild(badge);
        }
        badge.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="14" height="14" style="vertical-align:middle;margin-right:4px;"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>Session expires in ' + mins + ' min — <a href="/dashboard/login.html" style="color:#FBBF24;text-decoration:underline;">re-authenticate</a> · <a href="#" onclick="window.aevusRefreshSession();return false;" style="color:#10D478;text-decoration:underline;">refresh</a>';
      } else if (badge) {
        badge.remove();
      }
    } catch(e) {}
  }, 30000);

  // Audit log — record login event
  try {
    var tok = localStorage.getItem('aevus_id_token');
    if (tok) {
      var payload = JSON.parse(atob(tok.split('.')[1]));
      var entry = {
        event: 'session_active',
        user: payload.email || payload['cognito:username'] || 'unknown',
        groups: payload['cognito:groups'] || [],
        timestamp: new Date().toISOString(),
        userAgent: navigator.userAgent.substring(0, 100)
      };
      // Store in sessionStorage audit trail
      var log = JSON.parse(sessionStorage.getItem('aevus_audit_log') || '[]');
      if (log.length === 0 || log[log.length-1].event !== 'session_active') {
        log.push(entry);
        sessionStorage.setItem('aevus_audit_log', JSON.stringify(log));
      }
    }
  } catch(e) {}
})();

