  function navigateTo(page) {
    // B1 fix: Reset any active SVG zoom/transform on the process overview
    var _ovSvg = document.getElementById('process-svg');
    if (_ovSvg) { _ovSvg.style.transform = ''; _ovSvg.style.transformOrigin = ''; }
    var _zoomBar = document.getElementById('svg-zoom-bar');
    if (_zoomBar) _zoomBar.style.display = 'none';
    window._svgZoomLevel = 1;
    document.body.setAttribute('data-page', page);
    document.querySelectorAll('.page-section').forEach(s => s.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    const sec = document.querySelector(`.page-section[data-page="${page}"]`);
    const nav = document.querySelector(`.nav-item[data-page="${page}"]`);
    if (sec) sec.classList.add('active');
    if (nav) nav.classList.add('active');
    // Board rec #5: Update breadcrumb
    var bc = document.getElementById('breadcrumb-trail');
    if (bc) {
      var pageNames = {overview:'Process Overview',assets:'Assets',alarms:'Alarm Management',health:'Ariel JGJ/2 Health',diagnostics:'Diagnostics',trends:'Historian',cabinet:'Cabinet View',operations:'Operations',solar:'Solar Monitoring',weather:'Weather Intelligence',radio:'Radio Comms',map:'Site Map',network:'Network Topology',cyber:'Cybersecurity',reports:'Reports',settings:'Settings'};
      bc.innerHTML = '<span style="color:var(--accent);cursor:pointer;" onclick="window.location.hash=\'sites\'">BlueJay Unit #1 <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="vertical-align:middle;margin-left:2px;"><polyline points="6 9 12 15 18 9"/></svg></span> <span style="color:var(--text-faint);margin:0 6px;">›</span> <span>' + (pageNames[page]||page) + '</span>';
    }
    // Close mobile sidebar
    document.querySelector('.sidebar')?.classList.remove('open');
    document.querySelector('.sidebar-overlay')?.classList.remove('active');
    // Update mobile bottom nav active state
    document.querySelectorAll('.mob-nav-btn').forEach(function(b){b.classList.toggle('active',b.getAttribute('data-page')===page);});
    // 17th Audit Fix #1: Scroll to top on every page navigation
    var mainEl = document.querySelector('.main');
    if (mainEl) mainEl.scrollTop = 0;
    window.scrollTo(0, 0);
    // Render page content
    renderPage(page);
  }

  function initRouter() {
    document.querySelectorAll('.nav-item[data-page]').forEach(el => {
      el.addEventListener('click', e => {
        e.preventDefault();
        const page = el.dataset.page;
        window.location.hash = '#' + page;
      });
    });
    window.addEventListener('hashchange', () => {
      const page = location.hash.replace('#','') || 'overview';
      navigateTo(page);
    });
    const initial = location.hash.replace('#','') || 'overview';
    navigateTo(initial);
  }

  function renderBreadcrumb(pg){ /* disabled — 32nd audit */ }
  async function renderPage(page, isRefresh) { if(typeof renderQuickActions==="function")renderQuickActions(); renderBreadcrumb(page); var ft=document.querySelector('.footer');if(ft)ft.style.display=(page==='weather'||page==='radio'||page==='map')?'none':'';var sf=document.querySelector('.sidebar-footer');if(sf)sf.style.display=(page==='weather'||page==='radio'||page==='map')?'none':'';document.body.style.overflow=(page==='weather'||page==='radio'||page==='map')?'hidden':'';
    if (page !== 'map') document.body.classList.remove('map-active');
    // Demo mode: restrict to showcase pages
    var DEMO_ALLOWED = ['overview','solar','weather','map','health','alarms','assets','reports','methodology','privacy','radio','historian','network','cyber','operations','diagnostics','trends','cabinet','board','sites','executive','settings'];
    var _gateEl = document.querySelector('section[data-page="' + page + '"]');
    if (window.AEVUS_DEMO && DEMO_ALLOWED.indexOf(page) === -1) {
      if (_gateEl) _gateEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:60vh;flex-direction:column;gap:16px;">' +
        '<svg viewBox="0 0 24 24" width="48" height="48" fill="none" stroke="var(--text-muted)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>' +
        '<div style="font-size:18px;font-weight:700;color:var(--text-primary);">Full Access Required</div>' +
        '<div style="font-size:13px;color:var(--text-muted);max-width:360px;text-align:center;line-height:1.5;">This page is available to authenticated users. Sign in or request access to explore the full Aevus platform.</div>' +
        '<a href="/dashboard/login.html" style="margin-top:8px;padding:10px 24px;background:var(--accent);color:#fff;border-radius:8px;font-size:13px;font-weight:600;text-decoration:none;">Sign In — Rimrock Energy Operations</a>' +
        '</div>';
      return;
    }
    switch(page) {
      case 'overview': renderOverview(); break;
      case 'assets': isRefresh ? renderAssetsTable(currentAssetFilter) : renderAssetsPage(); break;
      case 'health': renderHealthPage(); break;
      case 'alerts': isRefresh ? renderAlertsList() : renderAlertsPage(); break;
      case 'diagnostics': renderDiagnosticsPage(); break;
      case 'trends': if (!isRefresh) await renderTrendsPage(); break;
      case 'cabinet': renderCabinetPage(); break;
      case 'operations': renderOperationsPage(); break;
      case 'solar': renderSolarPage(); break;
      case 'weather': renderWeatherPage(); break;
      case 'reports': renderReportsPage(); break;
      case 'alarms': isRefresh ? _updateAlarmsPageLive() : renderAlarmsPage(); break;
      case 'historian': renderHistorianPage(); break;
      case 'network': renderNetworkPage(); break;
      case 'cyber': renderCyberPage(); break;
      case 'radio': renderRadioCommsPage(); break;
      case 'map': renderMapPage(); break; /* map-active added in renderMapPage */
      case 'executive': if(!isRefresh && window._renderExecutivePage) window._renderExecutivePage(); break;
      case 'settings': renderSettingsPage(); break;
      case 'methodology': renderMethodologyPage(); break;
      case 'board': renderBoardPage(); break;
      case 'privacy': renderPrivacyPage(); break;
      case 'sites': renderSitesPage(); break;
          }
  }

