  function renderCorrelationsOverview() {
    const el = document.getElementById('correlations-panel');
    // ── Overview Audit #10: Correlation filter dropdown ──
    if (el && !document.getElementById('corr-filter-dd')) {
      var dd = document.createElement('div');
      dd.className = 'corr-dropdown';
      dd.id = 'corr-filter-dd';
      dd.innerHTML = '<select id="corr-type-filter" onchange="window._corrFilter=this.value;renderCorrelations&&renderCorrelations();">' +
        '<option value="all">All Correlations</option>' +
        '<option value="temperature">Temperature</option>' +
        '<option value="pressure">Pressure</option>' +
        '<option value="vibration">Vibration</option>' +
        '<option value="weather">Weather</option>' +
        '</select>';
      el.parentNode && el.parentNode.insertBefore(dd, el);
    }
    var corrFilter = window._corrFilter || 'all';
    if (!el) return;
    if (!correlations || correlations.length === 0) {
      el.style.display = 'none';
      var _cdd = document.getElementById('corr-filter-dd');
      if (_cdd) _cdd.style.display = 'none';
      return;
    }
    var _cdd2 = document.getElementById('corr-filter-dd');
    if (_cdd2) _cdd2.style.display = '';
    el.style.display = 'block';
    el.innerHTML = '<div class="section-title">IL9000 Pattern Detection</div><div style="display:inline-block;padding:2px 8px;background:rgba(167,139,250,0.1);border:1px solid rgba(167,139,250,0.2);border-radius:4px;font-size:8px;font-weight:700;color:#A78BFA;letter-spacing:1px;text-transform:uppercase;margin-left:8px;vertical-align:middle;">Patent Pending</div><div style="display:none"</div>' +
      correlations.slice(0, 5).map(c => {
        const sev = c.severity || 'low';
        return '<div class="corr-card ' + sev + '">' +
          '<span class="corr-severity ' + sev + '">' + sev + '</span>' +
          '<div style="flex:1;"><div style="font-size:13px;font-weight:600;color:var(--text-primary);">' + (c.pattern || c.type || '—') + '</div>' +
          '<div style="font-size:11px;color:var(--text-muted);margin-top:2px;">' + (c.message || '') + '</div>' +
          '<div style="font-size:10px;color:var(--text-muted);margin-top:2px;">Assets: ' + ((c.assets || []).join(', ') || '—') + '</div></div>' +
          '<div style="text-align:right;"><div style="font-size:16px;font-weight:700;font-family:var(--font-mono);color:' + (c.correlation_strength > 0.8 ? '#EF4444' : c.correlation_strength > 0.5 ? '#FBBF24' : '#10D478') + ';">' + (c.correlation_strength ? 'r=' + c.correlation_strength.toFixed(2) : '') + '</div><div style="font-size:9px;color:var(--text-muted);font-family:var(--font-mono);">' + timeAgo(c.detected_at) + '</div></div>' +
          '</div>';
      }).join('');
  }

