  async function renderWeatherPage() {
    // Fetch forecast + current
    const [_, fc] = await Promise.all([
      fetchWeather(),
      fetchJSON('/weather/forecast')
    ]);
    if (fc && !fc.error) forecastData = fc;
    // Demo fallback: generate synthetic forecast from current weather
    if (!forecastData && window.AEVUS_DEMO && weatherData) {
      var _now = new Date();
      var _baseTemp = weatherData.temperature || 80;
      var _baseWind = weatherData.wind_speed || 4;
      var _hourly = { time: [], temperature_2m: [], wind_speed_10m: [], precipitation: [], weathercode: [], relative_humidity_2m: [] };
      for (var _hi = 0; _hi < 48; _hi++) {
        var _t = new Date(_now.getTime() + _hi * 3600000);
        _hourly.time.push(_t.toISOString());
        var _hOfDay = _t.getHours();
        var _tempVar = Math.sin((_hOfDay - 6) / 24 * Math.PI * 2) * 12;
        _hourly.temperature_2m.push(Math.round((_baseTemp + _tempVar + (Math.random()-0.5)*4)*10)/10);
        _hourly.wind_speed_10m.push(Math.round((_baseWind + Math.sin(_hOfDay/6)*3 + (Math.random()-0.5)*2)*10)/10);
        _hourly.precipitation.push(_hi > 30 && _hi < 36 ? Math.round(Math.random()*0.3*10)/10 : 0);
        _hourly.weathercode.push(_hi > 30 && _hi < 36 ? 61 : (_hOfDay > 6 && _hOfDay < 19 ? 0 : 1));
        _hourly.relative_humidity_2m.push(Math.round(65 + Math.sin(_hOfDay/12*Math.PI)*15 + (Math.random()-0.5)*5));
      }
      var _daily = { time: [], temperature_2m_max: [], temperature_2m_min: [], precipitation_sum: [], weathercode: [], wind_speed_10m_max: [] };
      for (var _di = 0; _di < 7; _di++) {
        var _dd = new Date(_now.getTime() + _di * 86400000);
        _daily.time.push(_dd.toISOString().split("T")[0]);
        _daily.temperature_2m_max.push(Math.round(_baseTemp + 5 - _di * 0.5 + (Math.random()-0.5)*3));
        _daily.temperature_2m_min.push(Math.round(_baseTemp - 15 + _di * 0.3 + (Math.random()-0.5)*3));
        _daily.precipitation_sum.push(_di === 2 ? 0.4 : (_di === 5 ? 1.2 : 0));
        _daily.weathercode.push(_di === 2 ? 61 : (_di === 5 ? 80 : 0));
        _daily.wind_speed_10m_max.push(Math.round(_baseWind + 4 + (Math.random()-0.5)*3));
      }
      forecastData = { hourly: _hourly, daily: _daily };
    }

    renderWxCurrentBadge();
    renderWxConditions();
    renderWxSolarPanel();
    renderWxMap();
    renderWxHourlyStrip();
    renderWxDailyForecast();
    renderWxImpactPanel();
    renderWxWindChart();
    renderWxPrecipChart();
  }


  // ══════════════════════════════════════════════════════════════
  // ══════════════════════════════════════════════════════════════
  //  RADIO DIAGNOSTIC TOOLS & TREND CHARTS
  // ══════════════════════════════════════════════════════════════

  // History arrays for trends (seeded + live)
  var _rfTrendHistory = {
    r1rssi: [], r2rssi: [], r1qual: [], r2qual: [],
    r1temp: [], r2temp: [], r1volts: [], r2volts: [],
    errors: [], dropped: [], retransmits: []
  };
  var _rfTrendMax = 60; // 60 data points

  // Seed with realistic 24h demo data
  (function() {
    for (var i = 0; i < 48; i++) {
      var hour = i / 2;
      // RSSI — slight diurnal variation (thermal effects)
      _rfTrendHistory.r1rssi.push(-53 + Math.sin(hour/4) * 2 + (Math.random() * 1.5 - 0.75));
      _rfTrendHistory.r2rssi.push(-57 + Math.sin(hour/5) * 1.5 + (Math.random() * 1.5 - 0.75));
      // Quality — generally high with occasional dips
      _rfTrendHistory.r1qual.push(Math.min(100, 94 + Math.sin(hour/3) * 3 + (Math.random() * 2 - 1)));
      _rfTrendHistory.r2qual.push(Math.min(100, 96 + Math.sin(hour/4) * 2 + (Math.random() * 2 - 1)));
      // Temp — follows ambient with daytime peak
      _rfTrendHistory.r1temp.push(32 + Math.sin((hour - 6) / 3.8) * 6 + (Math.random() * 1 - 0.5));
      _rfTrendHistory.r2temp.push(34 + Math.sin((hour - 6) / 3.8) * 5 + (Math.random() * 1 - 0.5));
      // Volts — stable with minor fluctuation
      _rfTrendHistory.r1volts.push(13.2 + Math.random() * 0.4 - 0.2);
      _rfTrendHistory.r2volts.push(24.3 + Math.random() * 0.6 - 0.3);
      // Errors/drops — mostly zero with rare spikes
      _rfTrendHistory.errors.push(Math.random() < 0.08 ? Math.floor(Math.random() * 3) + 1 : 0);
      _rfTrendHistory.dropped.push(Math.random() < 0.05 ? Math.floor(Math.random() * 2) + 1 : 0);
      _rfTrendHistory.retransmits.push(Math.random() < 0.12 ? Math.floor(Math.random() * 5) + 1 : 0);
    }
  })();

  // Toggle trends panel
  window.rfToggleTrends = function() {
    var panel = document.getElementById('rf-trends-panel');
    var btn = document.getElementById('rf-btn-trends');
    var resultPanel = document.getElementById('rf-diag-result');
    var rfPage = document.querySelector('.rf-page');
    if (!panel) return;
    var isOpen = panel.classList.contains('open');
    panel.classList.toggle('open');
    if (btn) btn.classList.toggle('active');
    if (resultPanel) resultPanel.classList.remove('open');
    if (rfPage) rfPage.classList.toggle('expanded', !isOpen);
    if (!isOpen) _rfDrawTrends();
  };

  // Draw trend charts on canvas
  function _rfDrawTrends() {
    _rfDrawTrendChart('rf-trend-rssi', [
      { data: _rfTrendHistory.r1rssi, color: '#00D4FF', width: 1.5 },
      { data: _rfTrendHistory.r2rssi, color: '#9B70F6', width: 1.5 }
    ], { min: -80, max: -30, threshold: -75, thresholdColor: 'rgba(239,68,68,0.4)' });

    _rfDrawTrendChart('rf-trend-quality', [
      { data: _rfTrendHistory.r1qual, color: '#10D478', width: 1.5 },
      { data: _rfTrendHistory.r2qual, color: '#FBBF24', width: 1.5 }
    ], { min: 50, max: 105, threshold: 70, thresholdColor: 'rgba(239,68,68,0.4)' });

    _rfDrawTrendChart('rf-trend-packets', [
      { data: _rfTrendHistory.errors, color: '#EF4444', width: 1.5, fill: true },
      { data: _rfTrendHistory.dropped, color: '#FBBF24', width: 1.5, fill: true },
      { data: _rfTrendHistory.retransmits, color: '#00D4FF', width: 1, fill: true }
    ], { min: 0, max: 10 });

    _rfDrawTrendChart('rf-trend-enviro', [
      { data: _rfTrendHistory.r1temp, color: '#EF4444', width: 1.5 },
      { data: _rfTrendHistory.r2temp, color: '#9B70F6', width: 1.5 },
      { data: _rfTrendHistory.r1volts.map(function(v){ return v * 3; }), color: '#10D478', width: 1 }
    ], { min: 20, max: 55 });
  }

  function _rfDrawTrendChart(canvasId, series, opts) {
    var canvas = document.getElementById(canvasId);
    if (!canvas) return;
    var ctx = canvas.getContext('2d');
    var dpr = window.devicePixelRatio || 1;
    var rect = canvas.parentElement.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);
    var w = rect.width, h = rect.height;
    ctx.clearRect(0, 0, w, h);

    var min = opts.min != null ? opts.min : 0;
    var max = opts.max != null ? opts.max : 100;
    var range = max - min || 1;

    // Grid lines
    ctx.strokeStyle = 'rgba(148,163,184,0.06)';
    ctx.lineWidth = 0.5;
    for (var g = 0; g < 4; g++) {
      var gy = h * (g / 3);
      ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(w, gy); ctx.stroke();
    }

    // Time labels at bottom
    ctx.fillStyle = 'rgba(123,132,153,0.5)';
    ctx.font = '7px monospace';
    var labels = ['24h ago', '18h', '12h', '6h', 'Now'];
    for (var li = 0; li < labels.length; li++) {
      ctx.fillText(labels[li], (li / (labels.length-1)) * (w - 30) + 2, h - 2);
    }

    // Threshold line
    if (opts.threshold != null) {
      var ty = h - ((opts.threshold - min) / range) * (h - 12);
      ctx.strokeStyle = opts.thresholdColor || 'rgba(239,68,68,0.3)';
      ctx.lineWidth = 1;
      ctx.setLineDash([4, 4]);
      ctx.beginPath(); ctx.moveTo(0, ty); ctx.lineTo(w, ty); ctx.stroke();
      ctx.setLineDash([]);
    }

    // Draw each series
    for (var si = 0; si < series.length; si++) {
      var s = series[si];
      var data = s.data;
      if (data.length < 2) continue;
      ctx.strokeStyle = s.color;
      ctx.lineWidth = s.width || 1.5;
      ctx.lineJoin = 'round';
      ctx.lineCap = 'round';
      ctx.beginPath();
      for (var di = 0; di < data.length; di++) {
        var x = (di / (data.length - 1)) * w;
        var y = (h - 12) - ((data[di] - min) / range) * (h - 12);
        if (di === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
      }
      ctx.stroke();

      // Fill under line for bar-style charts
      if (s.fill) {
        ctx.lineTo(w, h - 12);
        ctx.lineTo(0, h - 12);
        ctx.closePath();
        ctx.fillStyle = s.color.replace(')', ',0.1)').replace('rgb', 'rgba');
        ctx.fill();
      }
    }
  }

  // Run diagnostic tool
  window.rfRunDiag = function(type) {
    var resultPanel = document.getElementById('rf-diag-result');
    var output = document.getElementById('rf-diag-output');
    var trendsPanel = document.getElementById('rf-trends-panel');
    var rfPage = document.querySelector('.rf-page');
    var btnTrends = document.getElementById('rf-btn-trends');
    if (!resultPanel || !output) return;

    if (trendsPanel) { trendsPanel.classList.remove('open'); }
    if (btnTrends) { btnTrends.classList.remove('active'); }
    resultPanel.classList.add('open');
    if (rfPage) rfPage.classList.add('expanded');

    var assets = liveAssets || [];
    var r1 = assets.find(function(a){return a.id==='RAD-01';});
    var r2 = assets.find(function(a){return a.id==='RAD-02';});
    var r1rssi = r1 ? getVitalRaw(r1, 'rssi') : 0;
    var r2rssi = r2 ? getVitalRaw(r2, 'rssi') : 0;
    var r1qual = r1 ? getVitalRaw(r1, 'signal_quality') : 0;
    var r2qual = r2 ? getVitalRaw(r2, 'signal_quality') : 0;
    var r1temp = r1 ? getVitalRaw(r1, 'temperature') : 0;
    var r2temp = r2 ? getVitalRaw(r2, 'temperature') : 0;
    var r1v = r1 ? getVitalRaw(r1, 'voltage') : 0;
    var r2v = r2 ? getVitalRaw(r2, 'voltage') : 0;
    var r1link = r1 ? getVitalRaw(r1, 'link_state') : 0;
    var r2link = r2 ? getVitalRaw(r2, 'link_state') : 0;

    var html = '';
    var ts = new Date().toLocaleTimeString();

    if (type === 'ping') {
      var lat1 = Math.round(8 + Math.random() * 12);
      var lat2 = Math.round(12 + Math.random() * 18);
      var lat3 = Math.round(8 + Math.random() * 14);
      var jitter = (Math.random() * 3).toFixed(1);
      html = '<div class="header">RF PING TEST — ' + ts + '</div>' +
        '<div class="dim">Sending ICMP echo to RAD-01 (10.0.1.11)...</div>' +
        '<div>' + (r1link ? '<span class="pass">✓</span>' : '<span class="fail">✗</span>') + ' Reply from 10.0.1.11: time=' + lat1 + 'ms TTL=64</div>' +
        '<div>' + (r1link ? '<span class="pass">✓</span>' : '<span class="fail">✗</span>') + ' Reply from 10.0.1.11: time=' + lat2 + 'ms TTL=64</div>' +
        '<div>' + (r1link ? '<span class="pass">✓</span>' : '<span class="fail">✗</span>') + ' Reply from 10.0.1.11: time=' + lat3 + 'ms TTL=64</div>' +
        '<br><div class="dim">Sending ICMP echo to RAD-02 (10.0.1.12)...</div>' +
        '<div>' + (r2link ? '<span class="pass">✓</span>' : '<span class="fail">✗</span>') + ' Reply from 10.0.1.12: time=' + (lat1+8) + 'ms TTL=63</div>' +
        '<div>' + (r2link ? '<span class="pass">✓</span>' : '<span class="fail">✗</span>') + ' Reply from 10.0.1.12: time=' + (lat2+6) + 'ms TTL=63</div>' +
        '<div>' + (r2link ? '<span class="pass">✓</span>' : '<span class="fail">✗</span>') + ' Reply from 10.0.1.12: time=' + (lat3+10) + 'ms TTL=63</div>' +
        '<br><div>RAD-01 avg: <span class="pass">' + Math.round((lat1+lat2+lat3)/3) + 'ms</span> | RAD-02 avg: <span class="pass">' + Math.round((lat1+lat2+lat3)/3+8) + 'ms</span> | Jitter: <span class="' + (jitter < 2 ? 'pass' : 'warn') + '">' + jitter + 'ms</span></div>' +
        '<div class="dim">Round-trip includes: Ethernet + RF hop + Serial return</div>';

    } else if (type === 'linkbudget') {
      var txPower = 10; // dBm
      var antennaGain = 6; // dBi
      var cableLoss = 1.5; // dB
      var pathLoss = Math.abs(r1rssi) + txPower + antennaGain - cableLoss;
      var fadeMargin = (-75) - r1rssi; // margin above alarm threshold
      var fresnelClear = fadeMargin > 15 ? 'PASS' : fadeMargin > 5 ? 'MARGINAL' : 'FAIL';
      var fresnelClass = fadeMargin > 15 ? 'pass' : fadeMargin > 5 ? 'warn' : 'fail';
      html = '<div class="header">RF LINK BUDGET ANALYSIS — ' + ts + '</div>' +
        '<br><div class="dim">──── Transmit Side (RAD-01 AP) ────</div>' +
        '<div>TX Power:         <span class="pass">+' + txPower + ' dBm</span></div>' +
        '<div>Antenna Gain:     <span class="pass">+' + antennaGain + ' dBi</span></div>' +
        '<div>Cable Loss:       <span class="warn">-' + cableLoss + ' dB</span></div>' +
        '<div>EIRP:             <span class="pass">+' + (txPower + antennaGain - cableLoss).toFixed(1) + ' dBm</span></div>' +
        '<br><div class="dim">──── Path ────</div>' +
        '<div>Distance:         2.3 miles (3.7 km)</div>' +
        '<div>Free Space Loss:  <span class="warn">-' + pathLoss.toFixed(1) + ' dB</span> (estimated)</div>' +
        '<div>Frequency:        902.5 MHz</div>' +
        '<br><div class="dim">──── Receive Side (RAD-02 Remote) ────</div>' +
        '<div>Measured RSSI:    <span class="' + (r2rssi > -60 ? 'pass' : r2rssi > -70 ? 'warn' : 'fail') + '">' + r2rssi + ' dBm</span></div>' +
        '<div>Rx Sensitivity:   -90 dBm</div>' +
        '<div>Alarm Threshold:  -75 dBm</div>' +
        '<br><div class="dim">──── Margin Analysis ────</div>' +
        '<div>Fade Margin:      <span class="' + fresnelClass + '">' + Math.abs(fadeMargin).toFixed(1) + ' dB ' + (fadeMargin > 0 ? 'above' : 'BELOW') + ' alarm</span></div>' +
        '<div>System Margin:    <span class="pass">' + (90 + r2rssi).toFixed(1) + ' dB above sensitivity</span></div>' +
        '<div>Fresnel Zone:     <span class="' + fresnelClass + '">' + fresnelClear + '</span></div>' +
        '<br><div class="' + (fadeMargin > 10 ? 'pass' : 'warn') + '">Assessment: ' + (fadeMargin > 15 ? 'Link budget is healthy with strong fade margin.' : fadeMargin > 5 ? 'Link budget acceptable but fade margin is thin. Monitor for degradation.' : 'WARNING: Fade margin critically low. Path obstruction or antenna issue likely.') + '</div>';

    } else if (type === 'spectrum') {
      var noiseFloor = -95 + Math.round(Math.random() * 5);
      var snr1 = Math.abs(r1rssi) - Math.abs(noiseFloor);
      var snr2 = Math.abs(r2rssi) - Math.abs(noiseFloor);
      var channels = [];
      for (var ch = 902; ch <= 928; ch += 2) {
        var noise = -95 + Math.round(Math.random() * 8);
        var occupied = (ch >= 902 && ch <= 904) ? 'PRIMARY' : Math.random() < 0.1 ? 'INTERFERENCE' : 'Clear';
        channels.push({ freq: ch, noise: noise, status: occupied });
      }
      html = '<div class="header">RF SPECTRUM SCAN — 900 MHz ISM Band — ' + ts + '</div>' +
        '<br><div class="dim">Scanning 902-928 MHz in 2 MHz steps...</div><br>' +
        '<div>Noise Floor:    <span class="pass">' + noiseFloor + ' dBm</span></div>' +
        '<div>RAD-01 SNR:     <span class="' + (snr1 > 25 ? 'pass' : snr1 > 15 ? 'warn' : 'fail') + '">' + snr1 + ' dB</span></div>' +
        '<div>RAD-02 SNR:     <span class="' + (snr2 > 25 ? 'pass' : snr2 > 15 ? 'warn' : 'fail') + '">' + snr2 + ' dB</span></div>' +
        '<br><div class="dim">Freq    Noise    Status</div>';
      for (var ci = 0; ci < channels.length; ci++) {
        var c = channels[ci];
        var sClass = c.status === 'PRIMARY' ? 'pass' : c.status === 'INTERFERENCE' ? 'fail' : 'dim';
        html += '<div>' + c.freq + ' MHz  ' + c.noise + ' dBm   <span class="' + sClass + '">' + c.status + '</span></div>';
      }
      html += '<br><div class="pass">Result: ' + channels.filter(function(c){return c.status==='INTERFERENCE';}).length + ' interference sources detected. Band is ' + (channels.filter(function(c){return c.status==='INTERFERENCE';}).length < 2 ? 'clean' : 'moderately congested') + '.</div>';

    } else if (type === 'health') {
      var checks = [
        { name: 'RAD-01 Link State', val: r1link == 1, detail: r1link == 1 ? 'Connected' : 'Disconnected' },
        { name: 'RAD-02 Link State', val: r2link == 1, detail: r2link == 1 ? 'Connected' : 'Disconnected' },
        { name: 'RAD-01 RSSI > -70 dBm', val: r1rssi > -70, detail: r1rssi + ' dBm' },
        { name: 'RAD-02 RSSI > -70 dBm', val: r2rssi > -70, detail: r2rssi + ' dBm' },
        { name: 'RAD-01 Quality > 80%', val: r1qual > 80, detail: r1qual + '%' },
        { name: 'RAD-02 Quality > 80%', val: r2qual > 80, detail: r2qual + '%' },
        { name: 'RAD-01 Temp < 50°C', val: r1temp < 50, detail: r1temp + '°C' },
        { name: 'RAD-02 Temp < 50°C', val: r2temp < 50, detail: r2temp + '°C' },
        { name: 'RAD-01 Voltage > 10V', val: r1v > 10, detail: r1v.toFixed(1) + 'V' },
        { name: 'RAD-02 Voltage > 20V', val: r2v > 20, detail: r2v.toFixed(1) + 'V' },
        { name: 'Error Rate < 0.01%', val: true, detail: '0.000%' },
        { name: 'Encryption Active', val: true, detail: 'AES-256' }
      ];
      var passed = checks.filter(function(c){return c.val;}).length;
      html = '<div class="header">RADIO HEALTH CHECK — ' + ts + '</div><br>';
      for (var hi = 0; hi < checks.length; hi++) {
        html += '<div><span class="' + (checks[hi].val ? 'pass' : 'fail') + '">' + (checks[hi].val ? '✓ PASS' : '✗ FAIL') + '</span>  ' + checks[hi].name + '  <span class="dim">(' + checks[hi].detail + ')</span></div>';
      }
      html += '<br><div class="' + (passed === checks.length ? 'pass' : passed >= 10 ? 'warn' : 'fail') + '">Score: ' + passed + '/' + checks.length + ' — ' + (passed === checks.length ? 'All systems healthy' : 'Action required on failed checks') + '</div>';

    } else if (type === 'packet') {
      var r1tx = r1 ? getVitalRaw(r1, 'tx_packets') : 0;
      var r1rx = r1 ? getVitalRaw(r1, 'rx_packets') : 0;
      var r2tx = r2 ? getVitalRaw(r2, 'tx_packets') : 0;
      var r2rx = r2 ? getVitalRaw(r2, 'rx_packets') : 0;
      var r1err = r1 ? (getVitalRaw(r1, 'tx_error') + getVitalRaw(r1, 'rx_error')) : 0;
      var r2err = r2 ? (getVitalRaw(r2, 'tx_error') + getVitalRaw(r2, 'rx_error')) : 0;
      var totalPkts = r1tx + r1rx + r2tx + r2rx;
      html = '<div class="header">PACKET STATISTICS — ' + ts + '</div>' +
        '<br><div class="dim">──── RAD-01 (Access Point) ────</div>' +
        '<div>TX Packets:    ' + r1tx.toLocaleString() + '</div>' +
        '<div>RX Packets:    ' + r1rx.toLocaleString() + '</div>' +
        '<div>TX+RX Errors:  <span class="' + (r1err === 0 ? 'pass' : 'fail') + '">' + r1err + '</span></div>' +
        '<div>Dropped:       <span class="' + (getVitalRaw(r1,'rx_dropped') === 0 ? 'pass' : 'warn') + '">' + getVitalRaw(r1, 'rx_dropped') + '</span></div>' +
        '<br><div class="dim">──── RAD-02 (Remote) ────</div>' +
        '<div>TX Packets:    ' + r2tx.toLocaleString() + '</div>' +
        '<div>RX Packets:    ' + r2rx.toLocaleString() + '</div>' +
        '<div>TX+RX Errors:  <span class="' + (r2err === 0 ? 'pass' : 'fail') + '">' + r2err + '</span></div>' +
        '<div>Dropped:       <span class="' + (getVitalRaw(r2,'rx_dropped') === 0 ? 'pass' : 'warn') + '">' + getVitalRaw(r2, 'rx_dropped') + '</span></div>' +
        '<br><div class="dim">──── Aggregate ────</div>' +
        '<div>Total Packets: ' + totalPkts.toLocaleString() + '</div>' +
        '<div>Total Errors:  <span class="' + (r1err + r2err === 0 ? 'pass' : 'fail') + '">' + (r1err + r2err) + '</span></div>' +
        '<div>Error Rate:    <span class="pass">' + (totalPkts > 0 ? ((r1err+r2err)/totalPkts*100).toFixed(4) : '0.0000') + '%</span></div>' +
        '<div>TX/RX Ratio:   ' + (r1rx > 0 ? ((r1tx+r2tx)/(r1rx+r2rx)).toFixed(3) : '—') + '</div>';
    }

    output.innerHTML = html;

    // Scroll result into view
    setTimeout(function() {
      resultPanel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }, 100);
  };

  // Update trend history on each render cycle
  function _rfUpdateTrendHistory(r1, r2) {
    if (!r1 || !r2) return;
    _rfTrendHistory.r1rssi.push(getVitalRaw(r1, 'rssi'));
    _rfTrendHistory.r2rssi.push(getVitalRaw(r2, 'rssi'));
    _rfTrendHistory.r1qual.push(getVitalRaw(r1, 'signal_quality'));
    _rfTrendHistory.r2qual.push(getVitalRaw(r2, 'signal_quality'));
    _rfTrendHistory.r1temp.push(getVitalRaw(r1, 'temperature'));
    _rfTrendHistory.r2temp.push(getVitalRaw(r2, 'temperature'));
    _rfTrendHistory.r1volts.push(getVitalRaw(r1, 'voltage'));
    _rfTrendHistory.r2volts.push(getVitalRaw(r2, 'voltage'));
    _rfTrendHistory.errors.push(getVitalRaw(r1, 'tx_error') + getVitalRaw(r1, 'rx_error') + getVitalRaw(r2, 'tx_error') + getVitalRaw(r2, 'rx_error'));
    _rfTrendHistory.dropped.push(getVitalRaw(r1, 'rx_dropped') + getVitalRaw(r2, 'rx_dropped'));
    _rfTrendHistory.retransmits.push(Math.floor(Math.random() * 3)); // simulated

    // Trim to max
    for (var key in _rfTrendHistory) {
      if (_rfTrendHistory[key].length > _rfTrendMax) _rfTrendHistory[key].shift();
    }

    // Redraw if trends panel is open
    var panel = document.getElementById('rf-trends-panel');
    if (panel && panel.classList.contains('open')) _rfDrawTrends();
  }

  //  RADIO UX UPGRADES (award audit — click-to-drill, sparklines, trends, tooltips)
  // ══════════════════════════════════════════════════════════════
  var _rfHistory = { 'RAD-01': [], 'RAD-02': [] };
  var _rfHistoryMax = 48;
  // Seed with realistic demo history
  (function() {
    for (var i = 0; i < 24; i++) {
      _rfHistory['RAD-01'].push(-53 + Math.round(Math.sin(i/3) * 2 + (Math.random() * 2 - 1)));
      _rfHistory['RAD-02'].push(-57 + Math.round(Math.sin(i/4) * 1.5 + (Math.random() * 2 - 1)));
    }
  })(); // 48 samples = 24h at 30min intervals (compressed for demo)
  var _rfDrillOpen = null;

