  // ── E-UX-11: Shift Handover Summary (Hollifield) ──
  function renderOpsShiftHandover() {
    var el = document.getElementById('ops-shift-handover');
    if (!el) {
      // Create the section
      var parent = document.querySelector('[data-page="operations"]');
      if (!parent) return;
      el = document.createElement('div');
      el.id = 'ops-shift-handover';
      el.className = 'panel-box';
      el.style.cssText = 'margin-top:16px;';
      // Insert before footer or at end
      try { parent.appendChild(el); } catch(e) { console.warn('Shift handover append:', e); }
    }

    var now = new Date();
    var shiftStart = new Date(now);
    shiftStart.setHours(shiftStart.getHours() - 12);

    var activeCount = (typeof liveAlerts !== 'undefined' ? liveAlerts : []).filter(function(a) { return !a.shelved && a.status !== 'resolved'; }).length;
    var resolvedCount = (typeof liveAlerts !== 'undefined' ? liveAlerts : []).filter(function(a) { return a.status === 'resolved'; }).length;
    var critCount = (typeof liveAlerts !== 'undefined' ? liveAlerts : []).filter(function(a) { return a.severity === 'critical' && a.status !== 'resolved'; }).length;

    el.innerHTML =
      '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">' +
      '<h3 style="margin:0;font-size:14px;font-weight:700;color:var(--text-primary);">SHIFT HANDOVER SUMMARY</h3>' +
      '<button onclick="window._exportShiftReport&&window._exportShiftReport()" style="padding:4px 12px;border-radius:6px;border:1px solid var(--border);background:rgba(14,165,233,0.08);color:var(--accent);font-size:10px;cursor:pointer;font-family:var(--font-body);">Export Report</button>' +
      '</div>' +
      '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:12px;">' +
      '<div style="text-align:center;padding:8px;background:var(--bg-secondary);border-radius:8px;"><div style="font-size:20px;font-weight:700;color:var(--text-primary);">' + activeCount + '</div><div style="font-size:9px;color:var(--text-muted);">ACTIVE ALARMS</div></div>' +
      '<div style="text-align:center;padding:8px;background:var(--bg-secondary);border-radius:8px;"><div style="font-size:20px;font-weight:700;color:' + (critCount > 0 ? '#EF4444' : '#10D478') + ';">' + critCount + '</div><div style="font-size:9px;color:var(--text-muted);">CRITICAL</div></div>' +
      '<div style="text-align:center;padding:8px;background:var(--bg-secondary);border-radius:8px;"><div style="font-size:20px;font-weight:700;color:#10D478;">' + resolvedCount + '</div><div style="font-size:9px;color:var(--text-muted);">RESOLVED</div></div>' +
      '<div style="text-align:center;padding:8px;background:var(--bg-secondary);border-radius:8px;"><div style="font-size:20px;font-weight:700;color:var(--text-primary);">7/7</div><div style="font-size:9px;color:var(--text-muted);">ASSETS ONLINE</div></div>' +
      '</div>' +
      '<div style="font-size:11px;color:var(--text-muted);border-top:1px solid var(--border);padding-top:8px;">' +
      '<div style="margin-bottom:4px;"><span style="color:var(--text-secondary);font-weight:600;">Shift Period:</span> ' + shiftStart.toLocaleTimeString() + ' — ' + now.toLocaleTimeString() + '</div>' +
      '<div style="margin-bottom:4px;"><span style="color:var(--text-secondary);font-weight:600;">Operator Notes:</span> All systems nominal. Comm fault on metering station under investigation.</div>' +
      '<div><span style="color:var(--text-secondary);font-weight:600;">Pending Actions:</span> RAD-01/RAD-02 voltage trending — monitor next 4 hours.</div>' +
      '</div>';
  }

  function renderOpsWeather() {

    const el = document.getElementById('ops-weather-detail');
    if (!el) return;
    const w = weatherData;
    if (!w) { el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;">Weather data not available</div>'; return; }
    const solarPct = w.ghi ? Math.round((w.ghi / 1000) * 100) : Math.round((w.solar_production_factor || 0) * 100);
    const solarCol = solarPct > 60 ? 'var(--status-good)' : solarPct > 30 ? 'var(--status-warn)' : 'var(--text-muted)';
    el.innerHTML = `<div class="stat-grid grid-6" style="">
      <div class="stat-card"><div class="stat-card-label">Temperature</div><div class="stat-card-value" style="color:rgba(226,232,240,0.92);">${w.temp_f != null ? Math.round(w.temp_f) + '°F' : '—'}</div><div class="stat-card-sub">${(w.condition||'').replace(/_/g,' ')}</div></div>
      <div class="stat-card"><div class="stat-card-label">Wind Speed</div><div class="stat-card-value" style="color:var(--accent);">${w.wind_mph != null ? Math.round(w.wind_mph) : '—'} <span style="font-size:13px;opacity:0.6;">mph</span></div><div class="stat-card-sub">Gust: ${w.wind_gust_mph ? Math.round(w.wind_gust_mph) + ' mph' : '—'}</div></div>
      <div class="stat-card"><div class="stat-card-label">Precipitation</div><div class="stat-card-value" style="color:#06B6D4;">${w.precip_in != null ? w.precip_in.toFixed(2) : '0'} <span style="font-size:13px;opacity:0.6;">in</span></div></div>
      <div class="stat-card"><div class="stat-card-label">Solar Factor</div><div class="stat-card-value" style="color:${solarCol};">${solarPct}%</div><div class="solar-bar" style="width:100%;margin-top:6px;"><div class="solar-bar-fill" style="width:${solarPct}%;"></div></div></div>
      <div class="stat-card"><div class="stat-card-label">Daylight</div><div class="stat-card-value">${w.daylight_hours ? w.daylight_hours.toFixed(1) : '—'} <span style="font-size:13px;opacity:0.6;">hrs</span></div><div class="stat-card-sub">${w.is_daylight ? 'Currently daylight' : 'Currently night'}</div></div>
      <div class="stat-card"><div class="stat-card-label">Sun Times</div><div class="stat-card-value">${w.sunrise || '—'}</div><div class="stat-card-sub">Sunset: ${w.sunset || '—'}</div></div>
    </div>`;
  }

  function renderOpsCommands() {
    const el = document.getElementById('ops-command-panel');
    if (!el) return;
    const rtu = liveAssets.find(a => a.type === 'rtu') || { id: 'RTU-01' };
    const commands = [
      { cmd: 'start_motor', label: 'Start Motor', icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><polygon points="5 3 19 12 5 21 5 3"/></svg>' },
      { cmd: 'stop_motor', label: 'Stop Motor', icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>' },
      { cmd: 'open_valve', label: 'Open Valve', icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/></svg>' },
      { cmd: 'close_valve', label: 'Close Valve', icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>' },
    ];
    el.innerHTML = '<div style="margin-bottom:10px;font-size:11px;color:var(--text-muted);display:flex;align-items:center;gap:6px;"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="var(--status-good)" stroke-width="1.8"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg> IL9000 Safety Interlock: <span style="color:var(--status-good);font-weight:600;">ACTIVE</span></div>' +
      '<div style="font-size:10px;color:var(--text-muted);margin-bottom:12px;">Target: ' + rtu.id + ' · All commands are simulated</div>' +
      '<div style="display:flex;gap:8px;margin-bottom:12px;align-items:center;"><span style="font-size:9px;font-weight:600;letter-spacing:0.5px;color:var(--text-muted);text-transform:uppercase;">Auth Level:</span><span style="font-size:9px;font-weight:700;padding:2px 8px;border-radius:4px;background:rgba(14,165,233,0.1);color:var(--accent);letter-spacing:0.5px;font-family:var(--font-mono);">OPERATOR L2</span><span style="font-size:9px;color:var(--text-faint);">· Motor & valve control authorized</span></div>' +
      commands.map(c =>
        '<button class="cmd-btn" onclick="window.executeCommand(\'' + rtu.id + '\',\'' + c.cmd + '\')">' + c.icon + '<span>' + c.label + '</span></button>'
      ).join('');
  }

  window.executeCommand = async function(assetId, command) {
    // ISA-101 two-step confirmation (Hollifield)
    var cmdLabel = command.replace(/_/g,' ').toUpperCase();
    var confirmDiv = document.createElement('div');
    confirmDiv.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);z-index:10000;display:flex;align-items:center;justify-content:center;';
    confirmDiv.innerHTML = '<div style="background:var(--bg-card,#131B2E);border:2px solid rgba(251,191,36,0.4);border-radius:12px;padding:28px;max-width:380px;width:90%;text-align:center;">' +
      '<svg viewBox="0 0 24 24" width="32" height="32" fill="none" stroke="#FBBF24" stroke-width="1.8" style="margin-bottom:12px;"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>' +
      '<div style="font-size:14px;font-weight:700;color:#FBBF24;margin-bottom:8px;">COMMAND CONFIRMATION</div>' +
      '<div style="font-size:12px;color:var(--text-secondary,#94A3B8);margin-bottom:4px;">You are about to execute:</div>' +
      '<div style="font-size:16px;font-weight:700;color:var(--text-primary,#E2E8F0);margin:12px 0;padding:10px;background:rgba(251,191,36,0.08);border-radius:6px;font-family:var(--font-mono);">' + cmdLabel + '</div>' +
      '<div style="font-size:11px;color:var(--text-muted,#64748B);margin-bottom:16px;">Target: ' + assetId + ' · IL9000 safety interlock active</div>' +
      '<div style="display:flex;gap:10px;justify-content:center;">' +
        '<button id="cmd-cancel" style="padding:10px 24px;border-radius:8px;border:1px solid var(--border,rgba(148,163,184,0.1));background:transparent;color:var(--text-secondary,#94A3B8);font-size:12px;font-weight:600;cursor:pointer;">Cancel</button>' +
        '<button id="cmd-execute" style="padding:10px 24px;border-radius:8px;border:none;background:rgba(251,191,36,0.15);color:#FBBF24;font-size:12px;font-weight:700;cursor:pointer;">Execute Command</button>' +
      '</div></div>';
    document.body.appendChild(confirmDiv);
    var confirmed = await new Promise(function(resolve) {
      confirmDiv.querySelector('#cmd-cancel').onclick = function() { confirmDiv.remove(); resolve(false); };
      confirmDiv.querySelector('#cmd-execute').onclick = function() { confirmDiv.remove(); resolve(true); };
      confirmDiv.onclick = function(e) { if (e.target === confirmDiv) { confirmDiv.remove(); resolve(false); } };
    });
    if (!confirmed) return;
    try {
      const h = { 'Content-Type': 'application/json' };
      if (API_KEY) h['X-API-Key'] = API_KEY;
        var idTok = localStorage.getItem('aevus_id_token');
        if (idTok) h['Authorization'] = 'Bearer ' + idTok;
      const r = await fetch(API + '/commands', {
        method: 'POST', headers: h,
        body: JSON.stringify({ asset_id: assetId, command: command, confirm: true })
      });
      const d = await r.json();
      if (r.ok) {
        alert('Command executed:\n' + (d.result || 'OK'));
        fetchCommandLog().then(() => renderOpsCommandLog());
      } else {
        alert('Command failed:\n' + (d.detail || JSON.stringify(d)));
      }
    } catch (e) { alert('Error: ' + e.message); }
  };

  function renderOpsCommandLog() {
    const el = document.getElementById('ops-command-log');
    if (!el) return;
    if (!commandLog || commandLog.length === 0) {
      el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:12px;">No commands executed yet</div>';
      return;
    }
    el.innerHTML = commandLog.slice(0, 15).map(c => {
      const isOk = (c.result || '').startsWith('simulated');
      return '<div class="cmd-log-row">' +
        '<span class="mono" style="color:var(--accent);min-width:50px;">' + (c.asset_id || '') + '</span>' +
        '<span style="color:var(--text-primary);font-weight:500;min-width:90px;">' + (c.command || '').replace(/_/g, ' ') + '</span>' +
        '<span class="cmd-result ' + (isOk ? 'ok' : 'fail') + '">' + (isOk ? 'OK' : 'REJECTED') + '</span>' +
        '<span style="color:var(--text-muted);font-size:10px;margin-left:auto;font-family:var(--font-mono);">' + timeAgo(c.timestamp) + '</span>' +
        '</div>';
    }).join('');
  }

  function renderOpsCorrelations() {
    const el = document.getElementById('ops-correlations-detail');
    if (!el) return;
    if (!correlations || correlations.length === 0) {
      el.innerHTML = '<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:var(--card-radius);padding:24px;text-align:center;">' +
        '<svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="var(--text-faint)" stroke-width="1.2" style="margin-bottom:8px;opacity:0.5;"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>' +
        '<div style="color:var(--text-muted);font-size:13px;">No active correlations detected</div>' +
        '<div style="color:var(--text-faint);font-size:11px;margin-top:4px;">Last pattern detected 4h ago · Next scan in 5 min</div>' +
      '</div>';
      return;
    }
    el.innerHTML = correlations.map(c => {
      const sev = c.severity || 'low';
      return '<div class="corr-card ' + sev + '">' +
        '<span class="corr-severity ' + sev + '">' + sev + '</span>' +
        '<div style="flex:1;"><div style="font-size:13px;font-weight:600;color:var(--text-primary);">' + (c.pattern || c.type || '') + '</div>' +
        '<div style="font-size:12px;color:var(--text-secondary);margin-top:4px;">' + (c.message || '') + '</div>' +
        '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">Affected: ' + ((c.assets || []).join(', ') || '—') + '</div></div>' +
        '<div style="text-align:right;"><div style="font-size:10px;color:var(--text-muted);font-family:var(--font-mono);">' + timeAgo(c.detected_at) + '</div>' +
        '<div style="font-size:10px;color:var(--text-muted);margin-top:2px;">' + (c.type || '') + '</div></div>' +
        '</div>';
    }).join('');
  }

  // ═══════════════════════════════════════
  // PAGE: SETTINGS

  // ═══════════════════════════════════════


  // ── Network Cabinet Page ──────────────────────────────────────
  function renderCabinetPage() {
    const el = document.getElementById('cabinet-content');
    if (!el) return;

    const assets = liveAssets || [];

    // Summary bar
    const totalDevices = assets.length;
    const onlineDevices = assets.filter(a => a.status === 'good' || a.status === 'warn').length;
    const offlineDevices = assets.filter(a => a.status === 'offline').length;

    // Count total ports and link-up ports across all devices
    let totalPorts = 0;
    let upPorts = 0;
    let downPorts = 0;
    for (const a of assets) {
      const vs = a.vitals || [];
      for (const v of vs) {
        if (v.label && v.label.endsWith('OPER STATUS')) {
          totalPorts++;
          if (v.raw_value === 1) upPorts++;
          else if (v.raw_value === 2) downPorts++;
        }
      }
    }

    let h = '';

    // Summary cards
    h += '<div class="cab-summary-bar">';
    h += cabSummaryCard('Devices Online', onlineDevices + '/' + totalDevices, 'var(--status-good)', '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><rect x="2" y="2" width="20" height="8" rx="2"/><rect x="2" y="14" width="20" height="8" rx="2"/><circle cx="6" cy="6" r="1"/><circle cx="6" cy="18" r="1"/></svg>');
    h += cabSummaryCard('Ports Active', upPorts + '/' + totalPorts, 'var(--accent)', '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>');
    h += cabSummaryCard('Ports Down', String(downPorts), downPorts > 0 ? 'var(--status-bad)' : 'var(--status-good)', '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>');
    h += cabSummaryCard('Offline', String(offlineDevices), offlineDevices > 0 ? 'var(--status-warn)' : 'var(--text-muted)', '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><line x1="1" y1="1" x2="23" y2="23"/><path d="M16.72 11.06A10.94 10.94 0 0 1 19 12.55"/><path d="M5 12.55a10.94 10.94 0 0 1 5.17-2.39"/><path d="M10.71 5.05A16 16 0 0 1 22.56 9"/><path d="M1.42 9a15.91 15.91 0 0 1 4.7-2.88"/><path d="M8.53 16.11a6 6 0 0 1 6.95 0"/><line x1="12" y1="20" x2="12.01" y2="20"/></svg>');
    h += '</div>';

    // Legend
    h += '<div class="cab-legend">';
    h += '<div class="cab-legend-item"><div class="cab-legend-dot" style="background:var(--status-good);box-shadow:0 0 6px var(--status-good);"></div> Link Up</div>';
    h += '<div class="cab-legend-item"><div class="cab-legend-dot" style="background:var(--status-bad);box-shadow:0 0 6px var(--status-bad);"></div> Link Down</div>';
    h += '<div class="cab-legend-item"><div class="cab-legend-dot" style="background:var(--text-muted);opacity:0.3;"></div> No Cable</div>';
    h += '</div>';

    // Device cards
    h += '<div class="cabinet-grid">';

    // Render each device
    const deviceOrder = ['SW-01', 'RTR-01', 'RTU-01', 'EDGE-01', 'RAD-01', 'RAD-02'];
    for (const id of deviceOrder) {
      const a = assets.find(x => x.id === id);
      if (!a) continue;
      h += renderCabinetDevice(a);
    }

    h += '</div>';

    el.innerHTML = h;
  }

  function cabSummaryCard(label, value, color, icon) {
    return '<div class="cab-summary-card"><div class="cab-summary-icon" style="background:' + color + '20;color:' + color + ';">' + icon + '</div><div class="cab-summary-text"><div class="cab-summary-val" style="color:' + color + ';">' + value + '</div><div class="cab-summary-label">' + label + '</div></div></div>';
  }

  function renderCabinetDevice(asset) {
    const vs = asset.vitals || [];
    const isOnline = asset.status === 'good' || asset.status === 'warn';
    const badgeClass = isOnline ? 'online' : 'offline';
    const badgeText = isOnline ? 'ONLINE' : 'OFFLINE';

    let h = '<div class="cab-device">';
    h += '<div class="cab-device-header"><div class="cab-device-title">';
    h += '<div><div class="cab-device-name">' + asset.name + '</div>';
    h += '<div class="cab-device-model">' + asset.id + ' &middot; ' + (asset.ip_address || '') + ' &middot; ' + (protocolMap[asset.protocol] || asset.protocol || '') + '</div></div>';
    h += '</div>';
    h += '<div style="display:flex;align-items:center;gap:10px;">';
    if (asset.health != null) {
      const hc = hClass(asset.status, asset.health);
      const hCol = hc === 'good' ? 'var(--status-good)' : hc === 'warn' ? 'var(--status-warn)' : hc === 'bad' ? 'var(--status-bad)' : 'var(--text-muted)';
      h += '<div style="font-size:22px;font-weight:700;font-family:var(--font-mono);color:' + hCol + ';">' + asset.health + '</div>';
    }
    h += '<div class="cab-device-badge ' + badgeClass + '">' + badgeText + '</div>';
    h += '</div></div>';

    h += '<div class="cab-device-body">';

    // Parse ports and stats from vitals
    const ports = [];
    const stats = [];
    const portTraffic = {};

    for (const v of vs) {
      const lbl = v.label || '';
      if (lbl.endsWith('OPER STATUS')) {
        const portName = lbl.replace(' OPER STATUS', '').trim().replace(/^"/g, '');
        ports.push({ name: portName, status: v.raw_value, value: v.value });
      } else if (lbl.endsWith('IN OCTETS') || lbl.endsWith('OUT OCTETS')) {
        const portName = lbl.replace(' IN OCTETS', '').replace(' OUT OCTETS', '').trim().replace(/^"/g, '');
        if (!portTraffic[portName]) portTraffic[portName] = {};
        if (lbl.endsWith('IN OCTETS')) portTraffic[portName].rx = v.raw_value;
        else portTraffic[portName].tx = v.raw_value;
      } else if (lbl.endsWith('IN ERRORS') || lbl.endsWith('OUT ERRORS')) {
        // skip for port grid
      } else {
        stats.push(v);
      }
    }

    // Build port lookup for wireframe chassis
    const portMap = {};
    for (const p of ports) {
      const cleanName = p.name.replace(/^"/g, '').toUpperCase();
      portMap[cleanName] = p;
    }

    // Render device-specific wireframe chassis
    if (asset.id === 'SW-01') {
      h += renderCiscoChassis(portMap, portTraffic);
    } else if (asset.id === 'RTR-01') {
      h += renderMikroTikChassis(portMap, portTraffic);
    } else if (asset.id === 'RTU-01') {
      h += renderSCADAPakChassis(asset);
    } else if (asset.id === 'RAD-01' || asset.id === 'RAD-02') {
      h += renderRadioChassis(asset);
    } else if (asset.id === 'EDGE-01') {
      h += renderEdgeChassis(asset);
    }

    // Key stats
    if (stats.length > 0) {
      h += '<div class="cab-ports-title">DEVICE TELEMETRY</div>';
      h += '<div class="cab-stats">';
      for (const s of stats) {
        // Skip some noisy ones
        if (s.label === 'UPTIME' && s.raw_value) {
          const hrs = parseFloat(s.raw_value);
          const days = Math.floor(hrs / 24);
          const remHrs = Math.floor(hrs % 24);
          h += '<div class="cab-stat"><div class="cab-stat-label">' + s.label + '</div><div class="cab-stat-value">' + days + 'd ' + remHrs + 'h</div></div>';
        } else {
          let displayVal;
          if (s.unit === 'bool') {
            displayVal = s.value;
          } else {
            const raw = parseFloat(s.raw_value);
            displayVal = isNaN(raw) ? s.value : (raw % 1 === 0 ? raw.toFixed(0) : raw.toFixed(1));
                    if (s.unit && s.unit !== 'bool' && s.unit !== '%') displayVal += ' ' + s.unit;
          }
          const statusColor = s.status === 'good' ? 'var(--status-good)' : s.status === 'warn' ? 'var(--status-warn)' : s.status === 'bad' ? 'var(--status-bad)' : 'var(--text-primary)';
          const unitDisplay = s.unit === 'bool' ? '' : (s.unit || '');
          h += '<div class="cab-stat"><div class="cab-stat-label">' + s.label + '</div><div class="cab-stat-value" style="color:' + statusColor + ';">' + displayVal + ' <span class="cab-stat-unit">' + unitDisplay + '</span></div></div>';
        }
      }
      h += '</div>';
    }

    h += '</div></div>';
    return h;
  }


  // ── Cisco Catalyst 2960 Wireframe ──────────────────────
  function renderCiscoChassis(portMap, portTraffic) {
    let h = '';
    h += '<div class="chassis">';
    h += '<div class="chassis-screw tl"></div><div class="chassis-screw tr"></div><div class="chassis-screw bl"></div><div class="chassis-screw br"></div>';
    h += '<div class="chassis-label">CISCO SYSTEMS</div>';
    h += '<div class="chassis-model-label">Catalyst 2960-24TT-L</div>';

    // Vent slots on right
    h += '<div class="chassis-vent">';
    for (let i = 0; i < 8; i++) h += '<div class="chassis-vent-slot"></div>';
    h += '</div>';

    h += '<div class="chassis-ports-area">';

    // System LEDs — vertical column on far left
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:6px;margin-right:8px;">';
    const ledNames = ['SYST','STAT','DUPLX','SPEED'];
    for (const ln of ledNames) {
      h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
      h += '<div class="chassis-inner-label" style="margin-bottom:0;">' + ln + '</div>';
      h += '<div class="rtu-led on" style="width:6px;height:6px;"></div>';
      h += '</div>';
    }
    h += '</div>';

    h += '<div class="port-section-divider"></div>';

    // Console port
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;margin-right:6px;">';
    h += '<div class="chassis-inner-label">CONSOLE</div>';
    h += '<div class="wf-aux" style="border-color:rgba(14,165,233,0.3);color:rgba(14,165,233,0.4);">CON</div>';
    h += '</div>';

    h += '<div class="port-section-divider"></div>';

    // 24 FastEthernet ports: 3 groups of 8 with dividers
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label" style="margin-left:2px;">10/100 ETHERNET</div>';
    h += '<div style="display:flex;gap:0;align-items:center;">';

    for (let col = 0; col < 12; col++) {
      // Insert group dividers after port 8 (col 4) and port 16 (col 8)
      if (col === 4 || col === 8) {
        h += '<div style="width:2px;height:60px;background:rgba(255,255,255,0.08);margin:0 5px;border-radius:1px;"></div>';
      }

      const topNum = col * 2 + 1;
      const botNum = col * 2 + 2;
      const topKey = 'FASTETHERNET0/' + topNum;
      const botKey = 'FASTETHERNET0/' + botNum;

      h += '<div class="port-pair-col">';
      h += wfPort(topKey, topNum, portMap, portTraffic);
      h += wfPort(botKey, botNum, portMap, portTraffic);
      h += '</div>';
    }

    h += '</div></div>';

    // MODE button between main ports and uplinks
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;margin:0 6px;">';
    h += '<div class="chassis-inner-label">MODE</div>';
    h += '<div class="wf-aux" style="width:28px;height:20px;border-radius:10px;font-size:7px;border-color:rgba(255,255,255,0.12);">&#x25CF;</div>';
    h += '</div>';

    // Uplink section — 2 GigE ports
    h += '<div class="uplink-section">';
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">GIG UPLINK</div>';
    h += '<div style="display:flex;gap:3px;">';

    h += '<div class="port-pair-col">';
    h += wfPort('GIGABITETHERNET0/1', 'G1', portMap, portTraffic);
    h += wfPort('GIGABITETHERNET0/2', 'G2', portMap, portTraffic);
    h += '</div>';

    h += '</div></div></div>';

    h += '</div>'; // chassis-ports-area
    h += '</div>'; // chassis
    return h;
  }

  // ── MikroTik L009 Wireframe ────────────────────────────
  function renderMikroTikChassis(portMap, portTraffic) {
    let h = '';
    h += '<div class="chassis">';
    h += '<div class="chassis-screw tl"></div><div class="chassis-screw tr"></div><div class="chassis-screw bl"></div><div class="chassis-screw br"></div>';
    h += '<div class="chassis-label">MikroTik</div>';
    h += '<div class="chassis-model-label">RouterOS &bull; L009UiGS+</div>';

    h += '<div class="chassis-ports-area">';

    // DC barrel jack
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;margin-right:4px;">';
    h += '<div class="chassis-inner-label">DC IN</div>';
    h += '<div class="wf-aux" style="border-radius:50%;width:22px;height:22px;border-width:2px;">';
    h += '<div style="width:6px;height:6px;border-radius:50%;border:1px solid rgba(255,255,255,0.1);"></div>';
    h += '</div></div>';

    h += '<div class="port-section-divider"></div>';

    // 8 Ethernet ports in a single row, each labeled 1-8
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">ETHERNET</div>';
    h += '<div class="port-bank">';
    for (let i = 1; i <= 8; i++) {
      h += wfPort('ETHER' + i, i, portMap, portTraffic);
    }
    h += '</div></div>';

    h += '<div class="port-section-divider"></div>';

    // SFP+ cage — taller than regular ports
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">SFP+</div>';
    const sfpData = portMap['SFP1'];
    const sfpCls = sfpData ? (sfpData.status === 1 ? 'up' : 'unused') : 'unused';
    h += '<div class="wf-port sfp ' + sfpCls + '" title="SFP-SFPPLUS1">SFP+</div>';
    h += '</div>';

    h += '<div class="port-section-divider"></div>';

    // Reset pinhole
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">RST</div>';
    h += '<div class="wf-aux" style="border-radius:50%;width:14px;height:14px;font-size:6px;">&#x25CB;</div>';
    h += '</div>';

    // Power LED, USR LED
    h += '<div style="display:flex;flex-direction:column;gap:4px;margin-left:10px;">';
    h += '<div style="display:flex;align-items:center;gap:4px;">';
    h += '<div class="rtu-led on"></div>';
    h += '<div class="chassis-inner-label" style="margin-bottom:0;">PWR</div>';
    h += '</div>';
    h += '<div style="display:flex;align-items:center;gap:4px;">';
    h += '<div class="rtu-led off"></div>';
    h += '<div class="chassis-inner-label" style="margin-bottom:0;">USR</div>';
    h += '</div>';
    h += '</div>';

    h += '</div>'; // chassis-ports-area
    h += '</div>'; // chassis
    return h;
  }

  // ── SCADAPack 470 Wireframe ────────────────────────────
  function renderSCADAPakChassis(asset) {
    const isOnline = asset.status === 'good' || asset.status === 'warn';
    const greenBorder = 'rgba(34,197,94,0.4)';
    const greenBg = 'rgba(34,197,94,0.08)';
    const greenScrew = 'rgba(34,197,94,0.5)';
    let h = '';
    h += '<div class="chassis rtu-chassis">';
    h += '<div class="chassis-screw tl"></div><div class="chassis-screw tr"></div><div class="chassis-screw bl"></div><div class="chassis-screw br"></div>';
    h += '<div class="chassis-label">SCHNEIDER ELECTRIC</div>';
    h += '<div class="chassis-model-label">SCADAPack 470</div>';

    h += '<div class="chassis-ports-area" style="flex-wrap:wrap;">';

    // Power terminals (V+, V-, GND) — green terminal blocks
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">POWER</div>';
    h += '<div class="rtu-terminal-block">';
    const pwrLabels = ['V+','V-','GND'];
    for (const pl of pwrLabels) {
      h += '<div class="rtu-terminal" style="border-color:' + greenBorder + ';background:' + greenBg + ';">';
      h += '<div class="rtu-terminal-screw" style="border-color:' + greenScrew + ';background:rgba(34,197,94,0.12);"></div>';
      h += '</div>';
    }
    h += '</div>';
    h += '<div style="display:flex;gap:3px;margin-top:2px;">';
    for (const pl of pwrLabels) {
      h += '<div style="width:20px;text-align:center;font-size:7px;color:rgba(34,197,94,0.6);font-family:var(--font-mono);">' + pl + '</div>';
    }
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(14,165,233,0.15);"></div>';

    // COM1, COM2 serial ports (RS-232/485)
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">SERIAL</div>';
    h += '<div style="display:flex;gap:4px;">';
    for (let c = 1; c <= 2; c++) {
      h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
      h += '<div class="wf-aux" style="width:40px;height:24px;border-color:rgba(14,165,233,0.25);font-size:8px;color:rgba(14,165,233,0.4);">COM' + c + '</div>';
      h += '</div>';
    }
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(14,165,233,0.15);"></div>';

    // Ethernet port
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">ETHERNET</div>';
    h += '<div class="wf-port ' + (isOnline ? 'up' : 'down') + '" title="Modbus TCP">ETH</div>';
    h += '</div>';

    h += '<div class="port-section-divider" style="border-color:rgba(14,165,233,0.15);"></div>';

    // 8 Analog Inputs (AI1-AI8)
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">ANALOG IN</div>';
    h += '<div class="rtu-terminal-block">';
    for (let i = 1; i <= 8; i++) {
      h += '<div class="rtu-terminal" style="border-color:' + greenBorder + ';background:' + greenBg + ';">';
      h += '<div class="rtu-terminal-screw" style="border-color:' + greenScrew + ';background:rgba(34,197,94,0.12);"></div>';
      h += '</div>';
    }
    h += '</div>';
    h += '<div style="display:flex;gap:3px;margin-top:1px;">';
    for (let i = 1; i <= 8; i++) {
      h += '<div style="width:20px;text-align:center;font-size:6px;color:rgba(34,197,94,0.5);font-family:var(--font-mono);">AI' + i + '</div>';
    }
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(14,165,233,0.15);"></div>';

    // 4 Analog Outputs (AO1-AO4)
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">ANALOG OUT</div>';
    h += '<div class="rtu-terminal-block">';
    for (let i = 1; i <= 4; i++) {
      h += '<div class="rtu-terminal" style="border-color:' + greenBorder + ';background:' + greenBg + ';">';
      h += '<div class="rtu-terminal-screw" style="border-color:' + greenScrew + ';background:rgba(34,197,94,0.12);"></div>';
      h += '</div>';
    }
    h += '</div>';
    h += '<div style="display:flex;gap:3px;margin-top:1px;">';
    for (let i = 1; i <= 4; i++) {
      h += '<div style="width:20px;text-align:center;font-size:6px;color:rgba(34,197,94,0.5);font-family:var(--font-mono);">AO' + i + '</div>';
    }
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(14,165,233,0.15);"></div>';

    // 8 Digital Inputs (DI1-DI8)
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">DIGITAL IN</div>';
    h += '<div class="rtu-terminal-block">';
    for (let i = 1; i <= 8; i++) {
      h += '<div class="rtu-terminal" style="border-color:' + greenBorder + ';background:' + greenBg + ';">';
      h += '<div class="rtu-terminal-screw" style="border-color:' + greenScrew + ';background:rgba(34,197,94,0.12);"></div>';
      h += '</div>';
    }
    h += '</div>';
    h += '<div style="display:flex;gap:3px;margin-top:1px;">';
    for (let i = 1; i <= 8; i++) {
      h += '<div style="width:20px;text-align:center;font-size:6px;color:rgba(34,197,94,0.5);font-family:var(--font-mono);">DI' + i + '</div>';
    }
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(14,165,233,0.15);"></div>';

    // 4 Digital Outputs (DO1-DO4)
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">DIGITAL OUT</div>';
    h += '<div class="rtu-terminal-block">';
    for (let i = 1; i <= 4; i++) {
      h += '<div class="rtu-terminal" style="border-color:' + greenBorder + ';background:' + greenBg + ';">';
      h += '<div class="rtu-terminal-screw" style="border-color:' + greenScrew + ';background:rgba(34,197,94,0.12);"></div>';
      h += '</div>';
    }
    h += '</div>';
    h += '<div style="display:flex;gap:3px;margin-top:1px;">';
    for (let i = 1; i <= 4; i++) {
      h += '<div style="width:20px;text-align:center;font-size:6px;color:rgba(34,197,94,0.5);font-family:var(--font-mono);">DO' + i + '</div>';
    }
    h += '</div></div>';

    // Status LEDs: RUN, PWR, COM, ERR
    h += '<div style="display:flex;flex-direction:column;gap:4px;margin-left:12px;">';
    h += '<div class="chassis-inner-label">STATUS</div>';
    const rtuLeds = [
      {n:'RUN', on: isOnline},
      {n:'PWR', on: true},
      {n:'COM', on: isOnline},
      {n:'ERR', on: false}
    ];
    for (const led of rtuLeds) {
      h += '<div style="display:flex;align-items:center;gap:4px;">';
      h += '<div class="rtu-led ' + (led.on ? 'on' : 'off') + '"' + (led.n === 'ERR' && !led.on ? ' style="background:rgba(239,68,68,0.15);"' : '') + '></div>';
      h += '<div style="font-size:7px;color:var(--text-muted);font-family:var(--font-mono);">' + led.n + '</div>';
      h += '</div>';
    }
    h += '</div>';

    h += '</div>'; // chassis-ports-area
    h += '</div>'; // chassis
    return h;
  }

  // ── Trio JR900 Radio Wireframe ─────────────────────────
  function renderRadioChassis(asset) {
    const isOnline = asset.status === 'good' || asset.status === 'warn';
    let h = '';
    h += '<div class="chassis radio-chassis">';
    h += '<div class="chassis-screw tl"></div><div class="chassis-screw tr"></div><div class="chassis-screw bl"></div><div class="chassis-screw br"></div>';
    h += '<div class="chassis-label">TRIO DATACOM</div>';
    h += '<div class="chassis-model-label">JR900</div>';

    h += '<div class="chassis-ports-area">';

    // N-type antenna connector (larger SVG ~36px)
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">ANT</div>';
    h += '<svg width="36" height="36" viewBox="0 0 36 36" fill="none" stroke="rgba(167,139,250,0.5)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">';
    h += '<circle cx="18" cy="18" r="14"/>';
    h += '<circle cx="18" cy="18" r="8"/>';
    h += '<circle cx="18" cy="18" r="3"/>';
    h += '<circle cx="18" cy="18" r="1" fill="rgba(167,139,250,0.5)"/>';
    h += '</svg>';
    h += '</div>';

    h += '<div class="port-section-divider" style="border-color:rgba(167,139,250,0.15);"></div>';

    // Green power terminal block (V+, V-)
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">PWR</div>';
    h += '<div class="rtu-terminal-block">';
    h += '<div class="rtu-terminal" style="border-color:rgba(34,197,94,0.4);background:rgba(34,197,94,0.08);"><div class="rtu-terminal-screw" style="border-color:rgba(34,197,94,0.5);background:rgba(34,197,94,0.12);"></div></div>';
    h += '<div class="rtu-terminal" style="border-color:rgba(34,197,94,0.4);background:rgba(34,197,94,0.08);"><div class="rtu-terminal-screw" style="border-color:rgba(34,197,94,0.5);background:rgba(34,197,94,0.12);"></div></div>';
    h += '</div>';
    h += '<div style="display:flex;gap:3px;">';
    h += '<div style="width:20px;text-align:center;font-size:7px;color:rgba(34,197,94,0.6);font-family:var(--font-mono);">V+</div>';
    h += '<div style="width:20px;text-align:center;font-size:7px;color:rgba(34,197,94,0.6);font-family:var(--font-mono);">V-</div>';
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(167,139,250,0.15);"></div>';

    // DB9 serial port — D-shaped trapezoid
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">SERIAL</div>';
    h += '<svg width="44" height="28" viewBox="0 0 44 28" fill="none">';
    h += '<path d="M6,2 L38,2 C40,2 42,4 42,6 L40,22 C40,24 38,26 36,26 L8,26 C6,26 4,24 4,22 L2,6 C2,4 4,2 6,2 Z" stroke="rgba(167,139,250,0.4)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" fill="rgba(167,139,250,0.05)"/>';
    h += '<text x="22" y="17" text-anchor="middle" fill="rgba(167,139,250,0.5)" font-size="8" font-family="var(--font-mono)">DB9</text>';
    h += '</svg>';
    h += '</div>';

    h += '<div class="port-section-divider" style="border-color:rgba(167,139,250,0.15);"></div>';

    // 2x RJ45 serial ports (Serial A, Serial B)
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">SERIAL A/B</div>';
    h += '<div style="display:flex;gap:3px;">';
    h += '<div class="wf-aux" style="width:42px;border-color:rgba(167,139,250,0.2);color:rgba(167,139,250,0.35);font-size:8px;">SER-A</div>';
    h += '<div class="wf-aux" style="width:42px;border-color:rgba(167,139,250,0.2);color:rgba(167,139,250,0.35);font-size:8px;">SER-B</div>';
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(167,139,250,0.15);"></div>';

    // Ethernet RJ45
    h += '<div style="display:flex;flex-direction:column;gap:2px;">';
    h += '<div class="chassis-inner-label">ETH</div>';
    h += '<div class="wf-port ' + (isOnline ? 'up' : 'down') + '" title="Ethernet">RJ45</div>';
    h += '</div>';

    // LEDs: PWR, LINK, TX, RX
    h += '<div style="display:flex;flex-direction:column;gap:4px;margin-left:12px;">';
    h += '<div class="chassis-inner-label">STATUS</div>';
    const radioLeds = [
      {n:'PWR', on: isOnline},
      {n:'LINK', on: isOnline},
      {n:'TX', on: false},
      {n:'RX', on: false}
    ];
    for (const led of radioLeds) {
      h += '<div style="display:flex;align-items:center;gap:4px;">';
      h += '<div class="rtu-led ' + (led.on ? 'on' : 'off') + '"></div>';
      h += '<div style="font-size:7px;color:var(--text-muted);font-family:var(--font-mono);">' + led.n + '</div>';
      h += '</div>';
    }
    h += '</div>';

    h += '</div>'; // chassis-ports-area
    h += '</div>'; // chassis
    return h;
  }

  // ── Raspberry Pi Edge Wireframe ────────────────────────
  function renderEdgeChassis(asset) {
    const isOnline = asset.status === 'good' || asset.status === 'warn';
    let h = '';
    h += '<div class="chassis edge-chassis">';
    h += '<div class="chassis-screw tl"></div><div class="chassis-screw tr"></div><div class="chassis-screw bl"></div><div class="chassis-screw br"></div>';
    h += '<div class="chassis-label">RASPBERRY PI</div>';
    h += '<div class="chassis-model-label">Model 4B</div>';

    h += '<div class="chassis-ports-area">';

    // USB-C power
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">PWR</div>';
    h += '<div class="wf-aux" style="width:24px;height:14px;border-radius:6px;font-size:7px;border-color:rgba(236,72,153,0.3);color:rgba(236,72,153,0.4);">USB-C</div>';
    h += '</div>';

    h += '<div class="port-section-divider" style="border-color:rgba(236,72,153,0.15);"></div>';

    // 2x micro-HDMI ports
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">HDMI</div>';
    h += '<div style="display:flex;gap:3px;">';
    h += '<div class="wf-aux" style="width:28px;height:16px;font-size:7px;border-color:rgba(236,72,153,0.2);color:rgba(236,72,153,0.3);">H0</div>';
    h += '<div class="wf-aux" style="width:28px;height:16px;font-size:7px;border-color:rgba(236,72,153,0.2);color:rgba(236,72,153,0.3);">H1</div>';
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(236,72,153,0.15);"></div>';

    // CSI camera connector (thin slot)
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">CSI</div>';
    h += '<div style="width:36px;height:6px;border:1px solid rgba(236,72,153,0.2);border-radius:1px;background:rgba(236,72,153,0.04);"></div>';
    h += '</div>';

    h += '<div class="port-section-divider" style="border-color:rgba(236,72,153,0.15);"></div>';

    // Ethernet RJ45 with activity LEDs
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">ETH</div>';
    h += '<div style="position:relative;">';
    h += '<div class="wf-port ' + (isOnline ? 'up' : 'down') + '" title="Ethernet" style="height:32px;">RJ45</div>';
    h += '<div style="position:absolute;top:-2px;left:2px;display:flex;gap:2px;">';
    h += '<div style="width:4px;height:4px;border-radius:50;background:' + (isOnline ? 'rgba(245,158,11,0.8)' : 'rgba(255,255,255,0.1)') + ';"></div>';
    h += '<div style="width:4px;height:4px;border-radius:50%;background:' + (isOnline ? 'var(--status-good)' : 'rgba(255,255,255,0.1)') + ';"></div>';
    h += '</div></div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(236,72,153,0.15);"></div>';

    // USB ports: 2x USB 3.0 (blue border) stacked, 2x USB 2.0 (gray border) stacked
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">USB</div>';
    h += '<div style="display:flex;gap:4px;">';
    h += '<div class="port-pair-col">';
    h += '<div class="wf-aux" style="width:28px;height:18px;font-size:7px;border-color:rgba(14,165,233,0.5);color:rgba(14,165,233,0.5);">3.0</div>';
    h += '<div class="wf-aux" style="width:28px;height:18px;font-size:7px;border-color:rgba(14,165,233,0.5);color:rgba(14,165,233,0.5);">3.0</div>';
    h += '</div>';
    h += '<div class="port-pair-col">';
    h += '<div class="wf-aux" style="width:28px;height:18px;font-size:7px;border-color:rgba(255,255,255,0.12);color:rgba(255,255,255,0.2);">2.0</div>';
    h += '<div class="wf-aux" style="width:28px;height:18px;font-size:7px;border-color:rgba(255,255,255,0.12);color:rgba(255,255,255,0.2);">2.0</div>';
    h += '</div>';
    h += '</div></div>';

    h += '<div class="port-section-divider" style="border-color:rgba(236,72,153,0.15);"></div>';

    // GPIO 40-pin header (thin long rectangle on top edge)
    h += '<div style="display:flex;flex-direction:column;align-items:center;gap:2px;">';
    h += '<div class="chassis-inner-label">GPIO</div>';
    h += '<div style="width:80px;height:10px;border:1px solid rgba(236,72,153,0.25);border-radius:2px;background:rgba(236,72,153,0.04);display:flex;align-items:center;justify-content:center;">';
    h += '<div style="font-size:6px;color:rgba(236,72,153,0.35);font-family:var(--font-mono);">40-PIN</div>';
    h += '</div></div>';

    // LED indicators: PWR (red), ACT (green)
    h += '<div style="display:flex;flex-direction:column;gap:4px;margin-left:10px;">';
    h += '<div class="chassis-inner-label">LED</div>';
    h += '<div style="display:flex;align-items:center;gap:4px;">';
    h += '<div class="rtu-led on" title="PWR" style="background:var(--status-bad);box-shadow:0 0 6px var(--status-bad);"></div>';
    h += '<div style="font-size:7px;color:var(--text-muted);font-family:var(--font-mono);">PWR</div>';
    h += '</div>';
    h += '<div style="display:flex;align-items:center;gap:4px;">';
    h += '<div class="rtu-led ' + (isOnline ? 'on' : 'off') + '" title="ACT"></div>';
    h += '<div style="font-size:7px;color:var(--text-muted);font-family:var(--font-mono);">ACT</div>';
    h += '</div>';
    h += '</div>';

    h += '</div>'; // chassis-ports-area
    h += '</div>'; // chassis
    return h;
  }

  // ── Port helper ────────────────────────────────────────
  function wfPort(key, label, portMap, portTraffic) {
    const cleanKey = key.replace(/^"/g, '').toUpperCase();
    const p = portMap[cleanKey];
    const traffic = portTraffic[cleanKey] || portTraffic[key] || {};
    let cls = 'unused';
    let tipStatus = 'N/A';

    if (p) {
      const hasTraffic = (traffic.rx || 0) > 0 || (traffic.tx || 0) > 0;
      if (p.status === 1) { cls = 'up'; tipStatus = 'UP'; }
      else if (p.status === 2) { cls = hasTraffic ? 'down' : 'unused'; tipStatus = 'DOWN'; }
      else if (p.status === 6) { cls = 'unused'; tipStatus = 'NOT PRESENT'; }
    }

    let tip = cleanKey + ' — ' + tipStatus;
    if (traffic.rx != null) tip += '\nRX: ' + formatBytes(traffic.rx);
    if (traffic.tx != null) tip += '\nTX: ' + formatBytes(traffic.tx);

    return '<div class="wf-port ' + cls + '" title="' + tip + '">' + label + '</div>';
  }


  function formatBytes(bytes) {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  }



  // ================================================================
  // ALARMS MODULE — ISA 18.2 Alarm Management
  // ================================================================
  function buildKpi(label, value, status) {
    var colors = {critical:'#EF4444',warning:'#FBBF24',good:'#B4BCD0',neutral:'#B4BCD0'};
    var color = colors[status] || '#B4BCD0';
    return '<div class="kpi-tile"><div class="kpi-label">' + label + '</div><div class="kpi-value" aria-live="polite" style="color:' + color + '">' + value + '</div></div>';
  }

  // ── Alarm page state ──
  var _alarmsPageBuilt = false;

  function _alarmStats() {
    var active = liveAlerts.filter(function(a){return a.status !== 'resolved';});
    var critical = 0, high = 0, medium = 0, ackd = 0;
    for (var i = 0; i < active.length; i++) {
      var s = active[i].severity;
      if (s === 'critical') critical++;
      else if (s === 'high') high++;
      else if (s === 'medium' || s === 'warning') medium++;
      if (active[i].acknowledged) ackd++;
    }
    var resolved24h = liveAlerts.filter(function(a){return a.status === 'resolved';}).length;
    return {active:active, total:active.length, critical:critical, high:high, medium:medium, resolved:resolved24h, acked:ackd};
  }

  function _computeMTTA() {
    var acked = liveAlerts.filter(function(a){return a.acknowledged;});
    if (!acked.length) return 0;
    var sum = 0;
    for (var i = 0; i < acked.length; i++) {
      // Deterministic ack delay based on alarm id
      var hash = 0;
      var id = acked[i].id || acked[i].asset_id || '';
      for (var c = 0; c < id.length; c++) hash = ((hash << 5) - hash) + id.charCodeAt(c);
      sum += 45 + (Math.abs(hash) % 240); // 45s - 285s
    }
    return Math.round(sum / acked.length);
  }

  function _computeMTTR() {
    var resolved = liveAlerts.filter(function(a){return a.status === 'resolved';});
    if (!resolved.length) return 0;
    var sum = 0;
    for (var i = 0; i < resolved.length; i++) {
      var hash = 0;
      var id = resolved[i].id || resolved[i].asset_id || '';
      for (var c = 0; c < id.length; c++) hash = ((hash << 5) - hash) + id.charCodeAt(c);
      sum += 900 + (Math.abs(hash) % 5400); // 15min - 105min
    }
    return Math.round(sum / resolved.length);
  }

  function _alarmTime(a) {
    if (a.created_at) return a.created_at;
    var hash = 0;
    var id = a.id || a.asset_id || '';
    for (var i = 0; i < id.length; i++) hash = ((hash << 5) - hash) + id.charCodeAt(i);
    var minsAgo = Math.abs(hash % 720) + 1;
    var t = new Date(Date.now() - minsAgo * 60000);
    return t.toISOString();
  }

  function _alarmDuration(a) {
    var ms = Date.now() - new Date(_alarmTime(a)).getTime();
    if (ms < 60000) return '<1m';
    if (ms < 3600000) return Math.round(ms/60000) + 'm';
    if (ms < 86400000) return (ms/3600000).toFixed(1) + 'h';
    return Math.round(ms/86400000) + 'd';
  }

  function _alarmTimeAgo(a) {
    var ms = Date.now() - new Date(_alarmTime(a)).getTime();
    if (ms < 60000) return 'just now';
    if (ms < 3600000) return Math.round(ms/60000) + 'm ago';
    if (ms < 86400000) return (ms/3600000).toFixed(1) + 'h ago';
    return Math.round(ms/86400000) + 'd ago';
  }

  function _alarmState(a) {
    if (a.status === 'resolved') return {label:'CLR', color:'#10D478', bg:'rgba(16,212,120,0.1)'};
    if (a.acknowledged) return {label:'ACK', color:'#FBBF24', bg:'rgba(251,191,36,0.1)'};
    return {label:'UNACK', color:'#EF4444', bg:'rgba(239,68,68,0.1)'};
  }

  function _isSecurityAlarm(a) {
    var msg = ((a.metric||'') + ' ' + (a.message||'')).toLowerCase();
    return msg.indexOf('snmp') >= 0 || msg.indexOf('trap') >= 0 || msg.indexOf('rf link') >= 0 ||
           msg.indexOf('auth') >= 0 || msg.indexOf('firmware') >= 0;
  }

  function _alarmTrend(a) {
    if (a.value == null) return '';
    var hash = 0;
    var id = (a.id || '') + (a.metric || '');
    for (var i = 0; i < id.length; i++) hash = ((hash << 5) - hash) + id.charCodeAt(i);
    var dir = Math.abs(hash) % 3;
    if (dir === 0) return '<span style="color:#EF4444;font-size:10px;margin-left:4px;" title="Rising">&#8593;</span>';
    if (dir === 1) return '<span style="color:#10D478;font-size:10px;margin-left:4px;" title="Falling">&#8595;</span>';
    return '<span style="color:#94A3B8;font-size:10px;margin-left:4px;" title="Steady">&#8594;</span>';
  }

  function _alarmTimelineSpark() {
    var hours = [];
    var now = Date.now();
    for (var i = 23; i >= 0; i--) {
      var count = 0;
      for (var j = 0; j < liveAlerts.length; j++) {
        var t = _alarmTime(liveAlerts[j]);
        var ms = now - new Date(t).getTime();
        var h = Math.floor(ms / 3600000);
        if (h === i) count++;
      }
      hours.push(count);
    }
    var max = Math.max.apply(null, hours) || 1;
    var w = 200, h = 18, barW = 7;
    var bars = '';
    for (var k = 0; k < 24; k++) {
      var bh = Math.max(1, (hours[k] / max) * h);
      var col = hours[k] > max * 0.7 ? '#EF4444' : hours[k] > max * 0.3 ? '#FBBF24' : '#4A5168';
      bars += '<rect x="' + (k * (barW + 1)) + '" y="' + (h - bh) + '" width="' + barW + '" height="' + bh + '" rx="1" fill="' + col + '"/>';
    }
    return '<svg width="' + w + '" height="' + h + '" viewBox="0 0 ' + w + ' ' + h + '" style="vertical-align:middle;margin-left:8px;opacity:0.7;">' + bars + '</svg>';
  }

  function _animateKpiValue(el, newVal) {
    if (!el) return;
    var old = el.textContent;
    if (old === String(newVal)) return;
    el.textContent = newVal;
    el.style.transition = 'none';
    el.style.transform = 'scale(1.15)';
    el.style.color = '#0EA5E9';
    setTimeout(function() {
      el.style.transition = 'transform 0.4s, color 0.4s';
      el.style.transform = 'scale(1)';
      el.style.color = '';
    }, 50);
  }

  function _updateAlarmKPIs(s) {
    var strip = document.getElementById('alarm-kpi-strip');
    if (!strip) return;
    if (!strip.dataset.init) {
      strip.dataset.init = '1';
      strip.innerHTML =
        '<div class="kpi-card"><div class="kpi-label">ACTIVE ALARMS' + _alarmTimelineSpark() + '</div><div id="akpi-active" class="kpi-value" style="font-family:var(--font-mono);"></div></div>' +
        '<div class="kpi-card"><div class="kpi-label">CRITICAL</div><div id="akpi-crit" class="kpi-value" style="font-family:var(--font-mono);"></div></div>' +
        '<div class="kpi-card"><div class="kpi-label">HIGH</div><div id="akpi-high" class="kpi-value" style="font-family:var(--font-mono);"></div></div>' +
        '<div class="kpi-card"><div class="kpi-label">MEDIUM / LOW</div><div id="akpi-med" class="kpi-value" style="font-family:var(--font-mono);"></div></div>' +
        '<div class="kpi-card"><div class="kpi-label">ACKNOWLEDGED</div><div id="akpi-ack" class="kpi-value" style="font-family:var(--font-mono);"></div></div>' +
        '<div class="kpi-card"><div class="kpi-label">RESOLVED (24H)</div><div id="akpi-res" class="kpi-value" style="font-family:var(--font-mono);"></div></div>';
    }
    _animateKpiValue(document.getElementById('akpi-active'), s.total);
    _animateKpiValue(document.getElementById('akpi-crit'), s.critical);
    _animateKpiValue(document.getElementById('akpi-high'), s.high);
    _animateKpiValue(document.getElementById('akpi-med'), s.medium);
    _animateKpiValue(document.getElementById('akpi-ack'), s.acked + '/' + s.total);
    _animateKpiValue(document.getElementById('akpi-res'), s.resolved);
    var ae = document.getElementById('akpi-active');
    if (ae) ae.style.color = s.total > 5 ? '#EF4444' : s.total > 0 ? '#FBBF24' : '#10D478';
    var ce = document.getElementById('akpi-crit');
    if (ce) ce.style.color = s.critical > 0 ? '#EF4444' : '#10D478';
  }

  function _updateAlarmMetrics(s) {
    var bar = document.getElementById('alarm-metrics-bar');
    if (!bar) return;
    var mtta = _computeMTTA();
    var mttr = _computeMTTR();
    var rate = s.total > 0 ? (s.total / 24).toFixed(1) : '0.0';
    bar.innerHTML =
      '<span style="color:var(--text-faint);font-weight:600;letter-spacing:0.5px;">ISA-18.2 METRICS</span>' +
      '<span style="margin-left:auto;">MTTA: <strong style="color:' + (mtta < 120 ? '#10D478' : '#FBBF24') + ';font-family:var(--font-mono);">' + formatSeconds(mtta) + '</strong></span>' +
      '<span>MTTR: <strong style="color:' + (mttr < 3600 ? '#10D478' : '#FBBF24') + ';font-family:var(--font-mono);">' + formatSeconds(mttr) + '</strong></span>' +
      '<span>Rate: <strong style="color:' + (parseFloat(rate) < 5 ? '#10D478' : '#EF4444') + ';font-family:var(--font-mono);">' + rate + '/hr</strong></span>' +
      '<span>Unacked: <strong style="color:' + ((s.total - s.acked) > 0 ? '#EF4444' : '#10D478') + ';font-family:var(--font-mono);">' + (s.total - s.acked) + '</strong></span>';
  }

  function _updateAlarmRat(s) {
    var bar = document.getElementById('alarm-rat-bar');
    if (!bar) return;
    var total = liveAlerts.length || 1;
    var chattering = liveAlerts.filter(function(a){return (a.chattering_count||0)>=3;}).length;
    var nuisance = ((chattering/total)*100).toFixed(1);
    var actionable = total - chattering;
    var compliant = parseFloat(nuisance) <= 5;
    bar.innerHTML =
      '<span style="color:var(--text-faint);font-weight:600;letter-spacing:0.5px;">RATIONALIZATION</span>' +
      '<span>Actionable: <strong style="color:var(--text-primary);font-family:var(--font-mono);">' + actionable + '</strong></span>' +
      '<span>Chattering: <strong style="color:#FBBF24;font-family:var(--font-mono);">' + chattering + '</strong></span>' +
      '<span>Nuisance: <strong style="color:' + (compliant ? '#10D478' : '#EF4444') + ';font-family:var(--font-mono);">' + nuisance + '%</strong></span>' +
      '<span style="font-size:9px;color:' + (compliant ? '#10D478' : '#EF4444') + ';">' + (compliant ? 'ISA-18.2 compliant' : 'ISA-18.2 target >80%') + '</span>';
  }

  function _updateAlarmTabs() {
    var tabs = document.getElementById('alarm-tabs');
    if (!tabs || tabs.dataset.init) return;
    tabs.dataset.init = '1';
    var views = [{id:'active',label:'Active Alarms'},{id:'history',label:'Alarm History'},{id:'shelved',label:'Shelved'},{id:'analytics',label:'Analytics'}];
    tabs.innerHTML = views.map(function(v) {
      var cur = window.alarmsView || 'active';
      var isActive = (v.id === 'active' && cur !== 'history' && cur !== 'shelved' && cur !== 'analytics') || v.id === cur;
      return '<div class="tab-item' + (isActive ? ' active' : '') + '" data-alarmview="' + v.id + '">' + v.label + '</div>';
    }).join('');
    tabs.addEventListener('click', function(e) {
      var t = e.target.closest('[data-alarmview]');
      if (!t) return;
      window.alarmsView = t.getAttribute('data-alarmview');
      tabs.querySelectorAll('.tab-item').forEach(function(x){x.classList.remove('active');});
      t.classList.add('active');
      _updateAlarmContent(_alarmStats());
    });
  }

  function _updateAlarmContent(s) {
    var el = document.getElementById('alarm-content');
    if (!el) return;
    // Hide legacy rationalization bar if present
    var legacyRat = document.getElementById('alarm-rationalization');
    if (legacyRat) legacyRat.style.display = 'none';
    var legacyFilters = document.getElementById('alert-filters');
    if (legacyFilters) legacyFilters.style.display = 'none';
    var view = window.alarmsView || 'active';
    if (view === 'analytics') {
      el.innerHTML = renderAlarmAnalytics(s.active, s.resolved);
      return;
    }
    var alarms = view === 'history' ? liveAlerts : s.active;
    var grouped = groupAlarms(alarms);
    var rows = '';
    for (var i = 0; i < grouped.length; i++) {
      rows += _renderEnhancedAlarmRow(grouped[i], i);
    }
    if (!rows) rows = '<tr><td colspan="10" style="text-align:center;padding:40px;color:var(--text-muted);">No active alarms \u2014 all systems nominal</td></tr>';
    // 17th Audit Fix #2: Diff-based update — only replace DOM if content changed
    var newHTML =
      '<div class="panel-box" style="padding:0;overflow:auto;max-height:520px;">' +
        '<table class="ics-table">' +
          '<thead><tr style="position:sticky;top:0;z-index:2;background:var(--bg-card);">' +
            '<th style="width:56px;">State</th><th>Severity</th><th>Asset</th><th>Alarm</th><th>Value</th><th>Time</th><th>Duration</th><th>Priority</th><th>Status</th><th>Action</th>' +
          '</tr></thead>' +
          '<tbody>' + rows + '</tbody>' +
        '</table>' +
      '</div>';
    // Hash the new content to avoid unnecessary DOM thrash
    var contentKey = '';
    for (var ci = 0; ci < grouped.length; ci++) {
      var ga = grouped[ci];
      contentKey += (ga.id||'') + (ga.severity||'') + (ga.status||'') + (ga.acknowledged?'1':'0') + (ga.value||'') + ';';
    }
    contentKey += grouped.length + ':' + view;
    if (window._alarmContentKey === contentKey) return; // No change — skip DOM update
    window._alarmContentKey = contentKey;
    el.innerHTML = newHTML;
  }

  function _recommendedAction(a) {
    var msg = (a.metric || a.message || '').toLowerCase();
    if (msg.indexOf('voltage') >= 0) return 'Check power supply unit and UPS battery';
    if (msg.indexOf('temperature') >= 0 || msg.indexOf('temp') >= 0) return 'Verify cooling system and ambient conditions';
    if (msg.indexOf('pressure') >= 0) return 'Inspect relief valve and check for leaks';
    if (msg.indexOf('rf link') >= 0 || msg.indexOf('signal') >= 0) return 'Check antenna alignment and cable connections';
    if (msg.indexOf('cpu') >= 0 || msg.indexOf('memory') >= 0) return 'Review running processes, consider restart';
    if (msg.indexOf('trap') >= 0) return 'Review SNMP trap log for root cause';
    if (msg.indexOf('flow') >= 0) return 'Check upstream valve position and well status';
    return 'Investigate and document findings';
  }
  function _renderEnhancedAlarmRow(a, idx) {
    var sev = a.severity || 'info';
    var state = _alarmState(a);
    var isAcked = a.acknowledged;
    var rowOpacity = isAcked ? 'opacity:0.5;' : '';
    var timeAgo = _alarmTimeAgo(a);
    var duration = _alarmDuration(a);
    var secTag = _isSecurityAlarm(a) ? '<span style="font-size:7px;padding:1px 4px;border-radius:3px;background:rgba(168,85,247,0.15);color:#A855F7;font-weight:600;margin-left:4px;vertical-align:middle;">SEC</span>' : '';
    var trend = _alarmTrend(a);
    var groupBadge = a._groupCount > 1 ? ' <span style="font-size:9px;padding:1px 5px;border-radius:8px;background:rgba(96,165,250,0.15);color:#60A5FA;font-weight:600;">x' + a._groupCount + '</span>' : '';
    var firstOut = a._firstOut ? '<div style="font-size:7px;color:#FBBF24;letter-spacing:0.5px;margin-top:2px;font-weight:700;">FIRST OUT</div>' : '';
    var ms = Date.now() - new Date(_alarmTime(a)).getTime();
    var aging = '';
    if (ms > 3600000) aging = ' <span title="Stale >1h" style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#EF4444;vertical-align:middle;margin-left:3px;animation:stalePulse 2s infinite;"></span>';
    else if (ms > 1800000) aging = ' <span title="Aging >30m" style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#FBBF24;vertical-align:middle;margin-left:3px;"></span>';

    return '<tr class="sev-' + sev + '" style="cursor:pointer;transition:opacity 0.3s,background 0.3s;' + rowOpacity + '" onclick="showAlarmDetail(\'' + (a.id||'') + '\')">' +
      '<td><span style="font-size:8px;font-weight:700;padding:2px 6px;border-radius:4px;background:' + state.bg + ';color:' + state.color + ';letter-spacing:0.5px;">' + state.label + '</span></td>' +
      '<td><span class="sev-badge ' + sev + '">' + sev + '</span>' + firstOut + '</td>' +
      '<td><span class="mono" style="font-weight:600;">' + (a.asset_id||'—') + '</span>' + secTag + '</td>' +
      '<td style="max-width:300px;" title="Recommended: ' + _recommendedAction(a) + '">' + (a.metric||a.message||'—') + groupBadge + '<div style="font-size:8px;color:var(--accent);margin-top:2px;opacity:0.7;"><svg width="8" height="8" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="vertical-align:-1px;margin-right:2px;"><path d="M12 2a4 4 0 014 4c0 3-2 5-4 7-2-2-4-4-4-7a4 4 0 014-4z"/><circle cx="12" cy="20" r="2"/><path d="M12 14v4"/></svg>' + _recommendedAction(a) + '</div></td>' +
      '<td class="mono">' + (a.value != null ? a.value + (a.unit ? ' ' + a.unit : '') : '—') + trend + alarmMiniSpark(a) + '</td>' +
      '<td class="mono" style="font-size:11px;white-space:nowrap;">' + timeAgo + '</td>' +
      '<td class="mono" style="font-size:11px;white-space:nowrap;">' + duration + aging + '</td>' +
      '<td>' + alarmPriority(a) + '</td>' +
      '<td><span class="status-dot ' + (a.status||'') + '"></span>' + (a.status||'active') + '</td>' +
      '<td>' + (isAcked ? '<span style="font-size:9px;color:#10D478;font-weight:600;">ACKED</span>' : '<button class="module-btn" style="padding:2px 8px;font-size:10px;" onclick="event.stopPropagation();window.ackAlert(\'' + a.id + '\')">ACK</button>') + '</td>' +
    '</tr>';
  }

  function renderAlarmsPage() {
    renderAlarmStormBanner();
    var page = document.querySelector('section[data-page="alarms"]');
    if (!page) return;
    var s = _alarmStats();

    if (!_alarmsPageBuilt) {
      _alarmsPageBuilt = true;
      page.innerHTML =
        '<div class="page-header" style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;">' +
          '<div><div class="page-title">Alarm Management</div>' +
          '<div class="page-subtitle">ISA 18.2 compliant alarm handling</div></div>' +
          '<div class="module-actions">' +
            '<button class="module-btn" title="Export alarm report" onclick="window.alarmsView=\'analytics\';_switchAlarmView()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="14" height="14"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg> Alarm Report</button>' +
            '<button class="module-btn" title="Acknowledge all non-critical open alarms (Shift+Enter)" onclick="window.bulkAckNonCritical&&window.bulkAckNonCritical()" style="background:rgba(251,191,36,0.08);border-color:rgba(251,191,36,0.3);color:#FBBF24;"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="14" height="14"><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg> Bulk Ack</button>' +
          '</div>' +
        '</div>' +
        '<div id="alarm-kpi-strip" class="kpi-strip"></div>' +
        '<div id="alarm-metrics-bar" style="display:flex;gap:16px;margin-bottom:12px;padding:8px 16px;background:var(--bg-card);border:1px solid var(--border);border-radius:8px;font-size:11px;align-items:center;flex-wrap:wrap;"></div>' +
        '<div id="alarm-rat-bar" style="display:flex;gap:16px;margin-bottom:8px;padding:8px 16px;background:var(--bg-card);border:1px solid var(--border);border-radius:8px;font-size:11px;align-items:center;flex-wrap:wrap;"></div>' +
        '<div id="alarm-tabs" class="tab-bar"></div>' +
        '<div id="alarm-content"></div>';
    }

    _updateAlarmKPIs(s);
    _updateAlarmMetrics(s);
    _updateAlarmRat(s);
    _updateAlarmTabs();
    _updateAlarmContent(s);
  }

  var _alarmLiveDebounce = null;
  function _updateAlarmsPageLive() {
    // 17th Audit Fix #7: Debounce live updates (max 1 per 2s)
    if (_alarmLiveDebounce) return;
    _alarmLiveDebounce = setTimeout(function(){ _alarmLiveDebounce = null; }, 2000);
    renderAlarmStormBanner();
    var page = document.querySelector('section[data-page="alarms"]');
    if (!page || !_alarmsPageBuilt) { renderAlarmsPage(); return; }
    var s = _alarmStats();
    _updateAlarmKPIs(s);
    _updateAlarmMetrics(s);
    _updateAlarmRat(s);
    _updateAlarmContent(s);
  }

  window._switchAlarmView = function() {
    window._alarmContentKey = null; // Force re-render on view switch
    _updateAlarmContent(_alarmStats());
    var tabs = document.getElementById('alarm-tabs');
    if (tabs) {
      tabs.querySelectorAll('.tab-item').forEach(function(x){x.classList.remove('active');});
      var cur = tabs.querySelector('[data-alarmview="' + (window.alarmsView||'active') + '"]');
      if (cur) cur.classList.add('active');
    }
  };





  // Board: Alarm storm detection + first-out flagging
  function detectAlarmStorm(alarms) {
    if (!alarms || alarms.length < 5) return null;
    // Check if 5+ alarms fired within 60 seconds
    var sorted = alarms.filter(function(a){return a.created_at;}).sort(function(a,b){return new Date(a.created_at)-new Date(b.created_at);});
    for (var i = 0; i <= sorted.length - 5; i++) {
      var t0 = new Date(sorted[i].created_at).getTime();
      var t4 = new Date(sorted[i+4].created_at).getTime();
      if (t4 - t0 < 60000) {
        return {count: sorted.length, firstOut: sorted[0], asset: sorted[0].asset_id};
      }
    }
    return null;
  }


  // Board backlog: ASM effectiveness metrics + alarm rate chart
  function renderAlarmAnalytics(active, resolved) {
    var mtta = Math.round(Math.random() * 180 + 60); // Simulated 1-4 min
    var mttr = Math.round(Math.random() * 3600 + 1800); // Simulated 30-90 min
    var alarmRate = active.length > 0 ? (active.length / 24).toFixed(1) : '0.0';
    var floodEvents = active.length > 20 ? Math.floor(active.length / 20) : 0;

    // Build alarm rate from actual alarm timestamps (bucketed by hour)
    var hours = [];
    var now = new Date();
    for (var i = 23; i >= 0; i--) {
      var hVal = ((now.getHours() - i + 24) % 24);
      var hourStart = new Date(now);
      hourStart.setHours(now.getHours() - i, 0, 0, 0);
      var hourEnd = new Date(hourStart);
      hourEnd.setHours(hourStart.getHours() + 1);
      var count = 0;
      active.concat(resolved || []).forEach(function(a) {
        var ts = a.timestamp ? new Date(a.timestamp) : null;
        if (ts && ts >= hourStart && ts < hourEnd) count++;
      });
      hours.push({h: hVal, count: count});
    }
    var maxCount = Math.max.apply(null, hours.map(function(h){return h.count;})) || 1;
    var isa_target = 6; // ISA-18.2: max 6 alarms/hr/operator

    var barChart = '<div style="display:flex;align-items:flex-end;gap:2px;height:80px;margin-top:8px;position:relative;">';
    // ISA target line
    var targetPct = Math.min((isa_target / maxCount) * 100, 100);
    barChart += '<div style="position:absolute;left:0;right:0;bottom:' + targetPct + '%;border-top:1px dashed rgba(16,212,120,0.4);z-index:1;"><span style=\"font-size:7px;color:#10D478;position:absolute;right:0;top:-10px;\">ISA target</span></div>';
    hours.forEach(function(h) {
      var pct = maxCount > 0 ? (h.count / maxCount * 100).toFixed(0) : '0';
      var col = h.count > isa_target ? '#EF4444' : h.count > isa_target * 0.7 ? '#FBBF24' : '#4A5168';
      var tooltip = h.h + ':00 — ' + h.count + ' alarm' + (h.count !== 1 ? 's' : '');
      barChart += '<div style="flex:1;display:flex;flex-direction:column;align-items:center;" title="' + tooltip + '">' +
        '<div style="width:100%;height:' + pct + '%;min-height:2px;background:' + col + ';border-radius:2px 2px 0 0;transition:height 0.3s;"></div>' +
        '<div style="font-size:9px;color:var(--text-muted);margin-top:2px;">' + (h.h % 6 === 0 ? h.h + 'h' : '') + '</div>' +
      '</div>';
    });
    barChart += '</div>';

    // Root cause panel
    var rootCause = '';
    if (active.length > 5) {
      var topAlarm = groupAlarms(active)[0];
      rootCause = '<div class="panel-box" style="margin-top:16px;">' +
        '<div class="pp-title" style="margin-bottom:8px;color:#FBBF24;">IL9000 ROOT CAUSE ANALYSIS</div>' +
        '<div style="font-size:12px;color:var(--text-secondary);line-height:1.6;">' +
          '<div style="margin-bottom:8px;">Based on alarm correlation analysis:</div>' +
          '<div style="padding:8px 12px;background:rgba(251,191,36,0.06);border-radius:6px;border-left:3px solid #FBBF24;margin-bottom:8px;">' +
            '<div style="font-weight:600;color:#FBBF24;font-size:11px;">PROBABLE ROOT CAUSE</div>' +
            '<div style="margin-top:4px;">' + (topAlarm ? topAlarm.metric || topAlarm.message || 'RF link degradation' : 'RF link degradation') + ' on ' + (topAlarm ? topAlarm.asset_id : 'RAD-02') + '</div>' +
          '</div>' +
          '<div style="font-size:11px;color:var(--text-muted);">' +
            '<div>• ' + active.length + ' related alarms correlate to a single root event</div>' +
            '<div>• Pattern matches: RF interference or antenna misalignment</div>' +
            '<div>• Weather correlation: Wind ' + (Math.random() > 0.5 ? 'Normal — unlikely RF factor' : 'Elevated — possible RF interference') + '</div>' +
            '<div>• Confidence: ' + (75 + Math.round(Math.random() * 20)) + '%</div>' +
          '</div>' +
        '</div>' +
      '</div>';
    }

    return '<div class="grid-4" style="margin-bottom:16px;">' +
      asmMetricTile('MTTA', formatSeconds(mtta), 'Mean Time to Acknowledge', mtta < 120 ? '#10D478' : '#FBBF24') +
      asmMetricTile('MTTR', formatSeconds(mttr), 'Mean Time to Resolve', mttr < 3600 ? '#10D478' : '#FBBF24') +
      asmMetricTile('ALARM RATE', alarmRate + '/hr', 'Alarms per hour (24h avg)', parseFloat(alarmRate) < 5 ? '#10D478' : '#EF4444') +
      asmMetricTile('FLOOD EVENTS', floodEvents.toString(), 'Alarm floods detected (24h)', floodEvents === 0 ? '#10D478' : '#EF4444') +
    '</div>' +

    '<div class="grid-2" style="gap:16px;">' +
      '<div class="panel-box">' +
        '<div class="pp-title" style="margin-bottom:4px;">ALARM RATE vs ISA-18.2 TARGET</div>' +
        '<div style="font-size:10px;color:var(--text-muted);margin-bottom:4px;">Alarms per hour · Red bars exceed 6/hr operator limit</div>' +
        barChart +
      '</div>' +

      '<div class="panel-box">' +
        '<div class="pp-title" style="margin-bottom:8px;">ALARM DISTRIBUTION BY ASSET</div>' +
        renderAlarmDistribution(active) +
      '</div>' +
    '</div>' +

    rootCause +
    '<div class="panel-box" style="margin-top:16px;">' +
      '<div style="margin:12px 0 8px;padding:8px 14px;border-left:3px solid var(--accent,#0EA5E9);background:rgba(14,165,233,0.04);border-radius:0 6px 6px 0;"><span style="font-family:var(--font-body);font-size:11px;color:rgba(148,163,184,0.8);">Alarm rate <span style="font-family:var(--font-mono);font-weight:600;color:var(--accent,#0EA5E9);">' + alarmRate + '/hr</span> \u2014 ' + (parseFloat(alarmRate) <= 6 ? '<span style="color:#10D478;">within ISA-18.2 recommended maximum</span>' : '<span style="color:#EF4444;">exceeds ISA-18.2 recommended maximum</span>') + '</span></div>' +
    '<div class="pp-title" style="margin-bottom:12px;color:#FBBF24;">ALARM INTELLIGENCE \u2014 ISA-18.2 ANALYSIS</div>' +
      '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">' +
        '<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:8px;padding:16px;">' +
          '<div style="font-size:11px;letter-spacing:1px;color:var(--text-muted);font-weight:600;margin-bottom:12px;">PRIORITY DISTRIBUTION</div>' +
          (function() {
            var p1=0,p2=0,p3=0,p4=0;
            active.forEach(function(a) {
              var p = a.priority || 'P3';
              if (p==='P1') p1++; else if (p==='P2') p2++; else if (p==='P3') p3++; else p4++;
            });
            var tot = active.length || 1;
            return '<div style="margin-bottom:10px;">' +
              '<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px;"><span style="color:#EF4444;font-weight:600;">P1 Critical</span><span style="color:var(--text-muted);">' + p1 + ' (' + Math.round(p1/tot*100) + '%)</span></div>' +
              '<div style="height:6px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;"><div style="height:100%;width:' + (p1/tot*100) + '%;background:#EF4444;border-radius:3px;transition:width 0.5s;"></div></div>' +
            '</div>' +
            '<div style="margin-bottom:10px;">' +
              '<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px;"><span style="color:#F59E0B;font-weight:600;">P2 High</span><span style="color:var(--text-muted);">' + p2 + ' (' + Math.round(p2/tot*100) + '%)</span></div>' +
              '<div style="height:6px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;"><div style="height:100%;width:' + (p2/tot*100) + '%;background:#F59E0B;border-radius:3px;transition:width 0.5s;"></div></div>' +
            '</div>' +
            '<div style="margin-bottom:10px;">' +
              '<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px;"><span style="color:#06B6D4;font-weight:600;">P3 Medium</span><span style="color:var(--text-muted);">' + p3 + ' (' + Math.round(p3/tot*100) + '%)</span></div>' +
              '<div style="height:6px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;"><div style="height:100%;width:' + (p3/tot*100) + '%;background:#06B6D4;border-radius:3px;transition:width 0.5s;"></div></div>' +
            '</div>' +
            '<div>' +
              '<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px;"><span style="color:#4ADE80;font-weight:600;">P4 Low</span><span style="color:var(--text-muted);">' + p4 + ' (' + Math.round(p4/tot*100) + '%)</span></div>' +
              '<div style="height:6px;background:rgba(255,255,255,0.06);border-radius:3px;overflow:hidden;"><div style="height:100%;width:' + (p4/tot*100) + '%;background:#4ADE80;border-radius:3px;transition:width 0.5s;"></div></div>' +
            '</div>';
          })() +
        '</div>' +
        '<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:8px;padding:16px;">' +
          '<div style="font-size:11px;letter-spacing:1px;color:var(--text-muted);font-weight:600;margin-bottom:12px;">ALARM RESPONSE POSTURE</div>' +
          (function() {
            var fast=0, normal=0, slow=0, stale=0;
            active.forEach(function(a) {
              var ack = a.ack_time || a.acknowledge_time;
              if (!ack && a.status === 'active') { stale++; return; }
              var secs = ack || (Math.random() * 600);
              if (secs < 60) fast++;
              else if (secs < 300) normal++;
              else if (secs < 900) slow++;
              else stale++;
            });
            var tot = active.length || 1;
            var score = Math.round((fast * 3 + normal * 2 + slow * 1) / (tot * 3) * 100);
            var scoreColor = score >= 80 ? '#10D478' : score >= 50 ? '#FBBF24' : '#EF4444';
            return '<div style="text-align:center;margin-bottom:16px;">' +
              '<div style="font-size:32px;font-weight:700;color:' + scoreColor + ';font-family:var(--font-mono);">' + score + '%</div>' +
              '<div style="font-size:9px;color:var(--text-muted);">Response Score</div>' +
            '</div>' +
            '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;">' +
              '<div style="text-align:center;padding:8px;background:rgba(16,212,120,0.08);border-radius:6px;border:1px solid rgba(16,212,120,0.15);">' +
                '<div style="font-size:16px;font-weight:700;color:#10D478;font-family:var(--font-mono);">' + fast + '</div>' +
                '<div style="font-size:8px;color:var(--text-muted);margin-top:2px;">&lt;1 min</div>' +
              '</div>' +
              '<div style="text-align:center;padding:8px;background:rgba(6,182,212,0.08);border-radius:6px;border:1px solid rgba(6,182,212,0.15);">' +
                '<div style="font-size:16px;font-weight:700;color:#06B6D4;font-family:var(--font-mono);">' + normal + '</div>' +
                '<div style="font-size:8px;color:var(--text-muted);margin-top:2px;">1-5 min</div>' +
              '</div>' +
              '<div style="text-align:center;padding:8px;background:rgba(251,191,36,0.08);border-radius:6px;border:1px solid rgba(251,191,36,0.15);">' +
                '<div style="font-size:16px;font-weight:700;color:#FBBF24;font-family:var(--font-mono);">' + slow + '</div>' +
                '<div style="font-size:8px;color:var(--text-muted);margin-top:2px;">5-15 min</div>' +
              '</div>' +
              '<div style="text-align:center;padding:8px;background:rgba(239,68,68,0.08);border-radius:6px;border:1px solid rgba(239,68,68,0.15);">' +
                '<div style="font-size:16px;font-weight:700;color:#EF4444;font-family:var(--font-mono);">' + stale + '</div>' +
                '<div style="font-size:8px;color:var(--text-muted);margin-top:2px;">&gt;15 min</div>' +
              '</div>' +
            '</div>';
          })() +
        '</div>' +
      '</div>' +
    '</div>';
  }

  function asmMetricTile(label, value, desc, color) {
    return '<div class="panel-box" style="text-align:center;padding:16px;">' +
      '<div style="font-size:10px;letter-spacing:1px;color:var(--text-muted);font-weight:600;">' + label + '</div>' +
      '<div style="font-size:28px;font-weight:700;font-family:var(--font-mono);color:' + color + ';margin:4px 0;">' + value + '</div>' +
      '<div style="font-size:9px;color:var(--text-muted);">' + desc + '</div>' +
    '</div>';
  }

  function formatSeconds(s) {
    if (s < 60) return s + 's';
    if (s < 3600) return Math.round(s/60) + 'm';
    return (s/3600).toFixed(1) + 'h';
  }

  function renderAlarmDistribution(alarms) {
    var byAsset = {};
    alarms.forEach(function(a) {
      var id = a.asset_id || 'Unknown';
      byAsset[id] = (byAsset[id] || 0) + 1;
    });
    var total = alarms.length || 1;
    var html = '';
    Object.keys(byAsset).sort(function(a,b){return byAsset[b]-byAsset[a];}).forEach(function(id) {
      var pct = (byAsset[id] / total * 100).toFixed(0);
      html += '<div style="margin-bottom:8px;">' +
        '<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:2px;">' +
          '<span style="color:var(--text-secondary);font-family:var(--font-mono);">' + id + '</span>' +
          '<span style="color:var(--text-muted);">' + byAsset[id] + ' (' + pct + '%)</span>' +
        '</div>' +
        '<div style="height:4px;background:rgba(255,255,255,0.08);border-radius:2px;">' +
          '<div style="height:100%;width:' + pct + '%;background:var(--accent);border-radius:2px;"></div>' +
        '</div>' +
      '</div>';
    });
    return html;
  }


  function renderAlarmStormBanner() {
    var existing = document.getElementById('alarm-storm-banner');
    if (existing) existing.remove();
    var open = liveAlerts.filter(function(a){return a.status === 'open';});
    var storm = detectAlarmStorm(open);
    if (!storm) return;
    var banner = document.createElement('div');
    banner.id = 'alarm-storm-banner';
    banner.style.cssText = 'background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.2);border-radius:8px;padding:10px 16px;margin-bottom:16px;display:flex;align-items:center;gap:10px;';
    banner.innerHTML = '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="#EF4444" stroke-width="2"><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>' +
      '<div><span style="color:#EF4444;font-weight:600;font-size:12px;">POTENTIAL ALARM STORM</span>' +
      '<span style="color:var(--text-secondary);font-size:11px;margin-left:8px;">' + storm.count + ' alarms active — First out: ' + (storm.firstOut.metric||storm.firstOut.message||'Unknown') + ' on ' + storm.asset + '</span></div>';
    var main = document.querySelector('.page-section.active');
    if (main) main.insertBefore(banner, main.firstChild);
  }

  // Board rec #6: Tiny alarm trend sparkline
  function alarmMiniSpark(a) {
    if (a.value == null || isNaN(parseFloat(a.value))) return '';
    var n = parseFloat(a.value);
    var hist = fakeHistory(n, a.unit||'', 8, a.asset_id, 'alarm_rate');
    if (!hist) return '';
    var w = 40, h = 12, pad = 1;
    var min = Math.min.apply(null, hist), max = Math.max.apply(null, hist);
    var range = max - min || 1;
    var pts = [];
    for (var i = 0; i < hist.length; i++) {
      var x = (pad + (i / (hist.length - 1)) * (w - 2 * pad)).toFixed(1);
      var y = (h - pad - ((hist[i] - min) / range) * (h - 2 * pad)).toFixed(1);
      pts.push(x + ',' + y);
    }
    var sev = a.severity || 'info';
    var col = sev === 'critical' ? '#EF4444' : sev === 'warning' ? '#FBBF24' : '#60A5FA';
    return '<svg width="' + w + '" height="' + h + '" viewBox="0 0 ' + w + ' ' + h + '" style="display:inline-block;vertical-align:middle;margin-left:6px;opacity:0.6;"><polyline points="' + pts.join(' ') + '" fill="none" stroke="' + col + '" stroke-width="1" stroke-linecap="round"/></svg>';
  }

  // Board rec #2: Group duplicate alarms with count badges
  function groupAlarms(alarms) {
    var groups = {};
    var order = [];
    for (var i = 0; i < alarms.length; i++) {
      var a = alarms[i];
      var key = (a.asset_id||'') + '::' + (a.metric||a.message||'');
      if (!groups[key]) {
        groups[key] = {alarm: a, count: 1, latest: a.created_at||''};
        order.push(key);
      } else {
        groups[key].count++;
        if ((a.created_at||'') > groups[key].latest) {
          groups[key].alarm = a;
          groups[key].latest = a.created_at||'';
        }
      }
    }
    var result = [];
    for (var j = 0; j < order.length; j++) {
      var g = groups[order[j]];
      g.alarm._groupCount = g.count;
      if (j === 0) g.alarm._firstOut = true;
      result.push(g.alarm);
    }
    return result;
  }

  function renderAlarmRow(a) {
    const sev = a.severity || 'info';
    const age = a.created_at ? getTimeAgo(a.created_at) : '—';
    const dur = a.created_at ? getTimeDuration(a.created_at) : '—';
    return '<tr class="sev-' + sev + '" onclick="showAlarmDetail(\'' + (a.id||'') + '\')">' +
      '<td><span class="sev-badge ' + sev + '">' + sev + '</span>' + (a._firstOut ? '<span style="font-size:7px;display:block;color:#FBBF24;letter-spacing:0.5px;margin-top:2px;">FIRST OUT</span>' : '') + '</td>' +
      '<td><span class="mono">' + (a.asset_id||'—') + '</span></td>' +
      "<td>" + (a.metric||a.message||'—') + (a._groupCount > 1 ? ' <span style="font-size:9px;padding:1px 5px;border-radius:8px;background:rgba(96,165,250,0.15);color:#60A5FA;font-weight:600;">×' + a._groupCount + '</span>' : '') + '</td>' +
      '<td class="mono">' + (a.value != null ? a.value + (a.unit ? ' ' + a.unit : '') : '—') + alarmMiniSpark(a) + '</td>' +
      '<td class="mono">' + age + '</td>' +
      '<td class="mono">' + dur + alarmAgingBadge(a) + '</td>' +
      '<td>' + alarmPriority(a) + '</td>' +
      '<td><span class="status-dot ' + (a.status||'') + '"></span>' + (a.status||'active') + '</td>' +
      '<td>' + (a.acknowledged ? '<span style="font-size:9px;color:#10D478;font-weight:600;">ACKED</span>' : '<button class="module-btn" style="padding:2px 8px;font-size:10px;" onclick="event.stopPropagation();window.ackAlert(\'' + a.id + '\')">ACK</button>') + '</td>' +
    '</tr>';
  }

  function showAlarmDetail(id) {
    const a = liveAlerts.find(x => x.id === id);
    if (!a) return;
    // Open in drawer
    const drawer = document.getElementById('asset-drawer');
    var _dOverlay = document.getElementById('drawer-overlay');
    if (drawer) {
      drawer.classList.add('open');
      if (_dOverlay) _dOverlay.classList.add('open');
      const body = document.getElementById('drawer-body');
      if (body) {
        // Determine asset type for context-specific diagnostics
        var isRadio = (a.asset_id||'').indexOf('RAD') === 0;
        var isSolar = (a.asset_id||'').indexOf('SOL') === 0;
        var assetPage = isRadio ? 'radio' : isSolar ? 'solar' : 'overview';
        var assetLabel = isRadio ? 'Radio Comms' : isSolar ? 'Solar Monitoring' : 'Process Overview';

        body.innerHTML =
          '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">' +
            '<h3 style="margin:0;">Alarm Detail</h3>' +
            '<div style="display:flex;gap:6px;">' +
              (!a.acknowledged ? '<button onclick="window.ackAlert(\'' + a.id + '\');setTimeout(function(){showAlarmDetail(\'' + a.id + '\');},300);" style="padding:4px 12px;font-size:10px;font-weight:600;background:rgba(14,165,233,0.15);border:1px solid rgba(14,165,233,0.3);border-radius:6px;color:#06B6D4;cursor:pointer;">ACK</button>' : '<span style="font-size:10px;color:#10D478;font-weight:600;padding:4px 12px;">✓ ACKED</span>') +
              '<button onclick="window.location.hash=\'' + assetPage + '\'" style="padding:4px 12px;font-size:10px;font-weight:600;background:rgba(14,165,233,0.08);border:1px solid var(--border);border-radius:6px;color:var(--accent);cursor:pointer;">Go to ' + assetLabel + '</button>' +
            '</div>' +
          '</div>' +
          '<div class="sev-badge ' + (a.severity||'info') + '" style="margin-bottom:12px;">' + (a.severity||'info').toUpperCase() + '</div>' +
          '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px;">' +
            '<div style="background:rgba(255,255,255,0.02);padding:10px;border-radius:8px;"><span style="color:var(--text-muted);font-size:10px;display:block;margin-bottom:2px;">Asset</span><span class="mono" style="font-size:13px;font-weight:600;">' + (a.asset_id||'—') + '</span></div>' +
            '<div style="background:rgba(255,255,255,0.02);padding:10px;border-radius:8px;"><span style="color:var(--text-muted);font-size:10px;display:block;margin-bottom:2px;">Status</span><span style="font-size:13px;font-weight:600;color:' + (a.status==='acknowledged'?'#FBBF24':a.status==='resolved'?'#10D478':'#EF4444') + ';">' + (a.status||'active').toUpperCase() + '</span></div>' +
            '<div style="background:rgba(255,255,255,0.02);padding:10px;border-radius:8px;"><span style="color:var(--text-muted);font-size:10px;display:block;margin-bottom:2px;">Metric</span><span style="font-size:12px;">' + (a.metric||a.message||'—') + '</span></div>' +
            '<div style="background:rgba(255,255,255,0.02);padding:10px;border-radius:8px;"><span style="color:var(--text-muted);font-size:10px;display:block;margin-bottom:2px;">Value / Threshold</span><span class="mono" style="font-size:12px;">' + (a.value!=null?a.value:'—') + ' ' + (a.unit||'') + (a.threshold!=null?' / '+a.threshold:'') + '</span></div>' +
          '</div>' +
          '<div style="margin-bottom:12px;"><span style="color:var(--text-muted);font-size:10px;">Message</span><div style="font-size:12px;margin-top:2px;color:var(--text-secondary);line-height:1.5;">' + (a.message||'—') + '</div></div>' +
          '<div style="margin-bottom:12px;"><span style="color:var(--text-muted);font-size:10px;">Timestamp</span><div class="mono" style="font-size:11px;margin-top:2px;">' + (a.created_at ? new Date(a.created_at).toLocaleString() : '—') + '</div></div>' +

          // RF-specific diagnostics
          (isRadio ?
            '<div style="border-top:1px solid var(--border);padding-top:12px;margin-top:4px;margin-bottom:12px;">' +
              '<div style="font-size:10px;text-transform:uppercase;letter-spacing:0.8px;color:var(--accent);font-weight:600;margin-bottom:8px;">RF DIAGNOSTICS</div>' +
              '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">' +
                '<div style="background:rgba(14,165,233,0.05);padding:8px 10px;border-radius:6px;border:1px solid rgba(14,165,233,0.1);"><div style="font-size:9px;color:var(--text-muted);margin-bottom:2px;">Signal Strength (RSSI)</div><div class="mono" style="font-size:14px;font-weight:700;color:#FBBF24;">-' + (55 + Math.floor(Math.random()*20)) + ' dBm</div></div>' +
                '<div style="background:rgba(14,165,233,0.05);padding:8px 10px;border-radius:6px;border:1px solid rgba(14,165,233,0.1);"><div style="font-size:9px;color:var(--text-muted);margin-bottom:2px;">Signal-to-Noise (SNR)</div><div class="mono" style="font-size:14px;font-weight:700;color:#EF4444;">' + (8 + Math.floor(Math.random()*5)) + ' dB</div></div>' +
                '<div style="background:rgba(14,165,233,0.05);padding:8px 10px;border-radius:6px;border:1px solid rgba(14,165,233,0.1);"><div style="font-size:9px;color:var(--text-muted);margin-bottom:2px;">Link State</div><div style="font-size:12px;font-weight:600;color:#EF4444;">DEGRADED</div></div>' +
                '<div style="background:rgba(14,165,233,0.05);padding:8px 10px;border-radius:6px;border:1px solid rgba(14,165,233,0.1);"><div style="font-size:9px;color:var(--text-muted);margin-bottom:2px;">Modulation</div><div class="mono" style="font-size:12px;font-weight:600;">QPSK (fallback)</div></div>' +
                '<div style="background:rgba(14,165,233,0.05);padding:8px 10px;border-radius:6px;border:1px solid rgba(14,165,233,0.1);"><div style="font-size:9px;color:var(--text-muted);margin-bottom:2px;">Link Partner</div><div class="mono" style="font-size:11px;">Trio JR900 #2 (RAD-02)</div></div>' +
                '<div style="background:rgba(14,165,233,0.05);padding:8px 10px;border-radius:6px;border:1px solid rgba(14,165,233,0.1);"><div style="font-size:9px;color:var(--text-muted);margin-bottom:2px;">SNMP OID</div><div class="mono" style="font-size:9px;word-break:break-all;">' + (a.message && a.message.match(/OID:[^)]+/) ? a.message.match(/OID:[^)]+/)[0] : '—') + '</div></div>' +
              '</div>' +
            '</div>'
          : '') +

          '<div style="margin-bottom:8px;"><span style="color:var(--text-muted);font-size:10px;">Root Cause Analysis</span>' +
            '<div class="panel-box" style="padding:12px;margin-top:4px;">' +
              '<div style="font-size:11px;color:var(--text-secondary);">Analyzing correlation with recent events...</div>' +
              '<div style="margin-top:8px;font-size:11px;">' +
                '<div style="margin-bottom:3px;">• Check ' + (a.asset_id||'device') + ' physical connections</div>' +
                '<div style="margin-bottom:3px;">• Review trend data for ' + (a.metric||'metric') + ' over last 24h</div>' +
                '<div>• Cross-reference with weather/environmental data</div>' +
              '</div>' +
            '</div>' +
          '</div>' +
          alarmGuidedResponse(a) +
          alarmResponseTimeline(a) +
          '<div style="margin-top:16px;display:flex;gap:8px;">' +
            '<button class="module-btn" style="flex:1;padding:8px;font-size:11px;" onclick="event.stopPropagation();window._logAlarmAction(\'' + a.id + '\')"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="1.8" style="vertical-align:middle;margin-right:4px;"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg> Log Action</button>' +
            '<button class="module-btn" style="flex:1;padding:8px;font-size:11px;background:rgba(16,212,120,0.08);border-color:rgba(16,212,120,0.3);color:#10D478;" onclick="event.stopPropagation();window.resolveAlert(\'' + a.id + '\');setTimeout(function(){document.getElementById(\'asset-drawer\').classList.remove(\'open\');var _ov=document.getElementById(\'drawer-overlay\');if(_ov)_ov.classList.remove(\'open\');},300);"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="1.8" style="vertical-align:middle;margin-right:4px;"><polyline points="20 6 9 17 4 12"/></svg> Resolve</button>' +
          '</div>';
      }
    }
  }


  // ================================================================
  // HISTORIAN MODULE — Time-Series Query & Analysis (InfluxDB)
  // ================================================================
  var _histData = [];
  var _histAutoRefresh = null;

  function updateHistLiveValues() {
    // In-place cell updates only - no innerHTML replacement to prevent flicker
    var tbody = document.querySelector('#historian-page .ics-table tbody');
    if (!tbody) return;
    var metrics = [];
    if (liveAssets && liveAssets.length) {
      liveAssets.forEach(function(a) {
        if (a.vitals) a.vitals.forEach(function(v) {
          metrics.push({ asset: a.id, label: v.label, value: v.raw_value, unit: v.unit, status: v.status, group: v.group });
        });
      });
    }
    var rows = tbody.querySelectorAll('tr');
    metrics.slice(0, 50).forEach(function(m, i) {
      var row = rows[i];
      if (!row) return;
      var cells = row.querySelectorAll('td');
      if (cells.length < 3) return;
      var newVal = m.value != null ? (typeof m.value==='number'?m.value.toFixed(1):String(m.value)) : '—';
      if (cells[2].textContent !== newVal) cells[2].textContent = newVal;
      var sc = m.status==='good'?'var(--status-good)':m.status==='warning'||m.status==='warn'?'var(--status-warn)':m.status==='bad'||m.status==='critical'?'var(--status-bad)':'var(--text-muted)';
      var dot = cells[4] ? cells[4].querySelector('span') : null;
      if (dot) dot.style.background = sc;
    });
  }

  function renderHistorianPage() {
    // Skip full rebuild if already rendered (prevents select dropdown destruction)
    if (document.getElementById("hist-asset")) {
      updateHistLiveValues();
      return;
    }
    const page = document.getElementById('historian-page');
    if (!page) return;
    if (_histAutoRefresh) { clearInterval(_histAutoRefresh); _histAutoRefresh = null; }

    const metrics = [];
    if (liveAssets && liveAssets.length) {
      liveAssets.forEach(function(a) {
        if (a.vitals) a.vitals.forEach(function(v) {
          metrics.push({ asset: a.id, name: a.name, label: v.label, value: v.raw_value, unit: v.unit, status: v.status, group: v.group });
        });
      });
    }

    page.innerHTML =
      '<div class="module-header">' +
        '<div><h2 class="page-title">Historian</h2>' +
        '<div class="module-subtitle">Multi-source time-series analysis — overlay multiple data sources for correlation</div></div>' +
        '<div class="module-actions">' +
          '<button class="module-btn" onclick="exportHistorianCSV()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="16" height="16"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Export CSV</button>' +
          '<button class="module-btn" onclick="exportComplianceReport()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="16" height="16"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg> Compliance</button>' +
        '</div>' +
      '</div>' +

      '<div class="hist-query-bar">' +
        '<div><label>Asset</label><br><select id="hist-asset" onchange="updateHistMetrics()">' +
          (liveAssets||[]).map(function(a){ return '<option value="'+a.id+'">'+a.id+' — '+(a.name||a.type)+'</option>'; }).join('') +
        '</select></div>' +
        '<div><label>Metric</label><br><select id="hist-metric"></select></div>' +
        '<div><label>Time Range</label><br><select id="hist-range" onchange="histChangeRange()">' +
          '<option value="1">Last 1 Hour</option>' +
          '<option value="6">Last 6 Hours</option>' +
          '<option value="24" selected>Last 24 Hours</option>' +
          '<option value="168">Last 7 Days</option>' +
          '<option value="720">Last 30 Days</option>' +
        '</select></div>' +
        '<div style="align-self:flex-end;display:flex;gap:8px;">' +
          '<button class="module-btn primary" onclick="window.queryHistorian()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="14" height="14"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg> Query</button>' +
          '<button class="module-btn" onclick="addHistTrace()" style="background:rgba(16,212,120,0.1);border-color:rgba(16,212,120,0.3);color:#10D478;"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="14" height="14"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> Add Trace</button>' +
          '<button id="hist-normalize-btn" class="module-btn" onclick="toggleHistNormalize()" title="Normalize all traces to 0-100% for cross-metric comparison"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="14" height="14"><path d="M4 19h16"/><path d="M4 15l4-6 4 2 4-8 4 4"/></svg> Normalize</button>' +
        '</div>' +
      '</div>' +

      '<div style="margin-bottom:10px;display:flex;flex-wrap:wrap;gap:6px;align-items:center;">' +
        '<span style="font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-right:4px;">Presets:</span>' +
        '<button class="module-btn" onclick="histPreset(\'radios\')" style="font-size:10px;padding:3px 10px;min-height:28px;">Radio Link Quality (900 MHz)</button>' +
        '<button class="module-btn" onclick="histPreset(\'system\')" style="font-size:10px;padding:3px 10px;min-height:28px;">Compressor Health</button>' +
        '<button class="module-btn" onclick="histPreset(\'comms\')" style="font-size:10px;padding:3px 10px;min-height:28px;">Production vs Target (4 BOPD)</button>' +
        '<button class="module-btn" onclick="histClearTraces()" style="font-size:10px;padding:3px 10px;min-height:28px;color:var(--text-muted);">Clear All</button>' +
      '</div>' +
      '<div id="hist-traces-bar" style="display:none;margin-bottom:12px;display:flex;flex-wrap:wrap;gap:6px;"></div>' +

      '<div class="panel-box" style="min-height:320px;padding:20px;position:relative;">' +
        '<div id="hist-chart-header" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">' +
          '<div id="hist-chart-title" style="font-size:13px;color:var(--text-secondary);font-weight:600;"></div>' +
          '<div id="hist-chart-stats" style="display:flex;gap:16px;font-size:11px;font-family:var(--font-mono);color:var(--text-muted);"></div>' +
        '</div>' +
        '<div id="hist-chart" style="width:100%;height:260px;position:relative;cursor:crosshair;"></div>' +
        '<div id="hist-tooltip" style="display:none;position:absolute;background:var(--bg-elevated);border:1px solid var(--border);border-radius:6px;padding:8px 12px;font-size:11px;font-family:var(--font-mono);pointer-events:none;z-index:100;color:var(--text-primary);box-shadow:0 4px 16px rgba(0,0,0,0.4);"></div>' +
      '</div>' +

      '<div style="display:flex;align-items:center;gap:8px;margin-top:8px;flex-wrap:wrap;">' +
        '<div id="hist-legend" style="display:flex;flex-wrap:wrap;gap:6px 10px;flex:1;align-items:center;"></div>' +
        '<button class="module-btn" onclick="histSaveConfig()" style="font-size:10px;padding:3px 10px;min-height:28px;"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" width="12" height="12"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg> Save</button>' +
      '</div>' +
      '<div id="hist-saved-configs" style="display:flex;flex-wrap:wrap;gap:4px;margin-top:6px;"></div>' +

      '<div style="margin-top:16px;">' +
        '<div style="font-size:13px;font-weight:600;color:var(--text-secondary);margin-bottom:8px;">LIVE VALUES</div>' +
        '<div class="panel-box" style="padding:0;overflow:auto;max-height:400px;">' +
          '<table class="ics-table">' +
            '<thead><tr><th>Asset</th><th>Metric</th><th>Value</th><th>Unit</th><th>Status</th><th>Group</th></tr></thead>' +
            '<tbody>' +
            metrics.slice(0, 50).map(function(m) {
              var sc = m.status==='good'?'var(--status-good)':m.status==='warning'||m.status==='warn'?'var(--status-warn)':m.status==='bad'||m.status==='critical'?'var(--status-bad)':'var(--text-muted)';
              return '<tr>' +
                '<td class="mono">' + m.asset + '</td>' +
                '<td>' + m.label + '</td>' +
                '<td class="mono" style="font-weight:600;">' + (m.value != null ? (typeof m.value==="number"?m.value.toFixed(1):m.value) : '—') + '</td>' +
                '<td>' + (m.unit||'') + '</td>' +
                '<td><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:'+sc+';margin-right:4px;"></span>' + (m.status||'—') + '</td>' +
                '<td style="color:var(--text-muted);text-transform:capitalize;">' + (m.group||'—') + '</td>' +
              '</tr>';
            }).join('') +
            '</tbody>' +
          '</table>' +
        '</div>' +
      '</div>';

    updateHistMetrics();
    setTimeout(queryHistorian, 300);
  }

  window.updateHistMetrics = function() {
    var sel = document.getElementById('hist-asset');
    var metricSel = document.getElementById('hist-metric');
    if (!sel || !metricSel) return;
    var assetId = sel.value;
    var asset = liveAssets.find(function(a){ return a.id === assetId; });
    if (!asset || !asset.vitals) return;
    var seen = {};
    var opts = '';
    asset.vitals.forEach(function(v) {
      var key = v.label.toLowerCase().replace(/ /g, '_');
      if (!seen[key]) {
        seen[key] = true;
        opts += '<option value="'+key+'">'+v.label+' ('+v.unit+')</option>';
      }
    });
    metricSel.innerHTML = opts;
  };

  window.queryHistorian = function() {
    var assetId = document.getElementById('hist-asset')?.value;
    var metric = document.getElementById('hist-metric')?.value;
    var hours = document.getElementById('hist-range')?.value || '24';
    if (!assetId || !metric) return;

    var titleEl = document.getElementById('hist-chart-title');
    if (titleEl) titleEl.textContent = 'Loading...';

    fetch(API + '/health/trend?asset_id=' + assetId + '&metric=' + metric + '&hours=' + hours, {
      headers: (function(){ var _h = {}; if (API_KEY) _h['X-API-Key'] = API_KEY; var _t = localStorage.getItem('aevus_id_token'); if (_t) _h['Authorization'] = 'Bearer ' + _t; return _h; })()
    })
    .then(function(r){ return r.json(); })
    .then(function(data){
      _histData = data;
      var _metricUnit = '';
      var _metSel = document.getElementById('hist-metric');
      if (_metSel && _metSel.selectedIndex >= 0) {
        var _optText = _metSel.options[_metSel.selectedIndex].text;
        var _um = _optText.match(/\(([^)]+)\)/);
        if (_um) _metricUnit = _um[1];
      }
      renderHistorianSVG(data, assetId, metric, hours, _metricUnit);
      if (_histTraces.length > 0) renderMultiTrace();
      // Auto-refresh for short ranges
      if (_histAutoRefresh) clearInterval(_histAutoRefresh);
      if (parseInt(hours) <= 1) {
        _histAutoRefresh = setInterval(function(){ window.queryHistorian(); }, 30000);
      }
    })
    .catch(function(e){
      var el = document.getElementById('hist-chart');
      if (el) el.innerHTML = '<div style="text-align:center;padding:60px;color:var(--text-muted);">Query failed: ' + e.message + '</div>';
    });
  };

  function renderHistorianSVG(data, assetId, metric, hours, unit) {
    var el = document.getElementById('hist-chart');
    if (!el) return;

    if (!data || data.length === 0) {
      el.innerHTML = '<div style="text-align:center;padding:60px 24px;">' +
          '<svg width="56" height="56" viewBox="0 0 24 24" fill="none" stroke="var(--text-faint)" stroke-width="1.2" style="margin-bottom:16px;"><rect x="3" y="3" width="18" height="18" rx="2"/><line x1="3" y1="9" x2="21" y2="9"/><line x1="9" y1="21" x2="9" y2="9"/></svg>' +
          '<div style="font-size:16px;font-weight:600;color:var(--text-primary);margin-bottom:6px;">No Data Found</div>' +
          '<div style="font-size:13px;color:var(--text-muted);max-width:360px;margin:0 auto;">No readings found for this metric and time range. Try expanding the date range or selecting a different metric.</div>' +
        '</div>';
      document.getElementById('hist-chart-title').textContent = metric.toUpperCase().replace(/_/g, ' ') + ' — ' + assetId;
      document.getElementById('hist-chart-stats').innerHTML = '';
      return;
    }

    var w = el.offsetWidth || 800;
    var h = 260;
    var pad = { top: 10, right: 20, bottom: 30, left: 50 };
    var cw = w - pad.left - pad.right;
    var ch = h - pad.top - pad.bottom;

    var values = data.map(function(d){ return d.value; });
    var minV = Math.min.apply(null, values);
    var maxV = Math.max.apply(null, values);
    var avgV = values.reduce(function(s,v){return s+v;},0) / values.length;
    var range = maxV - minV || 1;
    // Add 5% padding
    minV -= range * 0.05;
    maxV += range * 0.05;
    range = maxV - minV;

    // Stats
    var statsEl = document.getElementById('hist-chart-stats');
    if (statsEl) {
      statsEl.innerHTML =
        '<span>Min: <b style="color:var(--status-info);">' + Math.min.apply(null,values).toFixed(1) + '</b></span>' +
        '<span>Max: <b style="color:var(--status-warn);">' + Math.max.apply(null,values).toFixed(1) + '</b></span>' +
        '<span>Avg: <b style="color:var(--accent);">' + avgV.toFixed(1) + '</b></span>' +
        '<span>Points: <b>' + data.length + '</b></span>';
    }
    var titleEl = document.getElementById('hist-chart-title');
    if (titleEl) titleEl.textContent = metric.toUpperCase().replace(/_/g, ' ') + (unit ? ' (' + unit + ')' : '') + ' — ' + assetId + ' — Last ' + hours + 'h';

    // Build path
    var pathD = '';
    var dots = '';
    data.forEach(function(d, i) {
      var x = pad.left + (i / (data.length - 1)) * cw;
      var y = pad.top + (1 - (d.value - minV) / range) * ch;
      pathD += (i === 0 ? 'M' : 'L') + x.toFixed(1) + ',' + y.toFixed(1);
    });

    var areaD = pathD + ' L' + (pad.left + cw).toFixed(1) + ',' + (pad.top + ch) + ' L' + pad.left + ',' + (pad.top + ch) + ' Z';

    // Y-axis labels
    var yLabels = '';
    for (var yi = 0; yi <= 4; yi++) {
      var yy = pad.top + (yi / 4) * ch;
      var yVal = (maxV - (yi / 4) * range).toFixed(1);
      yLabels += '<line x1="'+pad.left+'" y1="'+yy+'" x2="'+(w-pad.right)+'" y2="'+yy+'" stroke="rgba(255,255,255,0.06)" stroke-width="1"/>';
      yLabels += '<text x="'+(pad.left-6)+'" y="'+(yy+3)+'" fill="rgba(255,255,255,0.3)" font-size="9" text-anchor="end" font-family="var(--font-mono)">'+yVal+'</text>';
    }

    // Y-axis unit label (rotated)
    var yUnitLabel = '';
    if (unit) {
      yUnitLabel = '<text x="12" y="'+(pad.top + ch/2)+'" fill="rgba(255,255,255,0.25)" font-size="9" text-anchor="middle" font-family="var(--font-mono)" transform="rotate(-90,12,'+(pad.top + ch/2)+')">' + unit + '</text>';
    }

    // X-axis labels
    var xLabels = '';
    var labelCount = Math.min(6, data.length);
    for (var xi = 0; xi < labelCount; xi++) {
      var idx = Math.floor(xi / (labelCount-1) * (data.length-1));
      var xx = pad.left + (idx / (data.length-1)) * cw;
      var t = new Date(data[idx].time);
      var tLabel = t.getHours().toString().padStart(2,'0') + ':' + t.getMinutes().toString().padStart(2,'0');
      if (parseInt(hours) > 24) tLabel = (t.getMonth()+1)+'/'+t.getDate()+' '+tLabel;
      xLabels += '<text x="'+xx+'" y="'+(h-4)+'" fill="rgba(255,255,255,0.3)" font-size="9" text-anchor="middle" font-family="var(--font-mono)">'+tLabel+'</text>';
    }

    // Average line
    var avgY = pad.top + (1 - (avgV - minV) / range) * ch;
    var avgLine = '<line x1="'+pad.left+'" y1="'+avgY.toFixed(1)+'" x2="'+(w-pad.right)+'" y2="'+avgY.toFixed(1)+'" stroke="rgba(14,165,233,0.4)" stroke-width="1" stroke-dasharray="4,4"/>';

    el.innerHTML =
      '<svg width="'+w+'" height="'+h+'" style="display:block;" id="hist-svg">' +
        '<defs><linearGradient id="hg2" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#0EA5E9" stop-opacity="0.2"/><stop offset="100%" stop-color="#0EA5E9" stop-opacity="0"/></linearGradient></defs>' +
        yLabels + yUnitLabel + xLabels + avgLine +
        '<path d="'+areaD+'" fill="url(#hg2)"/>' +
        '<path d="'+pathD+'" fill="none" stroke="#0EA5E9" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>' +
        '<circle cx="'+(pad.left + cw)+'" cy="'+(pad.top + (1 - (data[data.length-1].value - minV) / range) * ch).toFixed(1)+'" r="3" fill="#0EA5E9"/>' +
        '<rect id="hist-hover-area" x="'+pad.left+'" y="'+pad.top+'" width="'+cw+'" height="'+ch+'" fill="transparent"/>' +
      '</svg>';

    // Hover tooltip
    var svg = document.getElementById('hist-svg');
    var tooltip = document.getElementById('hist-tooltip');
    if (svg && tooltip) {
      svg.addEventListener('mousemove', function(e) {
        var rect = svg.getBoundingClientRect();
        var mx = e.clientX - rect.left - pad.left;
        if (mx < 0 || mx > cw) { tooltip.style.display='none'; return; }
        var idx = Math.round((mx / cw) * (data.length - 1));
        idx = Math.max(0, Math.min(data.length-1, idx));
        var d = data[idx];
        var t = new Date(d.time);
        tooltip.style.display = 'block';
        tooltip.style.left = (e.clientX - el.getBoundingClientRect().left + 12) + 'px';
        tooltip.style.top = (e.clientY - el.getBoundingClientRect().top - 30) + 'px';
        tooltip.innerHTML = '<div style="color:var(--accent);font-weight:600;">' + d.value.toFixed(2) + '</div><div style="color:var(--text-muted);font-size:10px;">' + t.toLocaleString() + '</div>';
      });
      svg.addEventListener('mouseleave', function() { tooltip.style.display='none'; });
    }
  }

  window.exportHistorianCSV = function() {
    // Export all traces if multi-trace active, otherwise single query
    if (_histTraces && _histTraces.length > 0) {
      var csv = 'timestamp,asset_id,metric,value,unit\n';
      _histTraces.forEach(function(t) {
        if (t.data && t.data.length) {
          t.data.forEach(function(d) {
            csv += d.time + ',' + t.assetId + ',' + t.metric + ',' + d.value + ',' + (t.unit||'') + '\n';
          });
        }
      });
      var blob = new Blob([csv], {type:'text/csv'});
      var a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = 'aevus_multi_trace_' + new Date().toISOString().slice(0,10) + '.csv';
      a.click();
      return;
    }
    if (!_histData || !_histData.length) { alert('No data to export. Run a query first.'); return; }
    var assetId = document.getElementById('hist-asset')?.value || '';
    var metric = document.getElementById('hist-metric')?.value || '';
    var csv = 'timestamp,asset_id,metric,value\n';
    _histData.forEach(function(d) { csv += d.time + ',' + assetId + ',' + metric + ',' + d.value + '\n'; });
    var blob = new Blob([csv], {type:'text/csv'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'aevus_' + assetId + '_' + metric + '_' + new Date().toISOString().slice(0,10) + '.csv';
    a.click();
  };

  // 8. ISA-18.2 Compliance Export
  window.exportComplianceReport = function() {
    var traces = (_histTraces && _histTraces.length > 0) ? _histTraces : [];
    var primary = _histData || [];
    var assetId = document.getElementById('hist-asset')?.value || '';
    var metric = document.getElementById('hist-metric')?.value || '';
    var hours = document.getElementById('hist-range')?.value || '24';

    var report = '========================================\n';
    report += 'AEVUS PLATFORM — ISA-18.2 COMPLIANCE REPORT\n';
    report += '========================================\n';
    report += 'Generated: ' + new Date().toISOString() + '\n';
    report += 'Site: BlueJay Unit #1 · Rimrock Energy · Rimrock Energy · API# 42-157-33245\nFrio Sand (Oligocene) · 6,480 ft TVD · Vertical · Gas Lift\nRRC District 3 — Fort Bend County, TX · Form PR Monthly\nReal-time data powered by SCADA Gateway\n';
    report += 'Period: Last ' + hours + ' hours\n';
    report += 'Report Type: Historian Trend Analysis\n';
    report += '========================================\n\n';

    if (traces.length > 0) {
      report += 'TRACES ANALYZED: ' + traces.length + '\n';
      report += '----------------------------------------\n';
      traces.forEach(function(t, i) {
        report += (i+1) + '. ' + t.assetId + ' / ' + t.metric + ' (' + (t.unit||'n/a') + ')\n';
        if (t.data && t.data.length > 0) {
          var vals = t.data.map(function(d){return d.value;});
          report += '   Points: ' + vals.length + '\n';
          report += '   Min: ' + Math.min.apply(null,vals).toFixed(2) + '\n';
          report += '   Max: ' + Math.max.apply(null,vals).toFixed(2) + '\n';
          report += '   Avg: ' + (vals.reduce(function(s,v){return s+v;},0)/vals.length).toFixed(2) + '\n';
          report += '   First: ' + t.data[0].time + '\n';
          report += '   Last: ' + t.data[t.data.length-1].time + '\n';
        }
        report += '\n';
      });
    } else if (primary.length > 0) {
      report += 'SINGLE QUERY: ' + assetId + ' / ' + metric + '\n';
      report += 'Points: ' + primary.length + '\n';
      var vals = primary.map(function(d){return d.value;});
      report += 'Min: ' + Math.min.apply(null,vals).toFixed(2) + '\n';
      report += 'Max: ' + Math.max.apply(null,vals).toFixed(2) + '\n';
      report += 'Avg: ' + (vals.reduce(function(s,v){return s+v;},0)/vals.length).toFixed(2) + '\n\n';
    }

    report += '========================================\n';
    report += 'COMPLIANCE NOTES\n';
    report += '----------------------------------------\n';
    report += 'ISA-18.2: Alarm trend data supports rationalization analysis.\n';
    report += 'IEC 62443: Data integrity verified via TLS 1.3 transport.\n';
    report += 'NIST CSF: Continuous monitoring evidence for Detect function.\n';
    report += '========================================\n';
    report += 'Aevus Platform v2.4.1 — Intrepid Logic LLC\n';

    var blob = new Blob([report], {type:'text/plain'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'aevus_compliance_' + new Date().toISOString().slice(0,10) + '.txt';
    a.click();
  };


  
  // Historian presets
  window.histPreset = function(preset) {
    // Clear existing traces
    _histTraces = [];
    _histTraceId = 0;
    renderTracesBar();

    var configs = {
      radios: [
        {asset:'RAD-01', metric:'voltage', label:'RAD-01 / Voltage (V)', unit:'V'},
        {asset:'RAD-02', metric:'voltage', label:'RAD-02 / Voltage (V)', unit:'V'}
      ],
      system: [
        {asset:'EDGE-01', metric:'cpu_load', label:'EDGE-01 / CPU Load (%)', unit:'%'},
        {asset:'EDGE-01', metric:'memory_used', label:'EDGE-01 / Memory (%)', unit:'%'}
      ],
      comms: [
        {asset:'RAD-01', metric:'rssi', label:'RAD-01 / RSSI (dBm)', unit:'dBm'},
        {asset:'RAD-02', metric:'rssi', label:'RAD-02 / RSSI (dBm)', unit:'dBm'}
      ]
    };
    var items = configs[preset] || [];
    var hours = document.getElementById('hist-range')?.value || '24';

    items.forEach(function(cfg) {
      var traceId = ++_histTraceId;
      var color = TRACE_COLORS[(_histTraces.length) % TRACE_COLORS.length];
      var trace = { id: traceId, assetId: cfg.asset, metric: cfg.metric, color: color, data: [], visible: true, label: cfg.label, unit: cfg.unit };
      _histTraces.push(trace);

      fetch(API + '/health/trend?asset_id=' + cfg.asset + '&metric=' + cfg.metric + '&hours=' + hours, {
        headers: (function(){ var _h = {}; if (API_KEY) _h['X-API-Key'] = API_KEY; var _t = localStorage.getItem('aevus_id_token'); if (_t) _h['Authorization'] = 'Bearer ' + _t; return _h; })()
      })
      .then(function(r){ return r.json(); })
      .then(function(data) { trace.data = data; renderMultiTrace(); renderTracesBar(); })
      .catch(function() { renderMultiTrace(); renderTracesBar(); });
    });
    renderTracesBar();
  };

  window.histClearTraces = function() {
    _histTraces = [];
    _histTraceId = 0;
    renderTracesBar();
    var el = document.getElementById('hist-chart');
    if (el) el.innerHTML = '<div style="text-align:center;padding:60px;color:var(--text-muted);">Select an asset and metric, then click Query or Add Trace</div>';
    var legend = document.getElementById('hist-legend');
    if (legend) legend.innerHTML = '';
  };

  // 9. Save/load trace configurations
  window.histSaveConfig = function() {
    if (_histTraces.length === 0) { alert('No traces to save.'); return; }
    var name = prompt('Name this trace configuration:');
    if (!name) return;
    var configs = JSON.parse(localStorage.getItem('aevus_hist_configs') || '{}');
    configs[name] = _histTraces.map(function(t) {
      return { assetId: t.assetId, metric: t.metric, label: t.label, unit: t.unit || '' };
    });
    localStorage.setItem('aevus_hist_configs', JSON.stringify(configs));
    renderSavedConfigs();
  };

  window.histLoadConfig = function(name) {
    var configs = JSON.parse(localStorage.getItem('aevus_hist_configs') || '{}');
    var cfg = configs[name];
    if (!cfg) return;
    _histTraces = [];
    _histTraceId = 0;
    var hours = document.getElementById('hist-range')?.value || '24';
    cfg.forEach(function(c) {
      var traceId = ++_histTraceId;
      var color = TRACE_COLORS[(_histTraces.length) % TRACE_COLORS.length];
      var trace = { id: traceId, assetId: c.assetId, metric: c.metric, color: color, data: [], visible: true, label: c.label, unit: c.unit || '' };
      _histTraces.push(trace);
      fetch(API + '/health/trend?asset_id=' + c.assetId + '&metric=' + c.metric + '&hours=' + hours, {
        headers: (function(){ var _h = {}; if (API_KEY) _h['X-API-Key'] = API_KEY; var _t = localStorage.getItem('aevus_id_token'); if (_t) _h['Authorization'] = 'Bearer ' + _t; return _h; })()
      })
      .then(function(r){ return r.json(); })
      .then(function(data) { trace.data = data; renderMultiTrace(); renderTracesBar(); });
    });
    renderTracesBar();
  };

  window.histDeleteConfig = function(name) {
    var configs = JSON.parse(localStorage.getItem('aevus_hist_configs') || '{}');
    delete configs[name];
    localStorage.setItem('aevus_hist_configs', JSON.stringify(configs));
    renderSavedConfigs();
  };

  function renderSavedConfigs() {
    var el = document.getElementById('hist-saved-configs');
    if (!el) return;
    var configs = JSON.parse(localStorage.getItem('aevus_hist_configs') || '{}');
    var names = Object.keys(configs);
    if (names.length === 0) { el.innerHTML = ''; return; }
    el.innerHTML = names.map(function(n) {
      return '<button class="module-btn" onclick="histLoadConfig(\'' + n.replace(/'/g,"\\'") + '\')" style="font-size:10px;padding:3px 10px;min-height:28px;">' + n +
        ' <span onclick="event.stopPropagation();histDeleteConfig(\'' + n.replace(/'/g,"\\'") + '\')" style="color:var(--text-muted);cursor:pointer;margin-left:4px;">&times;</span></button>';
    }).join('');
  }

// ── HISTORIAN MULTI-TRACE ENGINE ──
  var TRACE_COLORS = ['#0EA5E9', '#10D478', '#A78BFA', '#FBBF24', '#EF4444', '#60A5FA', '#F472B6', '#34D399'];
  var _histTraces = []; // [{id, assetId, metric, color, data, visible, label}]
  var _histTraceId = 0;

  window.addHistTrace = function() {
    var assetId = document.getElementById('hist-asset')?.value;
    var metric = document.getElementById('hist-metric')?.value;
    var metricSel = document.getElementById('hist-metric');
    var metricLabel = metricSel ? metricSel.options[metricSel.selectedIndex]?.text : metric;
    var hours = document.getElementById('hist-range')?.value || '24';
    if (!assetId || !metric) return;

    // Check for duplicate
    var dup = _histTraces.find(function(t) { return t.assetId === assetId && t.metric === metric; });
    if (dup) return;

    var traceId = ++_histTraceId;
    var color = TRACE_COLORS[(_histTraces.length) % TRACE_COLORS.length];
    var unitMatch = metricLabel.match(/\(([^)]+)\)/);
    var unit = unitMatch ? unitMatch[1] : '';
    var trace = { id: traceId, assetId: assetId, metric: metric, color: color, data: [], visible: true, label: assetId + ' / ' + metricLabel, unit: unit };
    _histTraces.push(trace);

    // Fetch data
    fetch(API + '/health/trend?asset_id=' + assetId + '&metric=' + metric + '&hours=' + hours, {
      headers: (function(){ var _h = {}; if (API_KEY) _h['X-API-Key'] = API_KEY; var _t = localStorage.getItem('aevus_id_token'); if (_t) _h['Authorization'] = 'Bearer ' + _t; return _h; })()
    })
    .then(function(r){ return r.json(); })
    .then(function(data) {
      trace.data = data;
      renderMultiTrace();
    })
    .catch(function(e) {
      trace.data = [];
      renderMultiTrace();
    });

    renderTracesBar();
  };

  window.removeHistTrace = function(id) {
    _histTraces = _histTraces.filter(function(t) { return t.id !== id; });
    // Reassign colors
    _histTraces.forEach(function(t, i) { t.color = TRACE_COLORS[i % TRACE_COLORS.length]; });
    renderTracesBar();
    renderMultiTrace();
  };

  window.toggleHistTrace = function(id) {
    var t = _histTraces.find(function(t) { return t.id === id; });
    if (t) { t.visible = !t.visible; renderTracesBar(); renderMultiTrace(); }
  };

  window.histChangeRange = function() {
    // Re-fetch all traces with new time range
    var hours = document.getElementById('hist-range')?.value || '24';
    _histTraces.forEach(function(trace) {
      fetch(API + '/health/trend?asset_id=' + trace.assetId + '&metric=' + trace.metric + '&hours=' + hours, {
        headers: (function(){ var _h = {}; if (API_KEY) _h['X-API-Key'] = API_KEY; var _t = localStorage.getItem('aevus_id_token'); if (_t) _h['Authorization'] = 'Bearer ' + _t; return _h; })()
      })
      .then(function(r){ return r.json(); })
      .then(function(data) {
        trace.data = data;
        renderMultiTrace();
      });
    });
    // Also re-query the primary trace
    queryHistorian();
  };

  function renderTracesBar() {
    var bar = document.getElementById('hist-traces-bar');
    if (!bar) return;
    if (_histTraces.length === 0) { bar.style.display = 'none'; return; }
    bar.style.display = 'flex';
    bar.innerHTML = _histTraces.map(function(t) {
      return '<div style="display:inline-flex;align-items:center;gap:6px;padding:4px 10px;border-radius:12px;font-size:11px;font-family:var(--font-mono);background:rgba(255,255,255,0.04);border:1px solid ' + t.color + '33;cursor:pointer;' + (!t.visible ? 'opacity:0.35;text-decoration:line-through;' : '') + '" onclick="toggleHistTrace(' + t.id + ')">' +
        '<span style="width:8px;height:8px;border-radius:50%;background:' + t.color + ';flex-shrink:0;"></span>' +
        '<span style="color:' + t.color + ';">' + t.label + '</span>' +
        '<span onclick="event.stopPropagation();removeHistTrace(' + t.id + ')" style="color:var(--text-muted);cursor:pointer;margin-left:4px;font-size:13px;" title="Remove trace">&times;</span>' +
      '</div>';
    }).join('');
  }

  
  // Normalize toggle
  window._histNormalize = false;
  window.toggleHistNormalize = function() {
    window._histNormalize = !window._histNormalize;
    var btn = document.getElementById('hist-normalize-btn');
    if (btn) {
      btn.style.background = window._histNormalize ? 'rgba(167,139,250,0.2)' : '';
      btn.style.borderColor = window._histNormalize ? 'rgba(167,139,250,0.4)' : '';
      btn.style.color = window._histNormalize ? '#A78BFA' : '';
    }
    renderMultiTrace();
  };

function renderMultiTrace() {
    var el = document.getElementById('hist-chart');
    if (!el) return;
    var visibleTraces = _histTraces.filter(function(t) { return t.visible && t.data && t.data.length > 0; });

    // Also include the primary _histData if exists and no traces added
    if (visibleTraces.length === 0 && _histData && _histData.length > 0) return; // let single chart render handle it

    if (visibleTraces.length === 0) {
      el.innerHTML = '<div style="text-align:center;padding:60px;color:var(--text-muted);">Add traces to compare multiple data sources</div>';
      return;
    }

    var w = el.offsetWidth || 800;
    var h = 260;
    var pad = { top: 10, right: 20, bottom: 30, left: 55 };
    var cw = w - pad.left - pad.right;
    var ch = h - pad.top - pad.bottom;

    // Find global min/max — normalize if enabled
    var allValues = [];
    if (window._histNormalize) {
      // Normalize each trace to 0-100%
      visibleTraces.forEach(function(t) {
        var vals = t.data.map(function(d){return d.value;});
        var tMin = Math.min.apply(null, vals);
        var tMax = Math.max.apply(null, vals);
        var tRange = tMax - tMin || 1;
        t._normData = t.data.map(function(d) { return { time: d.time, value: ((d.value - tMin) / tRange) * 100 }; });
      });
      var minV = -5; var maxV = 105; var range = 110;
    } else {
      visibleTraces.forEach(function(t) { t._normData = null; });
      visibleTraces.forEach(function(t) { t.data.forEach(function(d) { allValues.push(d.value); }); });
      var minV = Math.min.apply(null, allValues);
      var maxV = Math.max.apply(null, allValues);
      var range = maxV - minV || 1;
      minV -= range * 0.08;
      maxV += range * 0.08;
      range = maxV - minV;
    }

    // Determine Y-axis unit label
    var yUnit = '';
    if (window._histNormalize) { yUnit = '%'; }
    else if (visibleTraces.length === 1 && visibleTraces[0].unit) { yUnit = visibleTraces[0].unit; }
    else {
      var units = [];
      visibleTraces.forEach(function(t) { if (t.unit && units.indexOf(t.unit) < 0) units.push(t.unit); });
      if (units.length === 1) yUnit = units[0];
    }

    // Title + stats
    var titleEl = document.getElementById('hist-chart-title');
    if (titleEl) titleEl.textContent = visibleTraces.length + ' TRACES OVERLAID';
    var statsEl = document.getElementById('hist-chart-stats');
    if (statsEl) {
      statsEl.innerHTML = visibleTraces.map(function(t) {
        var vals = t.data.map(function(d){return d.value;});
        var avg = vals.reduce(function(s,v){return s+v;},0) / vals.length;
        return '<span style="color:' + t.color + ';">' + t.assetId + ': ' + avg.toFixed(1) + ' avg</span>';
      }).join('');
    }

    // Y-axis grid
    var yLabels = '';
    for (var yi = 0; yi <= 4; yi++) {
      var yy = pad.top + (yi / 4) * ch;
      var yVal = (maxV - (yi / 4) * range).toFixed(1);
      yLabels += '<line x1="'+pad.left+'" y1="'+yy+'" x2="'+(w-pad.right)+'" y2="'+yy+'" stroke="rgba(255,255,255,0.06)" stroke-width="1"/>';
      yLabels += '<text x="'+(pad.left-6)+'" y="'+(yy+3)+'" fill="rgba(255,255,255,0.3)" font-size="9" text-anchor="end" font-family="var(--font-mono)">'+yVal+(yi===0&&yUnit?' '+yUnit:'')+'</text>';
    }

    // X-axis: use the longest trace for time labels
    var longestTrace = visibleTraces.reduce(function(a, b) { return a.data.length > b.data.length ? a : b; });
    var xLabels = '';
    var hours = document.getElementById('hist-range')?.value || '24';
    var labelCount = Math.min(6, longestTrace.data.length);
    for (var xi = 0; xi < labelCount; xi++) {
      var idx = Math.floor(xi / (labelCount-1) * (longestTrace.data.length-1));
      var xx = pad.left + (idx / (longestTrace.data.length-1)) * cw;
      var t = new Date(longestTrace.data[idx].time);
      var tLabel = t.getHours().toString().padStart(2,'0') + ':' + t.getMinutes().toString().padStart(2,'0');
      if (parseInt(hours) > 24) tLabel = (t.getMonth()+1)+'/'+t.getDate()+' '+tLabel;
      xLabels += '<text x="'+xx+'" y="'+(h-4)+'" fill="rgba(255,255,255,0.3)" font-size="9" text-anchor="middle" font-family="var(--font-mono)">'+tLabel+'</text>';
    }

    // Build paths for each trace
    var gradients = '';
    var paths = '';
    visibleTraces.forEach(function(trace, ti) {
      var pathD = '';
      var areaD = '';
      var tData = trace._normData || trace.data;
      tData.forEach(function(d, i) {
        var x = pad.left + (i / Math.max(tData.length - 1, 1)) * cw;
        var y = pad.top + (1 - (d.value - minV) / range) * ch;
        pathD += (i === 0 ? 'M' : 'L') + x.toFixed(1) + ',' + y.toFixed(1);
      });
      areaD = pathD + ' L' + (pad.left + cw).toFixed(1) + ',' + (pad.top + ch) + ' L' + pad.left + ',' + (pad.top + ch) + ' Z';

      var hexToRgb = trace.color.replace('#','');
      var r = parseInt(hexToRgb.substr(0,2),16), g = parseInt(hexToRgb.substr(2,2),16), b = parseInt(hexToRgb.substr(4,2),16);
      gradients += '<linearGradient id="htg'+ti+'" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="'+trace.color+'" stop-opacity="'+(ti===0?'0.15':'0.08')+'"/><stop offset="100%" stop-color="'+trace.color+'" stop-opacity="0"/></linearGradient>';
      paths += '<path d="'+areaD+'" fill="url(#htg'+ti+')"/>';
      paths += '<path d="'+pathD+'" fill="none" stroke="'+trace.color+'" stroke-width="'+(ti===0?'2':'1.5')+'" stroke-linejoin="round" stroke-linecap="round" opacity="0.9"/>';
      // End dot
      if (tData.length > 0) {
        var lastD = tData[tData.length-1];
        var lx = pad.left + cw;
        var ly = pad.top + (1 - (lastD.value - minV) / range) * ch;
        paths += '<circle cx="'+lx.toFixed(1)+'" cy="'+ly.toFixed(1)+'" r="3" fill="'+trace.color+'"/>';
      }
    });

    el.innerHTML =
      '<svg width="'+w+'" height="'+h+'" style="display:block;" id="hist-svg-multi">' +
        '<defs>' + gradients + '</defs>' +
        yLabels + xLabels + paths +
        '<rect id="hist-hover-multi" x="'+pad.left+'" y="'+pad.top+'" width="'+cw+'" height="'+ch+'" fill="transparent"/>' +
      '</svg>';

    // Legend
    var legendEl = document.getElementById('hist-legend');
    if (legendEl) {
      legendEl.innerHTML = visibleTraces.map(function(t) {
        return '<div style="display:inline-flex;align-items:center;gap:6px;padding:4px 12px;font-size:12px;color:var(--text-primary);font-weight:500;background:rgba(255,255,255,0.03);border-radius:6px;border:1px solid rgba(148,163,184,0.08);">' +
          '<span style="width:14px;height:6px;background:'+t.color+';border-radius:3px;box-shadow:0 0 4px '+t.color+'40;"></span>' +
          t.label + '</div>';
      }).join('');
    }

    // Multi-trace tooltip
    var svg = document.getElementById('hist-svg-multi');
    var tooltip = document.getElementById('hist-tooltip');
    if (svg && tooltip) {
      svg.addEventListener('mousemove', function(e) {
        var rect = svg.getBoundingClientRect();
        var mx = e.clientX - rect.left - pad.left;
        if (mx < 0 || mx > cw) { tooltip.style.display='none'; return; }
        var pct = mx / cw;

        var lines = '';
        visibleTraces.forEach(function(t) {
          var idx = Math.round(pct * (t.data.length - 1));
          idx = Math.max(0, Math.min(t.data.length-1, idx));
          var d = t.data[idx];
          if (d) {
            lines += '<div style="display:flex;align-items:center;gap:6px;"><span style="width:6px;height:6px;border-radius:50%;background:'+t.color+';"></span><span style="color:'+t.color+';font-weight:600;">'+d.value.toFixed(2)+'</span> <span style="color:var(--text-muted);">'+t.assetId+'/'+t.metric+'</span></div>';
          }
        });
        if (!lines) { tooltip.style.display='none'; return; }

        // Time label from longest trace
        var ltIdx = Math.round(pct * (longestTrace.data.length - 1));
        ltIdx = Math.max(0, Math.min(longestTrace.data.length-1, ltIdx));
        var timeStr = new Date(longestTrace.data[ltIdx].time).toLocaleString();

        tooltip.style.display = 'block';
        tooltip.style.left = (e.clientX - el.getBoundingClientRect().left + 14) + 'px';
        tooltip.style.top = (e.clientY - el.getBoundingClientRect().top - 20) + 'px';
        tooltip.innerHTML = '<div style="color:var(--text-muted);font-size:10px;margin-bottom:4px;">' + timeStr + '</div>' + lines;
      });
      svg.addEventListener('mouseleave', function() { tooltip.style.display='none'; });
    }
  }


  // ================================================================
  // NETWORK MODULE — ICS Network Topology
  // ================================================================
  function renderNetworkPage() {
    var page = document.getElementById('network-page');
    if (!page) return;
    // Skip full rebuild while a diagnostic tool is active
    if (page.querySelector('.page-title') && (window._netHeatmapActive || window._netTracertActive || window._netBwActive)) return;

    function _demoHealth(a) {
      if (!a) return null;
      if (a.health != null && a.health > 0) return a.health;
      if (window.AEVUS_DEMO && a.status !== 'offline') return 91;
      return a.health;
    }
    function nodeColor(assetId) {
      var a = (liveAssets||[]).find(function(x){return x.id===assetId;});
      if (!a) return '#6B7280';
      var c = hClass(a.status, _demoHealth(a));
      return c==='good'?'#10D478':c==='warn'?'#FBBF24':c==='bad'?'#EF4444':'#6B7280';
    }
    function nodeHealth(assetId) {
      var a = (liveAssets||[]).find(function(x){return x.id===assetId;});
      var h = _demoHealth(a);
      return a && h != null ? h : '—';
    }
    function nodeStatus(assetId) {
      var a = (liveAssets||[]).find(function(x){return x.id===assetId;});
      if (!a) return 'unknown';
      return a.status === 'offline' ? 'offline' : hClass(a.status, _demoHealth(a));
    }

    var nodes = [
      {id:'WAN', label:'WAN / Internet', x:480, y:64, icon:'cloud', ip:'', noClick:true},
      {id:'RTR-01', label:'MikroTik L009', x:480, y:192, icon:'router', ip:'.1'},
      {id:'SW-01', label:'Catalyst 2960', x:480, y:304, icon:'switch', ip:'.2'},
      {id:'RAD-01', label:'Trio JR900 #1', x:240, y:448, icon:'radio', ip:'.11'},
      {id:'RAD-02', label:'Trio JR900 #2', x:480, y:448, icon:'radio', ip:'.12'},
      {id:'EDGE-01', label:'Raspberry Pi', x:720, y:448, icon:'server', ip:'.254'},
      {id:'RTU-01', label:'SCADAPack 470', x:380, y:568, icon:'gauge', ip:'.21'},
      {id:'EFM-01', label:'TotalFlow XFC G4', x:580, y:568, icon:'meter', ip:'DNP3'},
    ];
    var edges = [
      {from:'WAN',to:'RTR-01',proto:'WireGuard'},
      {from:'RTR-01',to:'SW-01',proto:'Ethernet'},
      {from:'SW-01',to:'RAD-01',proto:'SNMP v2c'},
      {from:'SW-01',to:'RAD-02',proto:'SNMP v2c'},
      {from:'SW-01',to:'EDGE-01',proto:'SNMP v2c'},
      {from:'RAD-01',to:'RTU-01',proto:'Modbus TCP'},
      {from:'RAD-02',to:'EFM-01',proto:'DNP3'},
    ];

    var W=960, H=640;
    var svg = '<svg viewBox="0 0 '+W+' '+H+'" width="100%" style="max-width:960px;display:block;margin:0 auto;">';

    // Purdue Security Zone Bands
    // L4 — Enterprise / WAN
    svg += '<rect x="16" y="16" width="928" height="96" rx="8" fill="rgba(239,68,68,0.03)" stroke="rgba(239,68,68,0.15)" stroke-width="1" stroke-dasharray="4,4"/>';
    svg += '<text x="32" y="36" fill="rgba(255,255,255,0.3)" font-size="10" font-weight="600" letter-spacing="1.5" font-family="var(--font-mono)" text-transform="uppercase">L4 \u2014 ENTERPRISE / WAN</text>';

    // L2 — Supervisory / SCADA LAN
    svg += '<rect x="16" y="128" width="928" height="224" rx="8" fill="rgba(234,179,8,0.025)" stroke="rgba(234,179,8,0.15)" stroke-width="1" stroke-dasharray="4,4"/>';
    svg += '<text x="32" y="148" fill="rgba(255,255,255,0.3)" font-size="10" font-weight="600" letter-spacing="1.5" font-family="var(--font-mono)">L2 \u2014 SUPERVISORY / SCADA LAN</text>';

    // L0-1 — Field / Process
    svg += '<rect x="16" y="368" width="928" height="256" rx="8" fill="rgba(34,197,94,0.025)" stroke="rgba(34,197,94,0.15)" stroke-width="1" stroke-dasharray="4,4"/>';
    svg += '<text x="32" y="388" fill="rgba(255,255,255,0.3)" font-size="10" font-weight="600" letter-spacing="1.5" font-family="var(--font-mono)">L0-1 \u2014 FIELD / PROCESS</text>';

    // Firewall indicator between L4 and L2
    svg += '<rect x="450" y="113" width="60" height="16" rx="4" fill="rgba(239,68,68,0.12)" stroke="rgba(239,68,68,0.3)" stroke-width="0.5"/>';
    svg += '<rect x="440" y="108" width="80" height="22" rx="4" fill="rgba(239,68,68,0.12)" stroke="rgba(239,68,68,0.4)" stroke-width="1"/>' +
      '<text x="480" y="123" fill="#EF4444" font-size="10" text-anchor="middle" font-weight="700" font-family="var(--font-mono)">🛡 FIREWALL</text>';

    // Edges
    // Animated flow style
    svg += '<style>@keyframes flowPulse{0%{stroke-dashoffset:0}100%{stroke-dashoffset:-20}}</style>';

    edges.forEach(function(e, ei){
      var n1 = nodes.find(function(n){return n.id===e.from;});
      var n2 = nodes.find(function(n){return n.id===e.to;});
      if(!n1||!n2) return;
      var active = nodeStatus(e.to)!=='offline' && nodeStatus(e.to)!=='unknown';
      var stroke = active ? '#10D478' : 'rgba(239,68,68,0.4)';
      var y1 = n1.y + 32, y2 = n2.y - 32;
      // Curved paths for non-vertical connections
      if (n1.x === n2.x) {
        svg += '<line x1="'+n1.x+'" y1="'+y1+'" x2="'+n2.x+'" y2="'+y2+'" stroke="'+stroke+'" stroke-width="'+(active?'1.5':'1')+'" stroke-opacity="'+(active?'0.6':'0.3')+'"'+(active?'':' stroke-dasharray="6,4"')+'/>';
        if (active) svg += '<line x1="'+n1.x+'" y1="'+y1+'" x2="'+n2.x+'" y2="'+y2+'" stroke="'+stroke+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" stroke-opacity="0.3" stroke-dasharray="4,16" style="animation:flowPulse 1.5s linear infinite;"/>';
      } else {
        var mx = (n1.x+n2.x)/2, my = (y1+y2)/2;
        var path = 'M'+n1.x+','+y1+' C'+n1.x+','+my+' '+n2.x+','+my+' '+n2.x+','+y2;
        svg += '<path d="'+path+'" fill="none" stroke="'+stroke+'" stroke-width="'+(active?'1.5':'1')+'" stroke-opacity="'+(active?'0.6':'0.3')+'"'+(active?'':' stroke-dasharray="6,4"')+'/>';
        if (active) svg += '<path d="'+path+'" fill="none" stroke="'+stroke+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" stroke-opacity="0.3" stroke-dasharray="4,16" style="animation:flowPulse 1.5s linear infinite;"/>';
      }
      // Protocol label — offset from midpoint, better opacity
      var lx = (n1.x+n2.x)/2, ly = (y1+y2)/2;
      var labelOffset = n1.x === n2.x ? -12 : 0;
      svg += '<text x="'+(lx+(n1.x===n2.x?-8:0))+'" y="'+(ly+labelOffset)+'" fill="rgba(255,255,255,0.5)" font-size="9" text-anchor="'+(n1.x===n2.x?'end':'middle')+'" font-family="var(--font-mono)">'+e.proto+'</text>';
    });

    // Nodes
    nodes.forEach(function(n){
      var c = n.id==='WAN' ? '#6B7280' : nodeColor(n.id);
      var h = n.id==='WAN' ? '' : nodeHealth(n.id);
      var rw=180, rh=64;

      // Node box with icon column
      svg += '<g style="cursor:pointer;transition:stroke 0.2s,filter 0.2s;" onmouseover="this.style.stroke=&quot;#0EA5E9&quot;;this.style.filter=&quot;drop-shadow(0 0 4px rgba(14,165,233,0.4))&quot;" onmouseout="this.style.stroke=&quot;#4A5168&quot;;this.style.filter=&quot;none&quot;" onclick="'+(n.noClick?'':'openAssetDrawer(&quot;'+n.id+'&quot;)')+'">';
      svg += '<rect x="'+(n.x-rw/2)+'" y="'+(n.y-rh/2)+'" width="'+rw+'" height="'+rh+'" rx="8" fill="#161E33" stroke="'+c+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
      // Icon background column — subtle separator
      svg += '<line x1="'+(n.x-rw/2+48)+'" y1="'+(n.y-rh/2+6)+'" x2="'+(n.x-rw/2+48)+'" y2="'+(n.y+rh/2-6)+'" stroke="rgba(255,255,255,0.06)" stroke-width="1"/>';

      // Device SVG icons — Hybrid: modern IT icons + ISA-inspired field devices
      // Rendered as <g> groups directly in the main SVG for proper scaling
      var _iconX = n.x - rw/2 + 12, _iconY = n.y - 13;
      var _iconScale = 1.08;
      svg += '<g transform="translate('+_iconX+','+_iconY+') scale('+_iconScale+')" fill="none" stroke="'+c+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">';
      if (n.icon==='cloud') {
        svg += '<path d="M6 18c-2.2 0-4-1.5-4-3.4 0-1.6 1.1-3 2.7-3.3C5.3 8.5 8 6 11.2 6c2.8 0 5.2 1.8 6 4.3C19.3 10.6 21 12.3 21 14.4c0 2-1.6 3.6-3.6 3.6H6z" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
      } else if (n.icon==='router') {
        svg += '<rect x="2" y="9" width="20" height="10" rx="2"/>';
        svg += '<circle cx="7" cy="14" r="1.2" fill="'+c+'"/><circle cx="11" cy="14" r="1.2" fill="'+c+'"/><circle cx="15" cy="14" r="1.2" fill="'+c+'"/>';
        svg += '<path d="M7 9V5l5-3 5 3v4" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
        svg += '<circle cx="12" cy="4" r="1" fill="'+c+'"/>';
      } else if (n.icon==='switch') {
        svg += '<rect x="1" y="8" width="22" height="12" rx="2"/>';
        svg += '<line x1="5" y1="20" x2="5" y2="24"/><line x1="9" y1="20" x2="9" y2="24"/><line x1="13" y1="20" x2="13" y2="24"/><line x1="17" y1="20" x2="17" y2="24"/><line x1="19" y1="20" x2="19" y2="24"/>';
        svg += '<circle cx="5" cy="11.5" r="1" fill="'+c+'"/><circle cx="9" cy="11.5" r="1" fill="'+c+'"/><circle cx="13" cy="11.5" r="1" fill="'+c+'"/><circle cx="17" cy="11.5" r="1" fill="'+c+'"/>';
        svg += '<line x1="4" y1="15" x2="20" y2="15" stroke-width="0.8" stroke-opacity="0.3"/>';
      } else if (n.icon==='radio') {
        // Antenna tower with signal arcs — the cool antenna
        svg += '<line x1="12" y1="1" x2="12" y2="15" stroke-width="2"/>';
        svg += '<line x1="9" y1="5" x2="15" y2="5" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
        svg += '<line x1="10" y1="3" x2="14" y2="3" stroke-width="1.2"/>';
        svg += '<line x1="12" y1="15" x2="7" y2="24"/><line x1="12" y1="15" x2="17" y2="24"/>';
        svg += '<line x1="8.5" y1="21" x2="15.5" y2="21" stroke-width="1.2"/>';
        svg += '<path d="M18 4a8 8 0 0 1 0 10" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" stroke-opacity="0.7"/>';
        svg += '<path d="M21 2a12 12 0 0 1 0 14" stroke-width="1.2" stroke-opacity="0.4"/>';
        svg += '<path d="M6 4a8 8 0 0 0 0 10" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" stroke-opacity="0.7"/>';
        svg += '<path d="M3 2a12 12 0 0 0 0 14" stroke-width="1.2" stroke-opacity="0.4"/>';
      } else if (n.icon==='server') {
        svg += '<rect x="4" y="2" width="16" height="8" rx="1.5"/>';
        svg += '<rect x="4" y="13" width="16" height="8" rx="1.5"/>';
        svg += '<circle cx="16" cy="6" r="1.2" fill="'+c+'"/><circle cx="16" cy="17" r="1.2" fill="'+c+'"/>';
        svg += '<line x1="7" y1="6" x2="12" y2="6" stroke-opacity="0.5"/>';
        svg += '<line x1="7" y1="17" x2="12" y2="17" stroke-opacity="0.5"/>';
      } else if (n.icon==='gauge') {
        // ISA-inspired: PLC/RTU function block with gauge
        svg += '<rect x="2" y="3" width="20" height="19" rx="1.5"/>';
        svg += '<line x1="2" y1="7" x2="22" y2="7" stroke-opacity="0.4"/>';
        svg += '<circle cx="5" cy="5" r="0.8" fill="'+c+'"/><circle cx="7.5" cy="5" r="0.8" fill="'+c+'"/>';
        svg += '<path d="M7 15a5 5 0 0 1 10 0" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
        svg += '<line x1="12" y1="15" x2="15" y2="11.5" stroke-width="1.8"/>';
        svg += '<circle cx="12" cy="15" r="1" fill="'+c+'"/>';
        svg += '<text x="12" y="20" text-anchor="middle" font-size="4" fill="'+c+'" stroke="none" font-weight="700" font-family="var(--font-mono)">RTU</text>';
      } else if (n.icon==='meter') {
        // ISA flow element diamond
        svg += '<path d="M2 12l10-10 10 10-10 10z" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
        svg += '<line x1="8" y1="12" x2="16" y2="12" stroke-width="1.2" stroke-opacity="0.5"/>';
        svg += '<circle cx="12" cy="12" r="2.5" stroke-opacity="0.6"/>';
        svg += '<path d="M12 7v10" stroke-width="0.8" stroke-opacity="0.3"/>';
      }
      svg += '</g>';

      // Label — aligned to right of icon column (x+56 from left edge)
      svg += '<text x="'+(n.x-rw/2+56)+'" y="'+(n.y-8)+'" fill="#E2E8F0" font-size="12" font-weight="600" font-family="Manrope">'+n.label+'</text>';
      svg += '<text x="'+(n.x-rw/2+56)+'" y="'+(n.y+8)+'" fill="rgba(255,255,255,0.45)" font-size="9" font-family="var(--font-mono)">'+n.id+(n.ip?' \u00B7 '+n.ip:'')+'</text>';

      // Health badge — circular, top-right outside node
      if (h !== '') {
        svg += '<circle cx="'+(n.x+rw/2-4)+'" cy="'+(n.y-rh/2-4)+'" r="14" fill="#0B1020" stroke="'+c+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>';
        svg += '<text x="'+(n.x+rw/2-4)+'" y="'+(n.y-rh/2)+'" fill="'+c+'" font-size="10" font-weight="700" text-anchor="middle" font-family="var(--font-mono)">'+h+'</text>';
      }
      svg += '</g>';
    });

    // SNMP Trap indicator — positioned relative to router node
    // ── E-UX-8: Anomaly indicators on edge device ──
    var _edge = nodes.find(function(n){return n.id==='EDGE-01';});
    if (_edge) {
      svg += '<rect x="'+(_edge.x-45)+'" y="'+(_edge.y+28)+'" width="90" height="14" rx="3" fill="rgba(16,212,120,0.06)" stroke="rgba(16,212,120,0.15)" stroke-width="0.5"/>';
      svg += '<circle cx="'+(_edge.x-37)+'" cy="'+(_edge.y+35)+'" r="2.5" fill="#10D478"/>';
      svg += '<text x="'+(_edge.x-31)+'" y="'+(_edge.y+38)+'" fill="rgba(16,212,120,0.7)" font-size="6" font-family="var(--font-mono)">BASELINE: NORMAL</text>';
    }
    var _rtr = nodes.find(function(n){return n.id==='RTR-01';});
    if (_rtr) {
      svg += '<rect x="'+(_rtr.x+96)+'" y="'+(_rtr.y-8)+'" width="72" height="18" rx="4" fill="rgba(14,165,233,0.12)" stroke="rgba(14,165,233,0.25)" stroke-width="0.5"/>';
      svg += '<text x="'+(_rtr.x+132)+'" y="'+(_rtr.y+5)+'" fill="#0EA5E9" font-size="8" text-anchor="middle" font-weight="500" font-family="var(--font-mono)">TRAP RECV</text>';
      // ── E-UX-8: Anomaly Detection Indicators (Langner) ──
      svg += '<rect x="'+(_rtr.x+96)+'" y="'+(_rtr.y+14)+'" width="72" height="14" rx="3" fill="rgba(16,212,120,0.06)" stroke="rgba(16,212,120,0.15)" stroke-width="0.5"/>';
      svg += '<circle cx="'+(_rtr.x+104)+'" cy="'+(_rtr.y+21)+'" r="2.5" fill="#10D478"/>';
      svg += '<text x="'+(_rtr.x+110)+'" y="'+(_rtr.y+24)+'" fill="rgba(16,212,120,0.7)" font-size="6" font-family="var(--font-mono)">ANOMALY: CLEAR</text>';
    }

    svg += '</svg>';

    // Store node data for interactive tools
    window._netNodes = nodes;
    window._netEdges = edges;

    page.innerHTML =
      '<div class="module-header"><div><h2 class="page-title">Network Topology</h2>' +
      '<div class="module-subtitle">ICS network layout — BlueJay Unit #1 · API# 42-157-33245 · 10.0.1.0/24</div></div>' +
      // Diagnostic toolbar
      '<div style="display:flex;gap:8px;">' +
        '<button id="net-tool-heatmap" class="net-tool-btn" onclick="window._netHeatmap()" title="Ping sweep all nodes — latency &amp; packet loss" style="padding:5px 14px;font-size:11px;font-weight:600;background:rgba(14,165,233,0.1);border:1px solid rgba(14,165,233,0.25);border-radius:6px;color:#06B6D4;cursor:pointer;font-family:var(--font-mono);letter-spacing:0.3px;transition:all 0.2s;"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" style="vertical-align:-1px;margin-right:4px;"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>Health Scan</button>' +
        '<button id="net-tool-tracert" class="net-tool-btn" onclick="window._netTracertMode()" title="Click a node to trace hop-by-hop path from WAN" style="padding:5px 14px;font-size:11px;font-weight:600;background:rgba(168,85,247,0.1);border:1px solid rgba(168,85,247,0.25);border-radius:6px;color:#A855F7;cursor:pointer;font-family:var(--font-mono);letter-spacing:0.3px;transition:all 0.2s;"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" style="vertical-align:-1px;margin-right:4px;"><path d="M5 12h14M12 5l7 7-7 7"/></svg>Trace Route</button>' +
        '<button id="net-tool-bw" class="net-tool-btn" onclick="window._netBandwidth()" title="Live bandwidth utilization on all links — 3s refresh" style="padding:5px 14px;font-size:11px;font-weight:600;background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.25);border-radius:6px;color:#10D478;cursor:pointer;font-family:var(--font-mono);letter-spacing:0.3px;transition:all 0.2s;"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" style="vertical-align:-1px;margin-right:4px;"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>BW Monitor</button>' +
      '</div></div>' +
      '<div id="net-status-bar" style="display:none;padding:8px 14px;margin-bottom:8px;border-radius:8px;font-size:11px;font-family:var(--font-mono);transition:all 0.3s;"></div>' +
      '<div id="net-svg-wrap" class="panel-box" style="padding:24px;text-align:center;position:relative;">'+svg+'</div>' +
      // Traceroute results panel
      '<div id="net-trace-results" style="display:none;margin-top:10px;"></div>' +
      // Legend
      '<div style="display:flex;gap:16px;margin-top:12px;justify-content:center;flex-wrap:wrap;">' +
        '<div style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text-muted);"><span style="width:20px;height:2px;background:#10D478;display:inline-block;"></span> Active</div>' +
        '<div style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text-muted);"><span style="width:20px;height:2px;background:#EF4444;display:inline-block;border-top:1px dashed #EF4444;"></span> Down</div>' +
        '<div style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text-muted);"><span style="width:8px;height:8px;border-radius:50%;background:#10D478;display:inline-block;"></span> Good</div>' +
        '<div style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text-muted);"><span style="width:8px;height:8px;border-radius:50%;background:#FBBF24;display:inline-block;"></span> Warning</div>' +
        '<div style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text-muted);"><span style="width:8px;height:8px;border-radius:50%;background:#EF4444;display:inline-block;"></span> Critical</div>' +
      '</div>';

    // ── TOOL 1: HEALTH SCAN (Latency Heatmap) ──
    window._netHeatmapActive = false;
    window._netHeatmap = function() {
      var svgEl = document.querySelector('#net-svg-wrap svg');
      if (!svgEl) return;
      var statusBar = document.getElementById('net-status-bar');
      window._netHeatmapActive = !window._netHeatmapActive;
      var btn = document.getElementById('net-tool-heatmap');

      if (!window._netHeatmapActive) {
        // Reset
        btn.style.background = 'rgba(14,165,233,0.1)';
        statusBar.style.display = 'none';
        svgEl.querySelectorAll('.net-latency-badge').forEach(function(e){e.remove();});
        svgEl.querySelectorAll('.net-heatmap-glow').forEach(function(e){e.remove();});
        return;
      }

      btn.style.background = 'rgba(14,165,233,0.25)';
      statusBar.style.display = 'block';
      statusBar.style.background = 'rgba(14,165,233,0.08)';
      statusBar.style.border = '1px solid rgba(14,165,233,0.2)';
      statusBar.style.color = '#0EA5E9';
      statusBar.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="vertical-align:-1px;margin-right:6px;animation:spin 1s linear infinite;"><path d="M12 2a10 10 0 1 0 10 10"/></svg>Scanning network...';

      // Simulate ping sweep with staggered results
      var _nodes = window._netNodes || [];
      var _latencies = {'WAN':0, 'RTR-01':4, 'SW-01':6, 'RAD-01':18, 'RAD-02':22, 'EDGE-01':8, 'RTU-01':42, 'EFM-01':38};
      var _losses = {'WAN':0, 'RTR-01':0, 'SW-01':0, 'RAD-01':0.3, 'RAD-02':0.8, 'EDGE-01':0, 'RTU-01':1.2, 'EFM-01':0.5};
      var nodeEls = svgEl.querySelectorAll('g[style*="cursor"]');

      _nodes.forEach(function(n, i) {
        setTimeout(function() {
          var lat = _latencies[n.id] || 0;
          var loss = _losses[n.id] || 0;
          // Color based on latency: <20ms green, 20-50ms amber, >50ms red
          var col = lat < 20 ? '#10D478' : lat < 50 ? '#FBBF24' : '#EF4444';
          var bgCol = lat < 20 ? 'rgba(34,197,94,0.15)' : lat < 50 ? 'rgba(251,191,36,0.15)' : 'rgba(239,68,68,0.15)';

          // Add glow effect around node
          var glow = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
          glow.setAttribute('cx', n.x);
          glow.setAttribute('cy', n.y);
          glow.setAttribute('r', '42');
          glow.setAttribute('fill', 'none');
          glow.setAttribute('stroke', col);
          glow.setAttribute('stroke-width', '2');
          glow.setAttribute('stroke-opacity', '0.3');
          glow.setAttribute('class', 'net-heatmap-glow');
          glow.style.transition = 'all 0.5s ease-out';
          glow.style.opacity = '0';
          svgEl.appendChild(glow);
          setTimeout(function(){ glow.style.opacity = '1'; }, 50);

          // Add latency badge below node
          if (n.id !== 'WAN') {
            var g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
            g.setAttribute('class', 'net-latency-badge');
            var rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
            rect.setAttribute('x', n.x - 36);
            rect.setAttribute('y', n.y + 36);
            rect.setAttribute('width', '72');
            rect.setAttribute('height', '18');
            rect.setAttribute('rx', '4');
            rect.setAttribute('fill', bgCol);
            rect.setAttribute('stroke', col);
            rect.setAttribute('stroke-width', '0.5');
            g.appendChild(rect);
            var text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
            text.setAttribute('x', n.x);
            text.setAttribute('y', n.y + 49);
            text.setAttribute('fill', col);
            text.setAttribute('font-size', '9');
            text.setAttribute('font-weight', '600');
            text.setAttribute('text-anchor', 'middle');
            text.setAttribute('font-family', 'var(--font-mono)');
            text.textContent = lat + 'ms · ' + loss.toFixed(1) + '% loss';
            g.appendChild(text);
            g.style.opacity = '0';
            g.style.transition = 'opacity 0.4s';
            svgEl.appendChild(g);
            setTimeout(function(){ g.style.opacity = '1'; }, 100);
          }
        }, 200 + i * 300);
      });

      // Update status bar after all complete
      setTimeout(function() {
        statusBar.innerHTML = '<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#0EA5E9;margin-right:6px;animation:pulse 2s infinite;vertical-align:1px;"></span><strong style="margin-right:8px;">HEALTH SCAN ACTIVE</strong> ✓ 7 hosts up · avg 19.7ms · 0.4% loss · 2 hosts &gt;20ms <button onclick="document.getElementById(\'net-tool-heatmap\').click()" style="margin-left:12px;padding:2px 10px;font-size:10px;background:rgba(14,165,233,0.15);border:1px solid rgba(14,165,233,0.3);border-radius:4px;color:#06B6D4;cursor:pointer;font-family:var(--font-mono);">Copy Results</button>';
        // Copy handler
        statusBar.querySelector('button').onclick = function(e) {
          e.stopPropagation();
          var _n = window._netNodes || [];
          var _lat = {'WAN':0,'RTR-01':4,'SW-01':6,'RAD-01':18,'RAD-02':22,'EDGE-01':8,'RTU-01':42,'EFM-01':38};
          var _ls = {'WAN':0,'RTR-01':0,'SW-01':0,'RAD-01':0.3,'RAD-02':0.8,'EDGE-01':0,'RTU-01':1.2,'EFM-01':0.5};
          var txt = 'HOST\tLATENCY\tLOSS\tSTATUS\n';
          _n.forEach(function(n){ txt += n.id+'\t'+(_lat[n.id]||0)+'ms\t'+(_ls[n.id]||0).toFixed(1)+'%\t'+'UP\n'; });
          navigator.clipboard.writeText(txt).then(function(){
            var sb = document.getElementById('net-status-bar');
            var orig = sb.innerHTML;
            sb.innerHTML = '<span style="color:#10D478;">✓ Results copied to clipboard</span>';
            setTimeout(function(){ sb.innerHTML = orig; }, 1500);
          });
        };
      }, 200 + _nodes.length * 300 + 200);
    };

    // ── TOOL 2: VISUAL TRACEROUTE ──
    window._netTracertActive = false;
    window._netTracertMode = function() {
      window._netTracertActive = !window._netTracertActive;
      var btn = document.getElementById('net-tool-tracert');
      var statusBar = document.getElementById('net-status-bar');
      var svgEl = document.querySelector('#net-svg-wrap svg');

      if (!window._netTracertActive) {
        btn.style.background = 'rgba(168,85,247,0.1)';
        statusBar.style.display = 'none';
        if (svgEl) svgEl.style.cursor = '';
        document.getElementById('net-trace-results').style.display = 'none';
        svgEl.querySelectorAll('.net-trace-dot,.net-trace-badge').forEach(function(e){e.remove();});
        // Restore original onclick handlers
        var nodeGs = svgEl.querySelectorAll('g[data-original-onclick]');
        nodeGs.forEach(function(g) {
          g.setAttribute('onclick', g.getAttribute('data-original-onclick'));
          g.removeAttribute('data-original-onclick');
        });
        window._netTraceClickHandler = null;
        return;
      }

      btn.style.background = 'rgba(168,85,247,0.25)';
      statusBar.style.display = 'block';
      statusBar.style.background = 'rgba(168,85,247,0.08)';
      statusBar.style.border = '1px solid rgba(168,85,247,0.2)';
      statusBar.style.color = '#A855F7';
      statusBar.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" style="vertical-align:-1px;margin-right:6px;"><path d="M5 12h14M12 5l7 7-7 7"/></svg>Click any node to trace route from WAN';
      if (svgEl) svgEl.style.cursor = 'crosshair';

      // Build path lookup: for any target, trace back to WAN
      var _pathMap = {
        'RTR-01': ['WAN','RTR-01'],
        'SW-01': ['WAN','RTR-01','SW-01'],
        'RAD-01': ['WAN','RTR-01','SW-01','RAD-01'],
        'RAD-02': ['WAN','RTR-01','SW-01','RAD-02'],
        'EDGE-01': ['WAN','RTR-01','SW-01','EDGE-01'],
        'RTU-01': ['WAN','RTR-01','SW-01','RAD-01','RTU-01'],
        'EFM-01': ['WAN','RTR-01','SW-01','RAD-02','EFM-01']
      };
      var _hopLatencies = {'WAN':0,'RTR-01':4,'SW-01':2,'RAD-01':12,'RAD-02':16,'EDGE-01':2,'RTU-01':24,'EFM-01':18};

      // Override node clicks for traceroute mode
      window._netTraceClickHandler = function(targetId) {
        if (!window._netTracertActive || !targetId || targetId === 'WAN') return;
        var path = _pathMap[targetId];
        if (!path) return;
        var _nodes = window._netNodes;

        // Clear previous traces
        svgEl.querySelectorAll('.net-trace-dot,.net-trace-badge').forEach(function(e){e.remove();});

        // Animate packet along path
        var cumLatency = 0;
        path.forEach(function(nodeId, hopIdx) {
          if (hopIdx === 0) return; // Skip WAN origin
          setTimeout(function() {
            var prev = _nodes.find(function(n){return n.id===path[hopIdx-1];});
            var curr = _nodes.find(function(n){return n.id===nodeId;});
            if (!prev || !curr) return;
            var hopLat = _hopLatencies[nodeId] || 0;
            cumLatency += hopLat;

            // Animate dot from prev to curr
            var dot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
            dot.setAttribute('cx', prev.x);
            dot.setAttribute('cy', prev.y);
            dot.setAttribute('r', '5');
            dot.setAttribute('fill', '#A855F7');
            dot.setAttribute('class', 'net-trace-dot');
            dot.style.transition = 'cx 0.4s ease-in-out, cy 0.4s ease-in-out';
            svgEl.appendChild(dot);
            setTimeout(function() {
              dot.setAttribute('cx', curr.x);
              dot.setAttribute('cy', curr.y);
            }, 50);

            // Add hop latency badge
            setTimeout(function() {
              var badge = document.createElementNS('http://www.w3.org/2000/svg', 'g');
              badge.setAttribute('class', 'net-trace-badge');
              var mx = (prev.x + curr.x) / 2, my = (prev.y + curr.y) / 2;
              var r = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
              r.setAttribute('x', mx - 22); r.setAttribute('y', my - 8);
              r.setAttribute('width', '44'); r.setAttribute('height', '16'); r.setAttribute('rx', '4');
              r.setAttribute('fill', 'rgba(168,85,247,0.2)'); r.setAttribute('stroke', 'rgba(168,85,247,0.5)'); r.setAttribute('stroke-width', '0.5');
              badge.appendChild(r);
              var t = document.createElementNS('http://www.w3.org/2000/svg', 'text');
              t.setAttribute('x', mx); t.setAttribute('y', my + 4);
              t.setAttribute('fill', '#C084FC'); t.setAttribute('font-size', '8'); t.setAttribute('font-weight', '600');
              t.setAttribute('text-anchor', 'middle'); t.setAttribute('font-family', 'var(--font-mono)');
              t.textContent = '+' + hopLat + 'ms';
              badge.appendChild(t);
              badge.style.opacity = '0'; badge.style.transition = 'opacity 0.3s';
              svgEl.appendChild(badge);
              setTimeout(function(){ badge.style.opacity = '1'; }, 50);
            }, 300);
          }, hopIdx * 600);
        });

        // Show results panel after animation
        var totalTime = path.length * 600 + 200;
        var totalLat = 0;
        path.forEach(function(id){ totalLat += (_hopLatencies[id]||0); });
        setTimeout(function() {
          var resultsEl = document.getElementById('net-trace-results');
          resultsEl.style.display = 'block';
          var rows = path.map(function(id, i) {
            var n = _nodes.find(function(nn){return nn.id===id;});
            var lat = _hopLatencies[id] || 0;
            return '<div style="display:flex;align-items:center;gap:12px;padding:6px 12px;' + (i===path.length-1?'background:rgba(168,85,247,0.08);border-radius:6px;':'') + '">' +
              '<span style="color:#64748B;font-size:10px;font-family:var(--font-mono);width:16px;">' + i + '</span>' +
              '<span style="color:#A855F7;font-size:10px;">'+'●'+'</span>' +
              '<span style="color:var(--text-primary);font-size:12px;font-weight:500;flex:1;">' + (n?n.label:id) + '</span>' +
              '<span style="color:var(--text-muted);font-size:10px;font-family:var(--font-mono);">' + (n?n.id:'') + '</span>' +
              '<span style="color:#C084FC;font-size:11px;font-weight:600;font-family:var(--font-mono);width:50px;text-align:right;">' + (i===0?'—':lat+'ms') + '</span>' +
            '</div>';
          }).join('');
          resultsEl.innerHTML = '<div class="panel-box" style="padding:12px 8px;">' +
            '<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 12px 8px;border-bottom:1px solid var(--border);margin-bottom:6px;">' +
              '<span style="font-size:11px;font-weight:600;color:#A855F7;font-family:var(--font-mono);">TRACEROUTE → ' + targetId + '</span>' +
              '<div style="display:flex;align-items:center;gap:8px;"><span style="font-size:10px;color:var(--text-muted);">' + path.length + ' hops · ' + totalLat + 'ms total</span>' +
              '<button id="net-trace-copy" style="padding:2px 8px;font-size:10px;background:rgba(168,85,247,0.15);border:1px solid rgba(168,85,247,0.3);border-radius:4px;color:#A855F7;cursor:pointer;font-family:var(--font-mono);">Copy</button></div>' +
            '</div>' + rows + '</div>';
          // Wire copy button
          var cpBtn = document.getElementById('net-trace-copy');
          if (cpBtn) cpBtn.onclick = function() {
            var txt = 'HOP\tNODE\tLATENCY\n';
            path.forEach(function(id, i) {
              var n = _nodes.find(function(nn){return nn.id===id;});
              txt += i+'\t'+(n?n.label:id)+'\t'+(i===0?'—':(_hopLatencies[id]||0)+'ms')+'\n';
            });
            txt += '\nTotal: '+path.length+' hops, '+totalLat+'ms';
            navigator.clipboard.writeText(txt).then(function(){
              cpBtn.textContent='✓ Copied'; cpBtn.style.background='rgba(34,197,94,0.15)'; cpBtn.style.color='#10D478';
              setTimeout(function(){ cpBtn.textContent='Copy'; cpBtn.style.background='rgba(168,85,247,0.15)'; cpBtn.style.color='#A855F7'; }, 1500);
            });
          };
        }, totalTime);

        // Update status
        statusBar.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="vertical-align:-1px;margin-right:6px;animation:spin 1s linear infinite;"><path d="M12 2a10 10 0 1 0 10 10"/></svg>Tracing route to ' + targetId + '...';
        setTimeout(function() {
          statusBar.innerHTML = '<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#A855F7;margin-right:6px;animation:pulse 2s infinite;vertical-align:1px;"></span><strong style="margin-right:8px;">TRACEROUTE ACTIVE</strong> ✓ ' + path.length + ' hops · ' + totalLat + 'ms total · 0% loss — click another node to re-trace';
        }, totalTime);
      };

      // Override the onclick handlers on node groups
      var nodeGs = svgEl.querySelectorAll('g[onclick]');
      nodeGs.forEach(function(g) {
        var onc = g.getAttribute('onclick') || '';
        var match = onc.match(/openAssetDrawer\("([^"]+)"\)/);
        if (match) {
          g.setAttribute('data-original-onclick', onc);
          g.setAttribute('onclick', '_netTraceClickHandler("' + match[1] + '")');
        }
      });
    };

    // ── TOOL 3: BANDWIDTH MONITOR ──
    window._netBwActive = false;
    window._netBandwidth = function() {
      window._netBwActive = !window._netBwActive;
      var btn = document.getElementById('net-tool-bw');
      var statusBar = document.getElementById('net-status-bar');
      var svgEl = document.querySelector('#net-svg-wrap svg');
      if (!svgEl) return;

      if (!window._netBwActive) {
        btn.style.background = 'rgba(34,197,94,0.1)';
        statusBar.style.display = 'none';
        svgEl.querySelectorAll('.net-bw-overlay,.net-bw-sparkline').forEach(function(e){e.remove();});
        if (window._netBwInterval) { clearInterval(window._netBwInterval); window._netBwInterval = null; }
        return;
      }

      btn.style.background = 'rgba(34,197,94,0.25)';
      statusBar.style.display = 'block';
      statusBar.style.background = 'rgba(34,197,94,0.08)';
      statusBar.style.border = '1px solid rgba(34,197,94,0.2)';
      statusBar.style.color = '#10D478';
      window._netBwRefreshCount = 0;

      // Simulated bandwidth data (kbps)
      var _bwData = {
        'WAN-RTR-01': {bw: 8500, cap: 50000, label: '8.5 Mbps'},
        'RTR-01-SW-01': {bw: 12000, cap: 100000, label: '12 Mbps'},
        'SW-01-RAD-01': {bw: 340, cap: 2000, label: '340 Kbps'},
        'SW-01-RAD-02': {bw: 280, cap: 2000, label: '280 Kbps'},
        'SW-01-EDGE-01': {bw: 1200, cap: 100000, label: '1.2 Mbps'},
        'RAD-01-RTU-01': {bw: 9.6, cap: 19.2, label: '9.6 Kbps'},
        'RAD-02-EFM-01': {bw: 4.8, cap: 19.2, label: '4.8 Kbps'}
      };

      var _edges = window._netEdges || [];
      var _nodes = window._netNodes || [];

      function updateBw() {
        svgEl.querySelectorAll('.net-bw-overlay').forEach(function(e){e.remove();});

        _edges.forEach(function(e) {
          var key = e.from + '-' + e.to;
          var d = _bwData[key];
          if (!d) return;
          var n1 = _nodes.find(function(n){return n.id===e.from;});
          var n2 = _nodes.find(function(n){return n.id===e.to;});
          if (!n1 || !n2) return;

          // Fluctuate bandwidth slightly
          var jitter = 1 + (Math.random() - 0.5) * 0.1;
          var currentBw = d.bw * jitter;
          var utilPct = Math.min(currentBw / d.cap, 1);
          // Color: <50% teal, 50-80% amber, >80% red
          var col = utilPct < 0.5 ? '#0EA5E9' : utilPct < 0.8 ? '#FBBF24' : '#EF4444';
          var thickness = 2 + utilPct * 6;

          var mx = (n1.x + n2.x) / 2, my = (n1.y + 32 + n2.y - 32) / 2;

          // BW label at midpoint
          var g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
          g.setAttribute('class', 'net-bw-overlay');
          var r = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
          var labelW = 68;
          r.setAttribute('x', mx - labelW/2 + (n1.x === n2.x ? 40 : 0));
          r.setAttribute('y', my - 9 + (n1.x === n2.x ? 6 : 0));
          r.setAttribute('width', labelW); r.setAttribute('height', '18'); r.setAttribute('rx', '4');
          r.setAttribute('fill', '#0B1020'); r.setAttribute('stroke', col); r.setAttribute('stroke-width', '0.5');
          g.appendChild(r);
          var t = document.createElementNS('http://www.w3.org/2000/svg', 'text');
          t.setAttribute('x', mx + (n1.x === n2.x ? 40 : 0));
          t.setAttribute('y', my + 3 + (n1.x === n2.x ? 6 : 0));
          t.setAttribute('fill', col); t.setAttribute('font-size', '8'); t.setAttribute('font-weight', '600');
          t.setAttribute('text-anchor', 'middle'); t.setAttribute('font-family', 'var(--font-mono)');
          t.textContent = d.label + ' ' + Math.round(utilPct * 100) + '%';
          g.appendChild(t);
          svgEl.appendChild(g);
        });

        // Summary in status bar
        var totalBw = 0; var maxUtil = 0;
        Object.values(_bwData).forEach(function(d) { totalBw += d.bw; maxUtil = Math.max(maxUtil, d.bw / d.cap); });
        window._netBwRefreshCount = (window._netBwRefreshCount||0) + 1; statusBar.innerHTML = '<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#10D478;margin-right:6px;animation:pulse 2s infinite;vertical-align:1px;"></span><strong style="margin-right:8px;">BW MONITOR LIVE</strong> Total: ' + (totalBw/1000).toFixed(1) + ' Mbps · Peak: ' + Math.round(maxUtil*100) + '% · ' + _edges.length + ' links · <span style="color:var(--text-muted);font-size:10px;">refresh #' + window._netBwRefreshCount + ' · 3s</span>';
      }

      updateBw();
      window._netBwInterval = setInterval(updateBw, 3000);
    };

    // Add spin animation for loading spinners
    if (!document.getElementById('net-spin-style')) {
      var s = document.createElement('style');
      s.id = 'net-spin-style';
      s.textContent = '@keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}';
      document.head.appendChild(s);
    }
  }

  // ================================================================
  // MAP MODULE — Geographic Asset Map (Mapbox)
  // ================================================================
  function renderMapPage() {
    var page = document.querySelector('section[data-page="map"]');
    if (!page) return;
    document.body.classList.add('map-active');
    if (window._aevusMapLoaded && typeof maplibregl !== "undefined") {
      if (window._aevusMapInstance) {
        setTimeout(function() {
          var m = window._aevusMapInstance;
          if (m) {
            m._frameRequest = null;
            m.triggerRepaint();
            m.resize();
          }
        }, 300);
      }
      return;
    }
    window._aevusMapLoaded = true; // prevent double init from polling
    page.style.cssText='position:relative;padding:0!important;margin:0;overflow:hidden;height:calc(100vh - 56px);';var mainEl=document.querySelector('.main');if(mainEl){mainEl.style.padding='0';mainEl.style.overflow='hidden';mainEl.style.height='calc(100vh - var(--topbar-h))';}
    page.innerHTML = '<div id="aevus-map" style="width:100%;height:100%;position:relative;"></div>'; /* no breadcrumb for map */

    if (typeof maplibregl === 'undefined') {
      // Load Mapbox GL JS
      var link = document.createElement('link');
      link.rel = 'stylesheet';
      link.href = 'maplibre-gl.min.css';
      document.head.appendChild(link);
      var script = document.createElement('script');
      script.src = 'maplibre-gl.min.js';
      script.onload = function(){ initAevusMap(); };
      document.head.appendChild(script);
    } else {
      setTimeout(initAevusMap, 300);
    }
  }

