  // ── GOLD PUSH: Confirmation dialog system ──
  function showConfirmDialog(title, message, proceedLabel, onProceed, destructive) {
    window._showConfirmDialog = showConfirmDialog;
    if (document.getElementById('confirm-overlay')) return;
    var overlay = document.createElement('div');
    overlay.id = 'confirm-overlay';
    overlay.className = 'confirm-overlay';
    overlay.innerHTML =
      '<div class="confirm-dialog" role="alertdialog" aria-labelledby="confirm-title" aria-describedby="confirm-msg">' +
        '<h3 id="confirm-title">' + title + '</h3>' +
        '<p id="confirm-msg">' + message + '</p>' +
        '<div class="confirm-actions">' +
          '<button class="confirm-cancel" id="confirm-cancel-btn">Cancel</button>' +
          '<button class="confirm-proceed' + (destructive ? ' destructive' : '') + '" id="confirm-proceed-btn">' + proceedLabel + '</button>' +
        '</div>' +
      '</div>';
    document.body.appendChild(overlay);
    document.getElementById('confirm-proceed-btn').focus();
    document.getElementById('confirm-cancel-btn').onclick = function() {
      overlay.remove();
    };
    overlay.onclick = function(e) {
      if (e.target === overlay) overlay.remove();
    };
    document.getElementById('confirm-proceed-btn').onclick = function() {
      overlay.remove();
      if (onProceed) onProceed();
    };
    // ESC to cancel
    var escHandler = function(e) {
      if (e.key === 'Escape') { overlay.remove(); document.removeEventListener('keydown', escHandler); }
    };
    document.addEventListener('keydown', escHandler);
  }

