  window._exportPDF = function() {
    var w = window.open('', '_blank');
    if (!w) { alert('Please allow popups for report export.'); return; }
    var now = new Date();
    var open = (window._getLiveAlerts?window._getLiveAlerts():[]).filter(function(a){ return a.status === 'open'; });
    var crits = open.filter(function(a){ return a.severity === 'critical'; }).length;
    var warns = open.filter(function(a){ return a.severity === 'warning'; }).length;
    var infos = open.filter(function(a){ return a.severity === 'info'; }).length;
    var assets = window._getLiveAssets ? window._getLiveAssets() : [];
    var online = assets.filter(function(a){ return a.status === 'online'; }).length;
    var avgHealth = assets.length ? Math.round(assets.reduce(function(s,a){ return s + (a.health_score||0); },0) / assets.length) : 0;
    var preds = window.livePredictions || [];

    var h = '<!DOCTYPE html><html><head><title>Aevus Operations Report</title><link rel=stylesheet href=https://fonts.googleapis.com/css2?family=Manrope:wght@400;600;800&display=swap>';
    h += '<style>body{font-family:Manrope,-apple-system,sans-serif;max-width:700px;margin:40px auto;padding:20px;color:#0f172a;font-size:12px;}h1{font-size:18px;margin:0;}h2{font-size:14px;margin-top:24px;color:#334155;font-weight:700;border-bottom:1px solid #e2e8f0;padding-bottom:6px;}table{width:100%;border-collapse:collapse;margin:8px 0;}td,th{padding:6px 8px;text-align:left;border-bottom:1px solid #e2e8f0;font-size:11px;}th{background:#f1f5f9;font-weight:600;color:#334155;}.metric{display:inline-block;margin:8px 16px 8px 0;text-align:center;}.metric b{font-size:22px;display:block;color:#06B6D4;}.sev-critical{color:#EF4444;font-weight:700;}.sev-warning{color:#F59E0B;font-weight:700;}.sev-info{color:#06B6D4;}@media print{body{margin:20px;padding:0;}@page{margin:1.5cm;}}.stat-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin:16px 0;}.stat-card{background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:12px;text-align:center;}.stat-card .val{font-size:24px;font-weight:800;color:#06B6D4;}.stat-card .lbl{font-size:10px;color:#64748b;margin-top:4px;}.risk-high{color:#EF4444;}.risk-med{color:#F59E0B;}.risk-low{color:#10B981;}</style></head><body>';
    h += '<div style=\"display:flex;align-items:center;gap:12px;padding-bottom:16px;border-bottom:2px solid #06B6D4;margin-bottom:20px;\"><svg viewBox=\"190 140 590 440\" width=\"44\" height=\"32\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M487.44,154.66c10.46-4.08,24.78-1.69,36.06-2.31,4.74-.26,12.18-.14,16.76.47,3.7.48,7.31,1.49,10.72,2.99,5.33,2.39,9.97,6.09,13.49,10.74,3.82,4.97,12.72,23.25,15.96,29.94,4.54,9.37,11.98,22.39,15.89,31.45,3.46,6.57,6.9,13.35,10.19,20.02,22.69,45.91,46.99,91.36,69.13,137.52l-54.16.03c-47.07.05-40.06,1.97-61.26-40.55l-24.62-49.05c-5.47-10.93-11.17-22.96-16.98-33.55l-99.6,199.06-24,48.21c-4.73,9.53-15.11,33.59-21.58,40.09-3.73,3.73-7.79,5.98-12.96,7.08-9.93,2.12-22.72.89-32.91.89l-55.33-.04c6.92-15.9,18.4-37.39,26.3-53.26l53.2-106.42,81.39-160.83c10.86-21.02,21.74-42.03,32.68-63.01,4.66-8.94,11.7-16.59,21.66-19.47Z\" fill=\"#06B6D4\"/><path d=\"M511.32,414.05c47.71-1.69,93.76.15,140.41-.7,25.11-1.16,40.33,1.6,51.03,26.81,19.12,38.52,39.61,76.78,58.21,114.48,1.64,5.09-5.72,2.33-9.89,3.04-18.94.02-35.99-.06-51.35.2-8.83.11-19.09.79-27.19-2.97-15.85-8.98-18.9-25.07-30.04-43.89-4.65-6.71-11.13-28.17-17.11-28.89-54.24-.39-110.5.43-164.82,0-4.63-.17-4.18-1.93-2.04-5.83,14.56-21.76,22.41-58.69,52.78-62.25Z\" fill=\"#06B6D4\"/></svg><div style=\"margin-left:8px;\"><svg viewBox=\"118 608 810 180\" width=\"80\" height=\"16\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M204.43,618.12c26.4-.58,23.17-1.16,35.11,21.84l15.82,30.55c18.26,35.34,36.29,70.8,54.08,106.38-5.78.02-27.39.66-31.56-.71-3.27-3.1-18.88-36.08-21.99-42.39l-39.67-80.67-3.58-7.1-43.04,87.65c-6.88,14.14-13.91,29.36-21.1,43.26l-30.47-.04,52.9-106,15.67-31.23c2.72-5.41,5.56-11.52,8.79-16.59,2.17-3.4,5.27-4.25,9.04-4.93Z\" fill=\"#06B6D4\"/><path d=\"M391.29,654.21c3.73-.27,7.47-.35,11.2-.23,17.08.62,35.26,6.93,46.83,19.86,13.85,15.47,15.82,30.06,15.07,49.65-10.58.57-22.49.1-33.21.2-25.16.22-50.69-.46-75.82.07,5.47,22.59,21.59,32.66,44.49,33.59,12.7.52,23.23-2.39,34.01-9.07,2.14-1.4,5.13-3.82,7.25-5.43,4.7,5.37,9.22,10.56,14.16,15.71-25.13,25.93-78.25,26.4-105.5,4.1-12.03-9.74-19.67-23.88-21.2-39.29-3.82-39.95,24.58-65.82,62.72-69.16Z\" fill=\"#06B6D4\"/><path d=\"M391.77,674.68c21.71-3.6,43.74,8.55,47.16,31.39l-34.8.05-48.88-.05c4.99-19.09,16.89-28.96,36.52-31.38Z\" fill=\"white\"/><path d=\"M595.64,655.28c7.6-.33,20.23-.36,27.66.08-3.04,6.73-6.97,14.18-10.3,20.86-10.62,21.31-21.12,42.68-31.49,64.12-2.16,4.45-15.11,33.01-18.53,35.67-2.21,1.71-23.97,1.27-27.95-.27-2.83-3.11-56.47-113.24-58.77-120.56l28.76-.02c3.82,6.78,7.71,16.11,11.43,23.34,11.49,22.36,21.99,47.11,33.77,69.09,14.98-30.85,30.12-61.64,45.43-92.33Z\" fill=\"#06B6D4\"/><path d=\"M746.49,655.1l26.17.11c.18,7.45.03,15.42.01,22.91l.1,30.32c.03,18.86,1.07,38.62-13.3,53.16-22.48,22.76-75.51,23.01-97.89.52-5.29-5.27-9.11-11.83-11.12-19.02-3.53-12.53-2.68-31.09-2.68-44.53l.07-43.38h26.69s-.01,45.22-.01,45.22c0,15.13-2.22,35.55,9.5,46.92,12.6,12.22,41.38,12.02,53.61-.74,11.22-11.7,8.88-31.35,8.88-46.36l-.02-45.12Z\" fill=\"#06B6D4\"/><path d=\"M852.86,654.21c18.53-1.72,39.25,2.13,55.61,11.14-3.24,6.3-7.01,12.67-10.54,18.83-11.15-5.92-21.44-9.44-34.22-9.81-10.5-.3-32.28.71-32.13,15.47.11,11.25,15.18,12.78,23.44,14.61,22.27,4.7,58.52,6.16,58.09,37.14-.44,31.93-34.9,37.08-59.92,36.85-17.86-1.27-37.89-4.14-52.48-15.48,3.05-5.71,7.85-13.2,11.38-18.73,15.79,10.68,31.45,14.05,50.45,13.36,5.98-.36,18.52-2.15,22.17-7.42,9.57-13.83-5.62-18.84-15.47-21.27-20.73-5.15-60.18-5.28-63.23-33.21-3.18-29.12,23.33-39.45,46.84-41.49Z\" fill=\"#06B6D4\"/></svg><div style=\"font-size:9px;color:#64748b;letter-spacing:2px;margin-top:4px;\">PREDICT. PREVENT. PERFORM.</div></div></div>';
    h += '<h1 style="margin-top:0;">Operations Summary Report</h1>';
    h += '<p style="font-size:12px;color:#64748b;">Generated: ' + now.toLocaleString() + ' &middot; Site: BlueJay Unit #1 · Rimrock Energy</p>';

    // KPI cards
    h += '<div class="stat-grid">';
    h += '<div class="stat-card"><div class="val">' + assets.length + '</div><div class="lbl">Total Assets</div></div>';
    h += '<div class="stat-card"><div class="val">' + online + '</div><div class="lbl">Online</div></div>';
    h += '<div class="stat-card"><div class="val">' + avgHealth + '%</div><div class="lbl">Avg Health</div></div>';
    h += '<div class="stat-card"><div class="val">' + open.length + '</div><div class="lbl">Active Alarms</div></div>';
    h += '</div>';

    // Active alarms table
    h += '<h2>Active Alarms</h2>';
    if (open.length) {
      h += '<table><tr><th>Severity</th><th>Asset</th><th>Description</th><th>Time</th></tr>';
      open.forEach(function(a){
        h += '<tr><td class="sev-' + a.severity + '">' + a.severity.toUpperCase() + '</td>';
        h += '<td>' + (a.asset_name||a.asset_id||'-') + '</td>';
        h += '<td>' + (a.description||a.alarm_text||a.message||'-') + '</td>';
        h += '<td>' + (a.timestamp ? new Date(a.timestamp).toLocaleString() : '-') + '</td></tr>';
      });
      h += '</table>';
    } else { h += '<p style="color:#64748b;">No active alarms.</p>'; }

    // Fleet health table
    h += '<h2>Fleet Health Summary</h2>';
    h += '<table><tr><th>Asset</th><th>Type</th><th>Status</th><th>Health</th></tr>';
    assets.forEach(function(a){
      var hc = (a.health_score||0) >= 80 ? '#10B981' : (a.health_score||0) >= 50 ? '#F59E0B' : '#EF4444';
      h += '<tr><td>' + a.id + ' ' + (a.name||'') + '</td><td>' + (a.type||'-') + '</td>';
      h += '<td>' + a.status + '</td><td style="color:' + hc + ';font-weight:700;">' + (a.health_score||'-') + '</td></tr>';
    });
    h += '</table>';

    // AI Predictions
    if (preds.length) {
      h += '<h2>AI Risk Predictions</h2>';
      h += '<table><tr><th>Asset</th><th>Risk</th><th>Predicted Failure</th><th>Confidence</th></tr>';
      preds.forEach(function(p){
        var rc = (p.risk_score||0) >= 70 ? 'risk-high' : (p.risk_score||0) >= 40 ? 'risk-med' : 'risk-low';
        h += '<tr><td>' + (p.asset_name||p.asset_id||'-') + '</td>';
        h += '<td class="' + rc + '">' + (p.risk_score||'-') + '</td>';
        h += '<td>' + (p.estimated_failure||'-') + '</td>';
        h += '<td>' + (p.confidence_interval||'-') + '</td></tr>';
      });
      h += '</table>';
    }

    h += '<div style=\"margin-top:32px;padding-top:12px;border-top:1px solid #e2e8f0;font-size:9px;color:#94a3b8;display:flex;justify-content:space-between;\"><span>Aevus Platform &middot; Intrepid Logic LLC &middot; SDVOSB</span><span>Predict. Prevent. Perform.</span></div>';
    h += '</body></html>';
    w.document.write(h);
    w.document.close();
    w.print();
  };
  window._exportPredictions = function() {
    var preds = window.livePredictions || [];
    var csv = 'Asset,Risk Score,Predicted Failure,Confidence\n';
    preds.forEach(function(p){ csv += (p.asset_name||p.asset_id)+','+p.risk_score+','+(p.estimated_failure||'-')+','+(p.confidence_interval||'-')+'\n'; });
    var blob = new Blob([csv], {type:'text/csv'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'aevus-predictions-'+new Date().toISOString().slice(0,10)+'.csv';
    a.click();
  };
  // ═══ 31st Audit: Role-Based View System ═══
  // Psychology-driven: each role sees what supports their decision-making pattern
  // Operator: high-frequency, action-oriented (System 1 thinking - fast, automatic)
  // Supervisor: contextual, trend-aware (System 1+2 - monitoring + analysis)
  // Compliance: documentation, audit-trail (System 2 - deliberate, methodical)
  // Executive: strategic, KPI-focused (System 2 - high-level pattern recognition)
  var ROLE_CONFIG = {
    operator: {
      label: 'Operator View',
      pages: ['overview','assets','alarms','health','radio','map','cabinet'],
      wallPages: ['overview','alarms','health','radio','assets'],
      badge: 'Operator'
    },
    supervisor: {
      label: 'Supervisor View',
      pages: ['overview','assets','alarms','health','radio','map','cabinet','operations','reports','weather','historian','solar','executive'],
      wallPages: ['overview','alarms','health','radio','operations','solar'],
      badge: 'Supervisor'
    },
    compliance: {
      label: 'Compliance View',
      pages: ['overview','assets','alarms','health','radio','map','operations','reports','historian','network','cyber','methodology','privacy','settings','executive'],
      wallPages: ['overview','alarms','cyber','network','health','radio'],
      badge: 'Compliance'
    },
    executive: {
      label: 'Executive View',
      pages: ['overview','sites','health','operations','solar','reports','weather','executive','alarms'],
      wallPages: ['overview','sites','solar','operations'],
      badge: 'Executive'
    }
  };

  window._setRole = function(role) {
    if (!ROLE_CONFIG[role]) role = 'operator';
    localStorage.setItem('aevus-role', role);
    // Rebuild command strip for new role
    var qab = document.getElementById('quick-actions-bar');
    if (qab) { qab.removeAttribute('data-built'); qab.innerHTML = ''; }
    if (typeof renderQuickActions === 'function') renderQuickActions();
    document.body.setAttribute('data-role', role);

    // Update nav visibility
    var navItems = document.querySelectorAll('.nav-item[data-page]');
    var allowedPages = ROLE_CONFIG[role].pages;
    navItems.forEach(function(el) {
      var page = el.getAttribute('data-page');
      if (allowedPages.indexOf(page) >= 0) {
        el.classList.remove('role-hidden');
      } else {
        el.classList.add('role-hidden');
      }
    });

    // Also hide section headers if all their children are hidden
    var headers = document.querySelectorAll('.nav-group-label');
    headers.forEach(function(h) {
      var next = h.nextElementSibling;
      var anyVisible = false;
      while (next && !next.classList.contains('nav-group-label') && !next.classList.contains('sidebar-footer')) {
        if (next.classList.contains('nav-item') && !next.classList.contains('role-hidden')) anyVisible = true;
        next = next.nextElementSibling;
      }
      h.style.display = anyVisible ? '' : 'none';
    });

    // Update UI elements
    var badge = document.getElementById('acct-role-badge');
    if (badge) { badge.textContent = ROLE_CONFIG[role].badge; badge.setAttribute('data-role', role); }
    var label = document.getElementById('role-select-label');
    if (label) label.textContent = ROLE_CONFIG[role].label;
    var wrap = document.getElementById('role-select-wrap');
    if (wrap) wrap.classList.remove('open');

    // Update dropdown active state
    var opts = document.querySelectorAll('.role-option');
    opts.forEach(function(o) { o.classList.toggle('active', o.getAttribute('data-role') === role); });

    // Update wall mode pages if active
    if (typeof wallPages !== 'undefined') {
      wallPages = ROLE_CONFIG[role].wallPages;
    }

    // If current page not in allowed list, navigate to default
    var currentPage = (location.hash.replace('#','') || 'overview');
    if (allowedPages.indexOf(currentPage) < 0) {
      var defaultPage = role === 'executive' ? 'overview' : 'overview';
      window.location.hash = '#' + defaultPage;
    }
  };

  // Apply role on load
  setTimeout(function() {
    var savedRole = localStorage.getItem('aevus-role') || 'operator';
    window._setRole(savedRole);

    // Close role dropdown on outside click
    document.addEventListener('click', function(e) {
      var wrap = document.getElementById('role-select-wrap');
      if (wrap && !wrap.contains(e.target)) wrap.classList.remove('open');
    });
  }, 500);

  

