// Tab switching
window._aiTab = function(tab) {
  document.querySelectorAll('.ai-panel-content').forEach(function(el){ el.style.display = 'none'; });
  document.querySelectorAll('.ai-tab').forEach(function(el){ el.style.color = 'var(--text-muted)'; el.style.borderBottom = '2px solid transparent'; el.style.fontWeight = 'normal'; });
  var panel = document.getElementById('ai-panel-' + tab);
  if (panel) panel.style.display = 'flex';
  var tabBtn = document.querySelector('.ai-tab[data-tab="' + tab + '"]');
  if (tabBtn) { tabBtn.style.color = 'var(--accent)'; tabBtn.style.borderBottom = '2px solid var(--accent)'; tabBtn.style.fontWeight = '600'; }
};

// Gather live context
window._aiContext = function() {
  var ctx = {};
  if (window._getLiveAlerts?window._getLiveAlerts():[]) ctx.alarms = (window._getLiveAlerts?window._getLiveAlerts():[]).filter(function(a){ return a.status==='open'; }).slice(0,10);
  if (window._getLiveAssets) ctx.assets = window._getLiveAssets().map(function(a){ return {id:a.id,name:a.name,status:a.status,health_score:a.health_score}; });
  if (window.livePredictions) ctx.predictions = window.livePredictions;
  return ctx;
};

// Quick action
window._aiQuick = function(q) {
  var input = document.getElementById('ai-input');
  if (input) { input.value = q; window._aiSend(); }
};

// Main chat send — tiered routing
window._aiSend = function() {
  var input = document.getElementById('ai-input');
  var msgs = document.getElementById('ai-messages');
  if (!input || !msgs || !input.value.trim()) return;
  var q = input.value.trim();
  input.value = '';

  var uDiv = document.createElement('div');
  uDiv.className = 'ai-msg-user';
  uDiv.textContent = q;
  msgs.appendChild(uDiv);

  var thinking = document.createElement('div');
  thinking.className = 'ai-msg-bot';
  thinking.innerHTML = '<div style="display:flex;align-items:center;gap:8px;"><div style="width:6px;height:6px;border-radius:50%;background:var(--accent);animation:pulse 0.8s infinite;"></div><div style="width:6px;height:6px;border-radius:50%;background:var(--accent);animation:pulse 0.8s 0.2s infinite;"></div><div style="width:6px;height:6px;border-radius:50%;background:var(--accent);animation:pulse 0.8s 0.4s infinite;"></div><span style="color:var(--text-faint);font-size:10px;margin-left:4px;">Analyzing</span></div>';
    // Progressive status update for slow models
    var _thinkTimer = setTimeout(function(){ if(thinking.parentNode) thinking.querySelector('span').textContent = 'Deep analysis in progress...'; }, 3000);
    var _thinkTimer2 = setTimeout(function(){ if(thinking.parentNode) thinking.querySelector('span').textContent = 'Generating response...'; }, 6000);
  msgs.appendChild(thinking);
  msgs.scrollTop = msgs.scrollHeight;

  window._aiQueryCount = (window._aiQueryCount || 0) + 1;
    var qc = document.getElementById('ai-query-count');
    if (qc) { qc.style.display = 'inline'; qc.textContent = window._aiQueryCount + ' queries'; }
    window._aiQueryCount = (window._aiQueryCount || 0) + 1;
    var qc = document.getElementById('ai-query-count');
    if (qc) { qc.style.display = 'inline'; qc.textContent = window._aiQueryCount + ' queries'; }
    fetch('/api/v1/ai/ask', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({ prompt: q, context: window._aiContext() })
  })
  .then(function(r){ if(!r.ok) throw new Error('AI error '+r.status); return r.json(); })
  .then(function(data){
    thinking.remove(); clearTimeout(_thinkTimer); clearTimeout(_thinkTimer2);
    var aDiv = document.createElement('div');
    aDiv.className = 'ai-msg-bot';
    aDiv.textContent = data.reply;
    msgs.appendChild(aDiv);
    var meta = document.createElement('div');
    meta.className = 'ai-msg-meta';
    meta.textContent = data.model + (data.tier > 1 ? ' \u00b7 Deep Analysis' : '');
    msgs.appendChild(meta);
    msgs.scrollTop = msgs.scrollHeight;
    var badge = document.getElementById('ai-tier-badge');
    if (badge) badge.textContent = data.model;
  })
  .catch(function(err){
    thinking.remove(); clearTimeout(_thinkTimer); clearTimeout(_thinkTimer2);
    var eDiv = document.createElement('div');
    eDiv.style.cssText = 'background:rgba(239,68,68,0.1);border-radius:8px;padding:8px 12px;font-size:11px;color:#EF4444;';
    eDiv.textContent = 'AI unavailable: ' + err.message;
    msgs.appendChild(eDiv);
    msgs.scrollTop = msgs.scrollHeight;
  });
};

// Similar alarm search — Cohere
window._aiSimilar = function() {
  var input = document.getElementById('ai-similar-input');
  var results = document.getElementById('ai-similar-results');
  if (!input || !results || !input.value.trim()) return;
  results.innerHTML = '<div style="font-size:11px;color:var(--text-faint);animation:pulse 1s infinite;">Searching with Cohere Embed v4 + Rerank 3.5...</div>';

  fetch('/api/v1/ai/similar', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({ alarm_text: input.value.trim() })
  })
  .then(function(r){ if(!r.ok) throw new Error('Search error'); return r.json(); })
  .then(function(data){
    var html = '<div style="font-size:9px;color:var(--text-faint);margin-bottom:8px;">' + data.model + '</div>';
    data.similar.forEach(function(s){
      var scoreColor = s.score > 0.5 ? '#10D478' : s.score > 0.2 ? '#FBBF24' : 'var(--text-faint)';
      html += '<div style="background:var(--bg-surface);border-radius:8px;padding:10px;margin-bottom:6px;border-left:3px solid ' + scoreColor + ';">' +
        '<div style="font-size:11px;color:var(--text-primary);font-weight:600;">' + s.alarm_text + '</div>' +
        '<div style="font-size:9px;color:var(--text-faint);margin-top:2px;">Relevance: ' + (s.score * 100).toFixed(1) + '%</div>' +
        (s.resolution ? '<div style="font-size:10px;color:var(--accent);margin-top:6px;padding-top:6px;border-top:1px solid var(--border);"><strong>Resolution:</strong> ' + s.resolution + '</div>' : '') +
      '</div>';
    });
    results.innerHTML = html;
  })
  .catch(function(err){
    results.innerHTML = '<div style="color:#EF4444;font-size:11px;">' + err.message + '</div>';
  });
};

// Voice interface
window._aiVoiceActive = false;
window._aiVoiceToggle = function() {
  var btn = document.getElementById('ai-voice-btn');
  var status = document.getElementById('ai-voice-status');
  var transcript = document.getElementById('ai-voice-transcript');
  var response = document.getElementById('ai-voice-response');
  
  if (window._aiVoiceActive) {
    window._aiVoiceActive = false;
    if (window._aiRecognition) window._aiRecognition.stop();
    btn.style.background = 'var(--bg-surface)';
    btn.style.borderColor = 'var(--accent)';
    status.textContent = 'Tap to start listening';
    return;
  }

  if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
    status.textContent = 'Speech recognition not supported in this browser';
    return;
  }

  window._aiVoiceActive = true;
  btn.style.background = 'rgba(239,68,68,0.2)';
  btn.style.borderColor = '#EF4444';
  status.textContent = 'Listening... speak now';

  var SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  var recognition = new SpeechRecognition();
  recognition.continuous = false;
  recognition.interimResults = true;
  recognition.lang = 'en-US';
  window._aiRecognition = recognition;

  recognition.onresult = function(event) {
    var text = '';
    for (var i = event.resultIndex; i < event.results.length; i++) {
      text += event.results[i][0].transcript;
    }
    transcript.textContent = text;
    if (event.results[event.results.length-1].isFinal) {
      status.textContent = 'Processing with Nova Sonic...';
      // Send to voice endpoint
      fetch('/api/v1/ai/voice', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ text: text, context: window._aiContext() })
      })
      .then(function(r){ return r.json(); })
      .then(function(data){
        response.style.display = 'block';
        response.textContent = data.reply;
        status.textContent = data.model + ' · ' + data.latency_ms + 'ms';
        // Text-to-speech response
        if ('speechSynthesis' in window) {
          var utter = new SpeechSynthesisUtterance(data.reply);
          utter.rate = 1.1;
          speechSynthesis.speak(utter);
        }
        window._aiVoiceActive = false;
        btn.style.background = 'var(--bg-surface)';
        btn.style.borderColor = 'var(--accent)';
      });
    }
  };
  recognition.onerror = function(e) {
    status.textContent = e.error === 'no-speech' ? 'No speech detected — tap to try again' : e.error === 'not-allowed' ? 'Microphone access needed — check browser permissions' : 'Could not hear clearly — tap to try again';
    window._aiVoiceActive = false;
    btn.style.background = 'var(--bg-surface)';
    btn.style.borderColor = 'var(--accent)';
  };
  recognition.onend = function() {
    if (window._aiVoiceActive) {
      window._aiVoiceActive = false;
      btn.style.background = 'var(--bg-surface)';
      btn.style.borderColor = 'var(--accent)';
    }
  };
  recognition.start();
};

// Vision upload
window._aiVisionFile = function(file) {
  if (!file) return;
  var preview = document.getElementById('ai-vision-preview');
  var result = document.getElementById('ai-vision-result');
  
  // Show preview
  var reader = new FileReader();
  reader.onload = function(e) {
    preview.style.display = 'block';
    preview.innerHTML = '<img src="' + e.target.result + '" style="max-width:100%;max-height:200px;border-radius:8px;border:1px solid var(--border);">' +
      '<div style="font-size:10px;color:var(--text-faint);margin-top:4px;">' + file.name + ' (' + (file.size/1024).toFixed(0) + 'KB)</div>';
    result.style.display = 'block';
    result.innerHTML = '<div style="font-size:11px;color:var(--text-faint);animation:pulse 1s infinite;">Analyzing with Nemotron 12B VL...</div>';
  };
  reader.readAsDataURL(file);
  
  // Upload and analyze
  var formData = new FormData();
  formData.append('image', file);
  formData.append('prompt', 'Analyze this equipment image for anomalies, corrosion, leaks, or safety concerns. Rate condition: GOOD/FAIR/POOR/CRITICAL.');
  
  fetch('/api/v1/ai/vision', {
    method: 'POST',
    body: formData
  })
  .then(function(r){ if(!r.ok) throw new Error('Vision error ' + r.status); return r.json(); })
  .then(function(data){
    result.innerHTML = '<div style="background:var(--bg-surface);border-radius:8px;padding:12px;font-size:11px;color:var(--text-secondary);line-height:1.6;white-space:pre-wrap;">' + data.analysis + '</div>' +
      '<div style="font-size:9px;color:var(--text-faint);margin-top:4px;">' + data.model + ' · ' + data.latency_ms + 'ms</div>';
  })
  .catch(function(err){
    result.innerHTML = '<div style="color:#EF4444;font-size:11px;">' + err.message + '</div>';
  });
};

// Edge inference
window._aiEdgeSend = function() {
  var input = document.getElementById('ai-edge-input');
  var result = document.getElementById('ai-edge-result');
  if (!input || !result || !input.value.trim()) return;
  
  result.innerHTML = '<div style="font-size:11px;color:var(--text-faint);animation:pulse 1s infinite;">Running on ' + (window._aiEdgeModel || 'nemotron-9b') + '...</div>';
  
  fetch('/api/v1/ai/edge', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({ prompt: input.value.trim(), context: window._aiContext(), model: window._aiEdgeModel || 'nemotron-9b' })
  })
  .then(function(r){ if(!r.ok) throw new Error('Edge error'); return r.json(); })
  .then(function(data){
    result.innerHTML = '<div style="background:var(--bg-surface);border-radius:8px;padding:12px;font-size:11px;color:var(--text-secondary);line-height:1.6;white-space:pre-wrap;">' + data.reply + '</div>' +
      '<div style="font-size:9px;color:var(--text-faint);margin-top:4px;">' + data.model + ' · ' + data.latency_ms + 'ms' + (data.simulated_edge ? ' · Simulated (Bedrock proxy)' : ' · Live Edge') + '</div>';
  })
  .catch(function(err){
    result.innerHTML = '<div style="color:#EF4444;font-size:11px;">' + err.message + '</div>';
  });
};

// Show model architecture
window._aiShowModels = function() {
  fetch('/api/v1/ai/models')
  .then(function(r){ return r.json(); })
  .then(function(data){
    var msgs = document.getElementById('ai-messages');
    if (!msgs) return;
    window._aiTab('chat');
    var html = '<strong>IL9000 Architecture</strong>\n' + data.architecture + '\n\n';
    html += '<strong>Routing:</strong>\n';
    Object.keys(data.routing).forEach(function(k){ html += k + ' → ' + data.routing[k] + '\n'; });
    html += '\n<strong>Models:</strong>\n';
    Object.keys(data.models).forEach(function(k){ 
      var m = data.models[k];
      html += 'T' + m.tier + ' ' + m.label + ' (' + m.provider + ') $' + m.cost_per_1k_queries + '/1K\n';
    });
    html += '\nEmbeddings: ' + data.embeddings;
    html += '\nEdge: ' + data.edge;
    html += '\nVoice: ' + data.voice;
    html += '\nVision: ' + data.vision;
    html += '\n\n' + data.finetune_pipeline;
    html += '\n' + data.patents.join(', ');
    var div = document.createElement('div');
    div.className = 'ai-msg-bot';
    div.textContent = html;
    msgs.appendChild(div);
    msgs.scrollTop = msgs.scrollHeight;
  });
};

// Proactive digest — runs every 5 min
window._aiDigestInterval = setInterval(function() {
  var ctx = window._aiContext();
  if (!ctx.alarms || ctx.alarms.length === 0) return;
  fetch('/api/v1/ai/digest', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify(ctx)
  })
  .then(function(r){ return r.json(); })
  .then(function(data){
    if (!data.digest || data.digest.length === 0) return;
    // Push to activity feed if it exists
    var feed = document.querySelector('.change-feed, .activity-feed');
    if (feed) {
      var item = document.createElement('div');
      item.style.cssText = 'padding:8px 12px;border-left:3px solid var(--accent);margin-bottom:6px;font-size:11px;background:rgba(14,165,233,0.05);border-radius:0 6px 6px 0;';
      item.innerHTML = '<div style="font-size:9px;color:var(--accent);font-weight:600;margin-bottom:4px;">AI SITUATION DIGEST</div>' +
        data.digest.map(function(b){ return '<div style="color:var(--text-secondary);margin:2px 0;">• ' + b + '</div>'; }).join('');
      feed.insertBefore(item, feed.firstChild);
    }
  })
  .catch(function(){});
}, 300000); // 5 minutes


