  // #38: Cognitive load indicator
  window._calcCognitiveLoad = function() {
    var score = 0;
    var _la = window._getLiveAlerts ? window._getLiveAlerts() : [];
    var _pr = window._getPredictions ? window._getPredictions() : [];
    var _openAlerts = _la.filter(function(a){return a.status==='open';}).length;
    var _criticals = _la.filter(function(a){return a.status==='open' && a.severity==='critical';}).length;
    score += _openAlerts * 5;
    score += _criticals * 15;
    if (_pr) score += _pr.length * 3;
    if (typeof correlations !== 'undefined' && correlations) score += correlations.filter(function(c){return c.severity==='high';}).length * 8;
    // Normalize to LOW/MEDIUM/HIGH
    if (score > 60) return {level:'HIGH', score:score, color:'#EF4444'};
    if (score > 25) return {level:'MEDIUM', score:score, color:'#FBBF24'};
    return {level:'LOW', score:score, color:'#10D478'};
  };

  // #39: Operator decision queue — prioritized actions
  window._buildDecisionQueue = function() {
    var queue = [];
    var _la = window._getLiveAlerts ? window._getLiveAlerts() : [];
    var _pr = window._getPredictions ? window._getPredictions() : [];
    // Critical alarms first
    _la.filter(function(a){return a.status==='open' && a.severity==='critical';}).forEach(function(a){
      queue.push({priority:1, type:'alarm', label:'Respond: '+a.asset_name+' — '+a.message, id:a.id});
    });
    // Predictions with high confidence
    if (_pr) _pr.filter(function(p){return (p.confidence||0)>0.7;}).forEach(function(p){
      queue.push({priority:2, type:'prediction', label:'Plan: '+(p.asset_name||'')+' — '+(p.failure_mode||''), id:p.id});
    });
    // Warning alarms
    _la.filter(function(a){return a.status==='open' && a.severity==='warning';}).forEach(function(a){
      queue.push({priority:3, type:'alarm', label:'Monitor: '+a.asset_name+' — '+a.message, id:a.id});
    });
    return queue.sort(function(a,b){return a.priority-b.priority;}).slice(0,5);
  };

  // #46: One-click chattering alarm suppression
  window.suppressChatteringAlarm = function(alarmId) {
    var alarm = (window._getLiveAlerts?window._getLiveAlerts():[]).find(function(a){ return a.id === alarmId; });
    if (!alarm) return;
    alarm._suppressed = true;
    alarm._suppressUntil = new Date(Date.now() + 30*60000).toISOString(); // 30 min
    if (window.showToast) window.showToast('Chattering alarm suppressed for 30 min: ' + (alarm.asset_name || alarm.asset_id), 'info');
    renderLiveAlerts();
  };

  // #78: Operator journey — shift context
  window._shiftContext = function() {
    var now = new Date();
    var hour = now.getHours();
    if (hour >= 6 && hour < 14) return {shift:'Day', icon:'☀', started:'06:00', remaining:14-hour};
    if (hour >= 14 && hour < 22) return {shift:'Swing', icon:'🌤', started:'14:00', remaining:22-hour};
    return {shift:'Night', icon:'🌙', started:'22:00', remaining:hour>=22?30-hour:6-hour};
  };

  // #82: Operator confidence score
  window._operatorConfidence = function() {
    var score = 100;
    var _la = window._getLiveAlerts ? window._getLiveAlerts() : [];
    var _hs = window._getHealthSummary ? window._getHealthSummary() : {};
    var _as = window._getLiveAssets ? window._getLiveAssets() : [];
    var openAlerts = _la.filter(function(a){return a.status==='open';}).length;
    var criticals = _la.filter(function(a){return a.status==='open'&&a.severity==='critical';}).length;
    score -= openAlerts * 3;
    score -= criticals * 10;
    if (_hs.avg_health && _hs.avg_health < 70) score -= 15;
    var commIssues = _as.filter(function(a){return a.status==='offline';}).length;
    score -= commIssues * 8;
    return Math.max(0, Math.min(100, score));
  };

  // #8: Correlation time axis consistency — newest right
  window._corrTimeFlip = true; // Flag: all time axes render left=old, right=new

  // #14: Sparkline axis consistency — all sparklines use same time window (24h)
  window._sparkAxisConsistent = true;

  // #44: Auto-suppress non-critical info during HIGH cognitive load
  window._autoSuppressLowPriority = function() {
    var cog = window._calcCognitiveLoad ? window._calcCognitiveLoad() : {level:'LOW'};
    if (cog.level === 'HIGH') {
      // Hide weather strip, sustainability, activity feed during HIGH load
      var sustain = document.getElementById('sustain-methodology');
      if (sustain && sustain.parentElement) sustain.parentElement.style.opacity = '0.3';
      var feed = document.getElementById('ov-activity-feed');
      if (feed) feed.style.maxHeight = '80px';
    } else {
      var feed2 = document.getElementById('ov-activity-feed');
      if (feed2) feed2.style.maxHeight = '200px';
    }
  };

